import { LocalDB, initializeDB, getLocalDb } from '../src/services/localDB';
import { Card } from '../src/types';

// データ補正用スクリプト
async function patchAllCards(userId: string) {
  initializeDB(userId);
  const db = getLocalDb();
  const cards: Card[] = await db.getAllCards();
  const now = new Date();
  let patched = 0;

  for (const card of cards) {
    let changed = false;
    const changes: Partial<Card> = {};

    // S（記憶強度）
    if (typeof card.memoryStability !== 'number' || isNaN(card.memoryStability)) {
      changes.memoryStability = 35; // S_init: 初期値
      changed = true;
    }
    // 状態
    if (!('state' in card) || !card.state) {
      changes.state = card.lastReviewAt ? 'STABLE' : 'PRE-LEARN';
      changed = true;
    }
    // 次回復習日
    if (!card.nextReviewDate) {
      changes.nextReviewDate = new Date(now.getTime() + 24 * 60 * 60 * 1000); // 1日後
      changed = true;
    }
    // 型変換（Timestamp→Date）
    if (card.nextReviewDate && typeof card.nextReviewDate !== 'object') {
      changes.nextReviewDate = new Date(card.nextReviewDate);
      changed = true;
    }
    // ここでpatch
    if (changed) {
      await db.updateItem('cards', card.id, changes);
      patched++;
    }
  }
  console.log(`Patched ${patched} cards.`);
}

// 実行例（ユーザーIDは適宜指定）
patchAllCards('test-user-id').then(() => {
  console.log('カードデータ補正完了');
});

import type { Card } from '../src/types/index';

// シミュレーション用：状態遷移・S・Iの変化をテスト
function simulateCardScenario(card: Card, scenario: Array<'success'|'fail'|'delay'|'view'>) {
  let S = card.memoryStability ?? 35;
  let state = card.state ?? 'PRE-LEARN';
  let I = 1; // 初期間隔
  const now = new Date();
  let nextReviewDate = card.nextReviewDate ?? new Date(now.getTime() + I * 24 * 60 * 60 * 1000);
  const λ = 0.15; // 忘却率
  const β = 0.5; // 失敗時減衰
  const S_success = 10; // 成功時強化量
  const penalty_miss = 0.7;
  const relearn_cap = 1;

  for (const event of scenario) {
    if (event === 'success') {
      S += S_success;
      state = 'STABLE';
      I = I * 1.8;
      nextReviewDate = new Date(now.getTime() + I * 24 * 60 * 60 * 1000);
    } else if (event === 'fail') {
      S *= β;
      state = 'FAILED';
      I = Math.min(I * 0.3, relearn_cap);
      nextReviewDate = new Date(now.getTime() + I * 24 * 60 * 60 * 1000);
    } else if (event === 'delay') {
      S = S * Math.exp(-λ * I);
      state = 'DECAYING';
      I = I * penalty_miss;
      nextReviewDate = new Date(now.getTime() + I * 24 * 60 * 60 * 1000);
    } else if (event === 'view') {
      S = Math.max(S, 35);
      // stateは変化なし
    }
    const nextReviewStr = nextReviewDate instanceof Date ? nextReviewDate.toISOString() : (nextReviewDate as any).toDate().toISOString();
    console.log(`Event: ${event}, S: ${S.toFixed(2)}, state: ${state}, I: ${I.toFixed(2)}, nextReviewDate: ${nextReviewStr}`);
  }
}

// テスト例
const testCard: Card = {
  id: 'test', userId: 'test', folderId: '', orderIndex: 0, questionNumber: '', isDraft: false, hasUncertainty: false, isCompleted: false, isSilent: false,
  questionText: '', questionImages: [], questionAudios: [], questionMemo: '', questionMarked: '', answerText: '', answerImages: [], answerAudios: [], answerMemo: '', answerMarked: '',
  memoryStability: 35, nextReviewDate: new Date(), createdAt: new Date(), updatedAt: new Date(), deviceId: '',
  state: 'PRE-LEARN',
  isDeleted: false,
};

simulateCardScenario(testCard, ['success','delay','fail','view','success']);

/**
 * 既存データの Base64 検出・移行スクリプト
 * 
 * 用途:
 * - DB内の Base64 混入を検出
 * - Base64 を localUrl に移動し、remoteUrl を null に設定
 * - 次回同期時に自動アップロード
 */

import { LocalDB, initializeDB, getLocalDb } from '../src/services/localDB';
import { isBase64DataUrl } from '../src/types/branded';

interface MigrationResult {
  totalCards: number;
  cardsWithBase64: number;
  imagesFixed: number;
  errors: string[];
}

export async function detectAndMigrateBase64(userId: string): Promise<MigrationResult> {
  initializeDB(userId);
  const db = getLocalDb();
  const result: MigrationResult = {
    totalCards: 0,
    cardsWithBase64: 0,
    imagesFixed: 0,
    errors: []
  };

  try {
    const cards = await db.cards.toArray();
    result.totalCards = cards.length;

    for (const card of cards) {
      let cardModified = false;

      // questionImages のチェック
      if (card.questionImages) {
        for (let i = 0; i < card.questionImages.length; i++) {
          const image = card.questionImages[i];
          
          // remoteUrl に Base64 が混入している場合
          if (image.remoteUrl && isBase64DataUrl(image.remoteUrl as string)) {
            console.warn(`[Migration] Base64 detected in card ${card.id}, questionImages[${i}].remoteUrl`);
            
            // Base64 を localUrl に移動（一時的な措置）
            card.questionImages[i] = {
              ...image,
              localUrl: null, // Base64 は破棄（再アップロードが必要）
              remoteUrl: null,
              status: 'failed' as const,
              uploadState: 'failed' as const
            };
            
            cardModified = true;
            result.imagesFixed++;
          }

          // localUrl に Base64 が混入している場合
          if (image.localUrl && isBase64DataUrl(image.localUrl as string)) {
            console.warn(`[Migration] Base64 detected in card ${card.id}, questionImages[${i}].localUrl`);
            
            card.questionImages[i] = {
              ...image,
              localUrl: null, // Base64 は破棄
              status: 'failed' as const,
              uploadState: 'failed' as const
            };
            
            cardModified = true;
            result.imagesFixed++;
          }
        }
      }

      // answerImages のチェック
      if (card.answerImages) {
        for (let i = 0; i < card.answerImages.length; i++) {
          const image = card.answerImages[i];
          
          if (image.remoteUrl && isBase64DataUrl(image.remoteUrl as string)) {
            console.warn(`[Migration] Base64 detected in card ${card.id}, answerImages[${i}].remoteUrl`);
            
            card.answerImages[i] = {
              ...image,
              localUrl: null,
              remoteUrl: null,
              status: 'failed' as const,
              uploadState: 'failed' as const
            };
            
            cardModified = true;
            result.imagesFixed++;
          }

          if (image.localUrl && isBase64DataUrl(image.localUrl as string)) {
            console.warn(`[Migration] Base64 detected in card ${card.id}, answerImages[${i}].localUrl`);
            
            card.answerImages[i] = {
              ...image,
              localUrl: null,
              status: 'failed' as const,
              uploadState: 'failed' as const
            };
            
            cardModified = true;
            result.imagesFixed++;
          }
        }
      }

      if (cardModified) {
        result.cardsWithBase64++;
        await db.cards.update(card.id, {
          questionImages: card.questionImages,
          answerImages: card.answerImages,
          updatedAt: new Date()
        });
      }
    }

    console.log('[Migration] Complete:', result);
    return result;

  } catch (error) {
    console.error('[Migration] Error:', error);
    result.errors.push(error instanceof Error ? error.message : String(error));
    return result;
  }
}

// CLI実行用
if (import.meta.url === `file://${process.argv[1]}`) {
  const userId = process.argv[2];
  if (!userId) {
    console.error('Usage: node migrateBase64.ts <userId>');
    process.exit(1);
  }

  detectAndMigrateBase64(userId)
    .then(result => {
      console.log('\n=== Migration Summary ===');
      console.log(`Total cards: ${result.totalCards}`);
      console.log(`Cards with Base64: ${result.cardsWithBase64}`);
      console.log(`Images fixed: ${result.imagesFixed}`);
      if (result.errors.length > 0) {
        console.log(`Errors: ${result.errors.length}`);
        result.errors.forEach(err => console.error(`  - ${err}`));
      }
    })
    .catch(err => {
      console.error('Migration failed:', err);
      process.exit(1);
    });
}

