const db = getFirestore();

async function verifySecuritySignal() {
    const testUserId = 'test_signal_user_' + Date.now();
    console.log(`[Verify] Starting verification for User: ${testUserId}`);

    // 1. Create initial user document
    await db.doc(`users/${testUserId}`).set({
        displayName: 'Test Signal User',
        email: 'test@example.com',
        createdAt: Timestamp.now(),
        isAccountLocked: false,
        requires2FA: false
    });
    console.log('[Verify] User created.');

    // 2. Set up listener on user document to catch the lock signal
    const userRef = db.doc(`users/${testUserId}`);
    const unsubscribe = userRef.onSnapshot((snap) => {
        const data = snap.data();
        if (data?.isAccountLocked) {
            console.log('✅ [SUCCESS] Account lock signal received!');
            console.log('   Data:', JSON.stringify(data, null, 2));
            process.exit(0);
        }
    });

    // 3. Trigger High Risk Event (simulating client-side log)
    // We send enough events to trigger a lock.
    // Assuming threshold is > 80 or something. 
    // Let's send a CRITICAL event if logic handles it, or multiple high events.
    // Based on `functions/src/security/index.ts`:
    // Risk Score += log.severity * 10.
    // Thresholds: Critical (80) -> Lock.
    
    // So 1 Critical event (severity 5? or just manual score?)
    // Logic: score += (5 - 1) * 10 ? No, let's look at logic.
    // calculateRiskScore adds based on new logs.
    // Let's inject a log with high severity.
    
    // Actually, the `security_logs` trigger updates the score.
    // Let's add a "concurrent_login" detected event.
    
    const highRiskLog = {
        userId: testUserId,
        eventType: 'abnormal_pattern', // This might trigger detection
        details: { reason: 'Test High Risk' },
        timestamp: Timestamp.now(),
        userAgent: 'TestScript',
        ipAddress: '127.0.0.1',
        deviceId: 'device_test',
        severity: 'critical' // severity: 'critical' usually implies high score impact
    };

    console.log('[Verify] Writing critical security log...');
    await db.collection(`users/${testUserId}/securityLogs`).add(highRiskLog);

    // Also manually boost score if the function logic relies on previous score?
    // The function `onLogCreated` calculates score.
    // If severity is 'critical', it should add significant score.

    // Wait for a bit
    setTimeout(async () => {
        console.log('[Verify] Waiting for lock...');
        // If single log isn't enough, add more.
        await db.collection(`users/${testUserId}/securityLogs`).add({
             ...highRiskLog,
             timestamp: Timestamp.now(),
             details: { reason: 'Second Hit' }
        });
    }, 2000);

    setTimeout(() => {
        console.error('❌ [TIMEOUT] Account was not locked in time.');
        process.exit(1);
    }, 10000);
}

verifySecuritySignal().catch(err => {
    console.error('Error:', err);
    process.exit(1);
});

import React, { useEffect, Suspense } from 'react';
import { Outlet, useLocation, useSearchParams } from 'react-router-dom';
import SettingsDialog from '@/components/settings/SettingsDialog';
import { SyncStatusIndicator } from '@/components/sync/SyncStatusIndicator';
import { cn } from '@/lib/utils';
import { UI_TYPO } from '@/styles/tokens/typography';
import { useSettingsQueryParam } from '@/hooks/useSettingsQueryParam';
import { useKatexLoader } from '@/hooks/useKatexLoader';

import { ThemeManager } from '@/components/common/ThemeManager';
import { SecurityAlertBanner } from './components/security/SecurityAlertBanner';
import { LocalDBStatusBanner } from './components/security/LocalDBStatusBanner';

// ... (existing imports)

export default function Layout() {
  // ... (existing logic)

  const location = useLocation();
  const [searchParams, setSearchParams] = useSearchParams();
  const isFoldersRoute = /^\/folders(?:\/|$)/i.test(location.pathname);
  const isCardEditRoute = /^\/cardedit(?:\/|$)/i.test(location.pathname);

  // ページ遷移時にスクロール位置をリセット
  useEffect(() => {
    window.scrollTo({ top: 0, left: 0, behavior: 'auto' });
    document.documentElement.scrollTop = 0;
    document.body.scrollTop = 0;
  }, [location.pathname]);

  // 安全策: Folders以外ではページスクロール固定クラスを必ず解除する
  useEffect(() => {
    if (!isFoldersRoute) {
      document.documentElement.classList.remove('no-page-scroll');
    }
  }, [isFoldersRoute, location.pathname]);

  const { isSettingsOpen, settingsTab, setIsSettingsOpen } = useSettingsQueryParam(searchParams, setSearchParams);
  
  // Determine currentPageName from location pathname
  const currentPageName = React.useMemo(() => {
    const path = location.pathname.substring(1); // remove leading slash
    if (path === '') return 'Folders';
    if (path === 'study') return 'StudyMode';
    if (path === 'uncertain') return 'UncertainMode';
    if (path === 'today-study') return 'TodayStudy';
    if (path === 'gallery') return 'Gallery';
    if (path === 'calendar') return 'Calendar';
    // Default capitalize for others which match component names largely
    return path.charAt(0).toUpperCase() + path.slice(1);
  }, [location.pathname]);

  useKatexLoader();

  const isStudyModePage = currentPageName === 'StudyMode';
  const isCardEditPage = currentPageName === 'CardEdit';

  return (
    <div className={cn("relative flex h-[100dvh] w-full flex-col overflow-hidden", UI_TYPO)}>
      <ThemeManager />

      {/* Desktop Sync Indicator (Fixed Top Right) */}
      <div className="hidden md:flex fixed top-1 right-2 z-50">
        {!['StudyMode'].includes(currentPageName) && (
            <SyncStatusIndicator />
        )}
      </div>

      {/* Mobile Header intentionally disabled */}
      
      <SettingsDialog open={isSettingsOpen} onOpenChange={setIsSettingsOpen} initialTab={settingsTab ?? 'account'} />



      {/* Main Content */}
      <main className={cn(
        "md:ml-0 flex min-h-0 flex-1 flex-col transition-[margin] duration-500 ease-[cubic-bezier(0.2,0.8,0.2,1)]"
      )}>
        <LocalDBStatusBanner />
        <SecurityAlertBanner />
        <div
          className={cn(
            "flex-1 min-h-0",
            isFoldersRoute || isCardEditRoute || isStudyModePage
              ? "overflow-hidden"
              : "overflow-y-auto",
            isFoldersRoute || isCardEditRoute || isStudyModePage
              ? ""
              : "pb-10"
          )}
        >
          <Suspense fallback={<LoadingFallback />}>
            <Outlet />
          </Suspense>
        </div>
      </main>
    </div>
  );
}

function LoadingFallback() {
  return (
    <div className="h-full min-h-[50vh] flex items-center justify-center bg-transparent animate-in fade-in duration-500">
      <div className="text-center">
        <div className="relative w-12 h-12 mx-auto mb-4">
          <div className="absolute inset-0 border-4 border-primary-600/10 rounded-full"></div>
          <div className="absolute inset-0 border-4 border-primary-600 rounded-full border-t-transparent animate-spin"></div>
        </div>
        <p className="text-primary-600 font-bold tracking-[0.3em] text-[10px] opacity-40">LOADING</p>
      </div>
    </div>
  );
}

/**
 * CalendarMiniView - ダッシュボード埋め込み用コンパクトカレンダー
 */
import React, { useState, useMemo } from 'react';
import { 
  format, 
  startOfMonth, 
  endOfMonth, 
  startOfWeek, 
  endOfWeek,
  addDays,
  addMonths,
  isSameMonth,
  isSameDay,
  isToday,
} from 'date-fns';
import { ChevronLeft, ChevronRight, Calendar as CalendarIcon } from '@/ui/icons';
import { cn } from '@/lib/utils';
import { Button } from '@/components/ui/button';
import { Card } from '@/types';

interface CalendarMiniViewProps {
  cards: Card[];
  weekStartDay?: 'monday' | 'sunday';
  accentColor?: string;
}

const toDate = (value: unknown): Date | null => {
  if (!value) return null;
  if (typeof value?.toDate === 'function') {
    const d = value.toDate();
    return d instanceof Date && !isNaN(d.getTime()) ? d : null;
  }
  if (value instanceof Date) return isNaN(value.getTime()) ? null : value;
  const d = new Date(value);
  return isNaN(d.getTime()) ? null : d;
};

export function CalendarMiniView({ 
  cards, 
  weekStartDay = 'monday',
  accentColor = '#689A98'
}: CalendarMiniViewProps) {
  const [currentMonth, setCurrentMonth] = useState(new Date());
  const [selectedDate, setSelectedDate] = useState(new Date());

  // 日付ごとのカード枚数を算出
  const cardsByDate = useMemo(() => {
    const grouped: Record<string, Card[]> = {};
    cards.forEach(card => {
      const dateVal = card.nextReviewDate || (card as any).next_review_date;
      const dateObj = toDate(dateVal);
      if (!dateObj) return;

      const dateKey = format(dateObj, 'yyyy-MM-dd');
      if (!grouped[dateKey]) grouped[dateKey] = [];
      grouped[dateKey].push(card);
    });
    return grouped;
  }, [cards]);

  // カレンダーの日付リストを生成
  const calendarDays = useMemo(() => {
    const monthStart = startOfMonth(currentMonth);
    const monthEnd = endOfMonth(currentMonth);
    const startDate = startOfWeek(monthStart, { weekStartsOn: weekStartDay === 'sunday' ? 0 : 1 });
    const endDate = endOfWeek(monthEnd, { weekStartsOn: weekStartDay === 'sunday' ? 0 : 1 });

    const days = [];
    let day = startDate;
    while (day <= endDate) {
      days.push(day);
      day = addDays(day, 1);
    }
    return days;
  }, [currentMonth, weekStartDay]);

  const weekDays = weekStartDay === 'sunday' 
    ? ['S', 'M', 'T', 'W', 'T', 'F', 'S']
    : ['M', 'T', 'W', 'T', 'F', 'S', 'S'];

  const selectedCards = useMemo(() => {
    const key = format(selectedDate, 'yyyy-MM-dd');
    return cardsByDate[key] || [];
  }, [selectedDate, cardsByDate]);

  return (
    <div className="space-y-4">
      <div className="flex items-center justify-between mb-4">
        <div className="flex items-center gap-2">
          <CalendarIcon className="w-4 h-4 text-slate-400" />
          <span className="text-sm font-bold text-slate-700 uppercase tracking-wider">
            {format(currentMonth, 'MMMM yyyy')}
          </span>
        </div>
        <div className="flex items-center gap-1">
          <Button 
            variant="ghost" 
            size="icon" 
            className="h-7 w-7 rounded-full"
            onClick={() => setCurrentMonth(addMonths(currentMonth, -1))}
          >
            <ChevronLeft className="w-4 h-4" />
          </Button>
          <Button 
            variant="ghost" 
            size="icon" 
            className="h-7 w-7 rounded-full"
            onClick={() => setCurrentMonth(addMonths(currentMonth, 1))}
          >
            <ChevronRight className="w-4 h-4" />
          </Button>
        </div>
      </div>

      <div className="grid grid-cols-7 mb-2">
        {weekDays.map((d, i) => (
          <div key={i} className="text-center text-[10px] font-bold text-slate-300">
            {d}
          </div>
        ))}
      </div>

      <div className="grid grid-cols-7 gap-1">
        {calendarDays.map((day, i) => {
          const isCurrentMonth = isSameMonth(day, currentMonth);
          const isSelected = isSameDay(day, selectedDate);
          const isTodayDate = isToday(day);
          const dateKey = format(day, 'yyyy-MM-dd');
          const dayCards = cardsByDate[dateKey] || [];
          const count = dayCards.length;

          return (
            <button
              key={i}
              onClick={() => setSelectedDate(day)}
              className={cn(
                "h-10 rounded-xl flex flex-col items-center justify-center transition-all relative overflow-hidden",
                !isCurrentMonth && "opacity-20",
                isSelected 
                  ? "bg-primary-50 text-primary-700 ring-1 ring-primary-200" 
                  : "hover:bg-slate-50 text-slate-500",
                isTodayDate && !isSelected && "bg-slate-100 font-bold"
              )}
            >
              <span className="text-[11px] font-medium leading-none mb-1">{format(day, 'd')}</span>
              {count > 0 && (
                <div 
                  className="w-1 h-1 rounded-full" 
                  style={{ backgroundColor: accentColor }}
                />
              )}
            </button>
          );
        })}
      </div>

      {selectedCards.length > 0 && (
        <div className="mt-4 pt-4 border-t border-slate-100 animate-in fade-in slide-in-from-top-2 duration-300">
          <div className="text-[10px] font-bold text-slate-400 uppercase mb-2">
            {format(selectedDate, 'MMM d')} - {selectedCards.length} Cards
          </div>
          <div className="space-y-1.5 max-h-[120px] overflow-y-auto pr-1 no-scrollbar">
            {selectedCards.slice(0, 5).map((card, i) => (
              <div key={i} className="text-[11px] text-slate-600 truncate bg-slate-50/50 rounded-lg px-2 py-1.5 border border-slate-100/50">
                {card.title || '無題のカード'}
              </div>
            ))}
            {selectedCards.length > 5 && (
              <div className="text-[10px] text-slate-400 italic pl-2 pt-1">
                and {selectedCards.length - 5} more...
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
}

