import { useCardBlocksDnd } from "@/components/card/editor/useCardBlocksDnd";
import { useCardMediaDialogs } from "@/components/card/editor/useCardMediaDialogs";

import type { Dispatch, MutableRefObject, SetStateAction } from "react";
import type { CardBlock, UploadedImage } from "@/types";

type DraftShape = {
  questionImages: UploadedImage[];
  answerImages: UploadedImage[];
  questionBlocks: CardBlock[];
  answerBlocks: CardBlock[];
};

type UseCardEditorContentControllerParams<TDraft extends DraftShape | null> = {
  draft: TDraft;
  setDraft: Dispatch<SetStateAction<TDraft>>;
  allowAutoMinHeightSyncRef: MutableRefObject<boolean>;
  resetDialogsRef: MutableRefObject<() => void>;
};

export function useCardEditorContentController<TDraft extends DraftShape | null>({
  draft,
  setDraft,
  allowAutoMinHeightSyncRef,
  resetDialogsRef,
}: UseCardEditorContentControllerParams<TDraft>) {
  const getSideBlocks = (side: "question" | "answer") =>
    side === "question" ? (draft?.questionBlocks ?? []) : (draft?.answerBlocks ?? []);

  const setSideBlocks = (side: "question" | "answer", nextBlocks: CardBlock[]) => {
    allowAutoMinHeightSyncRef.current = true;
    setDraft((prev) => {
      if (!prev) return prev;
      const reindexed = nextBlocks.map((block, index) => ({ ...block, orderIndex: index }));
      return side === "question" ? { ...prev, questionBlocks: reindexed } : { ...prev, answerBlocks: reindexed };
    });
  };

  const upsertSingleBlock = (side: "question" | "answer", type: CardBlock["type"], payload: Partial<CardBlock>) => {
    const uniqueId =
      typeof crypto !== "undefined" && typeof crypto.randomUUID === "function"
        ? crypto.randomUUID()
        : `${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;

    const blocks = getSideBlocks(side);
    const index = blocks.findIndex((block) => block.type === type);

    if (index >= 0) {
      const next = [...blocks];
      next[index] = { ...next[index], ...payload };
      setSideBlocks(side, next);
      return;
    }

    const nextBlock: CardBlock = {
      id: `${side}-${type}-${uniqueId}`,
      type,
      orderIndex: blocks.length,
      content: "",
      ...payload,
    } as CardBlock;

    setSideBlocks(side, [...blocks, nextBlock]);
  };

  const removeBlockByTypeIfExists = (side: "question" | "answer", type: CardBlock["type"]) => {
    const blocks = getSideBlocks(side);
    setSideBlocks(
      side,
      blocks.filter((block) => block.type !== type)
    );
  };

  const { onDragEnd } = useCardBlocksDnd({
    draft,
    setDraft,
    allowAutoMinHeightSyncRef,
  });

  const mediaDialogs = useCardMediaDialogs({
    draft,
    setDraft,
    getSideBlocks,
    setSideBlocks,
    removeBlockByTypeIfExists,
    upsertSingleBlock,
  });

  resetDialogsRef.current = () => {
    mediaDialogs.setImageDialogSide(null);
    mediaDialogs.setAudioDialogSide(null);
    mediaDialogs.setLinkDialogSide(null);
  };

  return {
    onDragEnd,
    setSideBlocks,
    ...mediaDialogs,
  };
}

import { useCallback, useEffect, useMemo, useRef, useState } from "react";

import { sortBlocksByOrderIndex } from "@/components/card/blocks/blockOrdering";
import {
  makeNewDraft,
  normalizeOrderIndex,
  normalizeSelectedCardId,
  sanitizeReferences,
  shouldAutoOpenEditorForCard,
  type EditorDraft,
} from "@/components/card/editor/cardEditorUtils";
import { LEGACY_BASE_LAYOUT_ROWS, normalizeExtraRows, normalizeLayoutRows } from "@/domain/card/extraRows";
import { resolveCardTagNames } from "@/hooks/useTags";

import type { CardBlock, Card, UploadedImage } from "@/types";

const NEW_SENTINEL = "__new__" as const;

type UseCardEditorSessionParams = {
  selectedCardId: string | null;
  folderId?: string;
  autoEdit?: boolean;
  cards: Card[];
  updateCard: (id: string, data: Partial<Card>) => Promise<unknown>;
  createCard?: (data: Partial<Card>) => Promise<unknown>;
  addTag: (name: string) => Promise<{ id: string }>;
  tagById: Map<string, unknown> | Record<string, unknown>;
  toastSuccess?: (message: string) => void;
  toastError?: (message: string) => void;
  onCardUpdated?: () => void;
  onSelectCardId?: (cardId: string) => void;
  resetDialogs: () => void;
};

export function useCardEditorSession({
  selectedCardId,
  folderId,
  autoEdit,
  cards,
  updateCard,
  createCard,
  addTag,
  tagById,
  toastSuccess,
  toastError,
  onCardUpdated,
  onSelectCardId,
  resetDialogs,
}: UseCardEditorSessionParams) {
  const [localSelectedCardId, setLocalSelectedCardId] = useState<string | null>(null);
  const [isFlipped, setIsFlipped] = useState(false);
  const [isEditing, setIsEditing] = useState(false);
  const [isSaving, setIsSaving] = useState(false);
  const [draft, setDraft] = useState<EditorDraft | null>(null);

  const editingCardIdRef = useRef<string | null>(null);
  const hydratedFromIdRef = useRef<string | null>(null);
  const autoOpenCheckedIdRef = useRef<string | null>(null);

  useEffect(() => {
    if (selectedCardId != null) setLocalSelectedCardId(null);
  }, [selectedCardId]);

  const effectiveSelectedCardId = selectedCardId ?? localSelectedCardId;
  const normalizedSelectedCardId = useMemo(
    () => normalizeSelectedCardId(effectiveSelectedCardId),
    [effectiveSelectedCardId]
  );
  const isNew = normalizedSelectedCardId === NEW_SENTINEL;

  const selectedCard = useMemo(() => {
    if (!normalizedSelectedCardId || isNew) return null;
    return cards.find((card) => card.id === normalizedSelectedCardId) ?? null;
  }, [cards, normalizedSelectedCardId, isNew]);

  const buildDraftFromCard = useCallback((card: Card): EditorDraft => {
    const legacyQuestionRows = normalizeExtraRows((card as any)?.questionExtraRows ?? (card as any)?.question_extra_rows ?? 0);
    const legacyAnswerRows = normalizeExtraRows((card as any)?.answerExtraRows ?? (card as any)?.answer_extra_rows ?? 0);
    const migratedRows = LEGACY_BASE_LAYOUT_ROWS + Math.max(legacyQuestionRows, legacyAnswerRows);

    return {
      title: card.title ?? "",
      tags: resolveCardTagNames(card.tagIds, (card as any).tags, tagById as any),
      isDraft: card.isDraft ?? false,
      questionImages: ((card as any).questionImages ?? []) as UploadedImage[],
      answerImages: ((card as any).answerImages ?? []) as UploadedImage[],
      questionBlocks: sortBlocksByOrderIndex((card.questionBlocks ?? []) as CardBlock[]),
      answerBlocks: sortBlocksByOrderIndex((card.answerBlocks ?? []) as CardBlock[]),
      layoutRows: normalizeLayoutRows((card as any).layoutRows ?? (card as any).layout_rows ?? migratedRows),
    };
  }, [tagById]);

  useEffect(() => {
    if (!normalizedSelectedCardId) {
      setIsFlipped(false);
      setIsEditing(false);
      setDraft(null);
      editingCardIdRef.current = null;
      hydratedFromIdRef.current = null;
      autoOpenCheckedIdRef.current = null;
      return;
    }

    setIsFlipped(false);

    if (normalizedSelectedCardId === NEW_SENTINEL) {
      setIsEditing(true);
      setDraft((prev) => prev ?? makeNewDraft());
      editingCardIdRef.current = NEW_SENTINEL;
      hydratedFromIdRef.current = NEW_SENTINEL;
      autoOpenCheckedIdRef.current = NEW_SENTINEL;
      return;
    }

    setIsEditing(!!autoEdit);
    setDraft(null);
    editingCardIdRef.current = null;
    hydratedFromIdRef.current = null;
    autoOpenCheckedIdRef.current = null;
  }, [autoEdit, normalizedSelectedCardId]);

  useEffect(() => {
    if (!normalizedSelectedCardId || normalizedSelectedCardId === NEW_SENTINEL || !selectedCard || isEditing) return;
    if (autoOpenCheckedIdRef.current === normalizedSelectedCardId) return;
    autoOpenCheckedIdRef.current = normalizedSelectedCardId;
    if (shouldAutoOpenEditorForCard(selectedCard)) setIsEditing(true);
  }, [normalizedSelectedCardId, selectedCard, isEditing]);

  useEffect(() => {
    if (isEditing) {
      editingCardIdRef.current = isNew ? NEW_SENTINEL : normalizedSelectedCardId;
      return;
    }
    editingCardIdRef.current = null;
    hydratedFromIdRef.current = null;
    setDraft(null);
  }, [isEditing, isNew, normalizedSelectedCardId]);

  useEffect(() => {
    if (!isEditing) return;

    const targetId = isNew ? NEW_SENTINEL : normalizedSelectedCardId;
    if (!targetId) return;

    if (isNew) {
      setDraft((prev) => prev ?? makeNewDraft());
      hydratedFromIdRef.current = NEW_SENTINEL;
      return;
    }

    if (!selectedCard) return;
    if (hydratedFromIdRef.current === selectedCard.id) return;

    setDraft(buildDraftFromCard(selectedCard));
    hydratedFromIdRef.current = selectedCard.id;
  }, [isEditing, isNew, normalizedSelectedCardId, selectedCard, buildDraftFromCard]);

  const handleStartNew = useCallback(() => {
    setDraft(makeNewDraft());
    setIsEditing(true);

    if (typeof onSelectCardId === "function") onSelectCardId(NEW_SENTINEL);
    else setLocalSelectedCardId(NEW_SENTINEL);
  }, [onSelectCardId]);

  const handleCancel = useCallback(() => {
    setIsSaving(false);
    resetDialogs();
    setDraft(null);
    setIsEditing(false);

    if (!selectedCardId && localSelectedCardId === NEW_SENTINEL) {
      setLocalSelectedCardId(null);
    }
  }, [localSelectedCardId, resetDialogs, selectedCardId]);

  const handleSave = useCallback(async () => {
    if (!draft) return;

    try {
      setIsSaving(true);

      const sanitizeBlocksForSave = (blocks: CardBlock[]): CardBlock[] => {
        const next: CardBlock[] = [];
        for (const block of blocks ?? []) {
          if (block?.type === "reference") {
            const cleaned = sanitizeReferences((block as any)?.references ?? []);
            if (cleaned.length === 0) continue;
            next.push({ ...(block as any), references: cleaned } as CardBlock);
            continue;
          }
          next.push(block);
        }
        return normalizeOrderIndex(next);
      };

      const resolvedTags = await Promise.all(draft.tags.map((name) => addTag(name)));
      const tagIds = resolvedTags.map((tag) => tag.id);
      const payload: Partial<Card> = {
        title: draft.title,
        tagIds,
        isDraft: draft.isDraft,
        questionImages: draft.questionImages,
        answerImages: draft.answerImages,
        questionBlocks: sanitizeBlocksForSave(draft.questionBlocks),
        answerBlocks: sanitizeBlocksForSave(draft.answerBlocks),
        layoutRows: normalizeLayoutRows(draft.layoutRows),
      };

      if (isNew) {
        if (typeof createCard !== "function") {
          console.error("[CardEditorPane] createCard が useCards にありません。useCards の作成関数名に合わせて置き換えてください。");
          toastError?.("カードの作成関数が見つかりません");
          return;
        }

        const created = await createCard({ ...payload, folderId: folderId ?? "" });
        const newId =
          (typeof created === "object" && created !== null && "id" in created && (created as any).id) ||
          (typeof created === "string" ? created : null);

        onCardUpdated?.();
        toastSuccess?.("カードを作成しました");

        if (newId) {
          if (typeof onSelectCardId === "function") onSelectCardId(newId);
          else setLocalSelectedCardId(newId);
        }

        setIsEditing(false);
        return;
      }

      if (!selectedCard) return;

      await updateCard(selectedCard.id, payload);
      onCardUpdated?.();
      toastSuccess?.("カードを更新しました");
      setIsEditing(false);
    } catch (error) {
      console.error("カード保存に失敗しました:", error);
      const message = error instanceof Error ? error.message : "カード保存に失敗しました";
      toastError?.(message);
    } finally {
      setIsSaving(false);
    }
  }, [
    addTag,
    createCard,
    draft,
    folderId,
    isNew,
    onCardUpdated,
    onSelectCardId,
    selectedCard,
    toastError,
    toastSuccess,
    updateCard,
  ]);

  const handleToggleBookmark = useCallback(async (card: Card) => {
    try {
      await updateCard(card.id, { isBookmarked: !card.isBookmarked });
      onCardUpdated?.();
    } catch (error) {
      console.error("ブックマークの更新に失敗しました:", error);
    }
  }, [onCardUpdated, updateCard]);

  const handleToggleUncertainty = useCallback(async (card: Card) => {
    try {
      await updateCard(card.id, { hasUncertainty: !card.hasUncertainty });
      onCardUpdated?.();
    } catch (error) {
      console.error("不確証マークの更新に失敗しました:", error);
    }
  }, [onCardUpdated, updateCard]);

  const handleUpdateTags = useCallback(async (nextTags: string[]) => {
    if (isEditing) {
      setDraft((prev) => (prev ? { ...prev, tags: nextTags } : prev));
      return;
    }
    if (!selectedCard) return;
    const resolved = await Promise.all(nextTags.map((name) => addTag(name)));
    await updateCard(selectedCard.id, { tagIds: resolved.map((tag) => tag.id) });
    onCardUpdated?.();
  }, [addTag, isEditing, onCardUpdated, selectedCard, updateCard]);

  const handleToggleDraft = useCallback(async (nextIsDraft: boolean) => {
    if (isEditing) {
      setDraft((prev) => (prev ? { ...prev, isDraft: nextIsDraft } : prev));
    }
    // 既存カード編集中は即同期する。新規カード（selectedCardなし）のみローカル保持。
    if (!selectedCard) return;
    await updateCard(selectedCard.id, { isDraft: nextIsDraft });
    onCardUpdated?.();
  }, [isEditing, onCardUpdated, selectedCard, updateCard]);

  const handleUpdateTitle = useCallback(async (nextTitle: string) => {
    if (isEditing) {
      setDraft((prev) => (prev ? { ...prev, title: nextTitle } : prev));
      return;
    }
    if (!selectedCard) return;
    await updateCard(selectedCard.id, { title: nextTitle });
    onCardUpdated?.();
  }, [isEditing, onCardUpdated, selectedCard, updateCard]);

  const panelCard = useMemo(() => {
    if (selectedCard) {
      if (!isEditing || !draft) return selectedCard;
      return {
        ...selectedCard,
        title: draft.title,
        tags: draft.tags,
        isDraft: draft.isDraft,
        layoutRows: draft.layoutRows,
      };
    }
    if (!draft) return null;

    const now = new Date();
    return {
      id: "__draft__",
      userId: "",
      deviceId: "web",
      folderId: "",
      orderIndex: 0,
      questionNumber: "",
      title: draft.title,
      tags: draft.tags,
      isDraft: draft.isDraft,
      isDeleted: false,
      hasUncertainty: false,
      isBookmarked: false,
      isCompleted: false,
      isSilent: false,
      questionText: "",
      questionImages: [],
      questionAudios: [],
      questionMarked: "",
      answerText: "",
      answerImages: [],
      answerAudios: [],
      answerMarked: "",
      memoryStability: 0,
      nextReviewDate: now,
      createdAt: now,
      updatedAt: now,
      reviewLogs: [],
      layoutRows: draft.layoutRows,
    } as Card;
  }, [draft, isEditing, selectedCard]);

  return {
    draft,
    setDraft,
    normalizedSelectedCardId,
    isNew,
    selectedCard,
    isFlipped,
    setIsFlipped,
    isEditing,
    setIsEditing,
    isSaving,
    handleStartNew,
    handleCancel,
    handleSave,
    handleToggleBookmark,
    handleToggleUncertainty,
    handleUpdateTags,
    handleToggleDraft,
    handleUpdateTitle,
    panelCard,
  };
}

import React, { useCallback } from 'react';
import { Star } from '@/ui/icons';
import { CircleHelp } from '@/ui/icons';
import { cn } from '@/lib/utils';
import {
  CARD_ACTION_BG_CLASS,
  CARD_ACTION_COLOR_ACTIVE_CLASS,
  CARD_ACTION_COLOR_IDLE_CLASS,
  CARD_ACTION_ICON_CLASS,
} from '@/components/card/common/constants';

interface CardCornerActionsProps {
  onHelp?: () => void;
  onStar?: () => void;
  helpActive?: boolean;
  starActive?: boolean;
  disabled?: boolean;
  className?: string;
}

export function CardCornerActions({
  onHelp,
  onStar,
  helpActive = false,
  starActive = false,
  disabled = false,
  className,
}: CardCornerActionsProps) {
  if (!onHelp && !onStar) return null;

  const stop = useCallback((e: React.SyntheticEvent) => {
    e.stopPropagation();
  }, []);

  const buttonBaseClass =
    'rounded-full h-7 w-7 min-h-0 min-w-0 transition-colors flex items-center justify-center bg-transparent hover:bg-transparent active:bg-transparent ' +
    'focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-primary/40';
  const disabledClass = disabled ? 'opacity-50 pointer-events-none' : '';

  return (
    <div className={cn('flex items-center gap-1', className)}>
      {onHelp ? (
        <button
          type="button"
          aria-label="不確実フラグ"
          aria-pressed={helpActive}
          disabled={disabled}
          onPointerDown={stop}
          onMouseDown={stop}
          onKeyDown={stop}
          onClick={(e) => {
            e.stopPropagation();
            onHelp();
          }}
          className={cn(
            buttonBaseClass,
            disabledClass,
            CARD_ACTION_BG_CLASS,
            helpActive
              ? CARD_ACTION_COLOR_ACTIVE_CLASS
              : CARD_ACTION_COLOR_IDLE_CLASS
          )}
        >
          <CircleHelp className={cn(CARD_ACTION_ICON_CLASS, helpActive && 'opacity-90')} />
        </button>
      ) : null}

      {onStar ? (
        <button
          type="button"
          aria-label="ブックマーク"
          aria-pressed={starActive}
          disabled={disabled}
          onPointerDown={stop}
          onMouseDown={stop}
          onKeyDown={stop}
          onClick={(e) => {
            e.stopPropagation();
            onStar();
          }}
          className={cn(
            buttonBaseClass,
            disabledClass,
            CARD_ACTION_BG_CLASS,
            starActive
              ? CARD_ACTION_COLOR_ACTIVE_CLASS
              : CARD_ACTION_COLOR_IDLE_CLASS
          )}
        >
          <Star className={cn(CARD_ACTION_ICON_CLASS, starActive && 'fill-current')} />
        </button>
      ) : null}
    </div>
  );
}

import React from 'react';
import { cn } from '@/lib/utils';
import { ScaleToFitFrame } from '@/components/card/frame/ScaleToFitFrame';
import { CardShell } from '@/components/card/frame/CardShell';
import { CardSurface } from '@/components/card/frame/CardSurface';
import {
  CARD_BASE_WIDTH,
  CARD_RULED_OFFSET_BOTTOM_PX,
  CARD_ROW_PX,
  CARD_RULED_OFFSET_TOP_PX,
} from '@/components/card/common/constants';

// CardShell の props 型をそのまま流用するための別名
type CardShellProps = React.ComponentProps<typeof CardShell>;

/**
 * CardFrame:
 * - 「カードの外枠 + スケール調整 + 罫線背景 + overlay」をまとめた共通フレーム
 * - 編集/閲覧/学習など、どこでも同じカード見た目にしたい時の“正”になるコンポーネント
 */
export interface CardFrameProps
  // CardShell の props を基本的に引き継ぐが、
  // children は CardFrame 側で明示管理し、
  // className は CardFrame が標準スタイルを持つので上書き合成のため別定義、
  // ref は forwardRef で受けるので除外する
  extends Omit<CardShellProps, 'children' | 'className' | 'ref'> {
  /** カード内部に表示する内容 */
  children: React.ReactNode;

  /** “設計上のカード基準幅(px)”。ScaleToFitFrame の基準にも使う */
  baseWidth?: number;

  /** 画面端からの余白など、スケール計算に使う padding(px) */
  contentPaddingPx?: number;

  /** 基準幅より大きく拡大して表示してよいか */
  allowUpscale?: boolean;

  /** 拡大時の最大スケール */
  maxScale?: number;

  /** 追加のスケール倍率 */
  scaleMultiplier?: number;

  /** CardShell に渡す追加クラス（標準クラスに合成される） */
  className?: string;

  /** 罫線（ノートっぽい線）を使うか */
  ruled?: boolean;

  /** 罫線の行間(px)。CARD_ROW_PX と揃えると「文字行」と一致する */
  ruledRowPx?: number;

  /** 罫線の開始Yオフセット(px)。上部 padding と揃えてズレを防ぐ */
  ruledOffsetPx?: number;

  /** 罫線の不透明度（薄さ調整） */
  ruledOpacity?: number;
  /** カード下端から最後の罫線までのオフセット(px) */
  ruledBottomOffsetPx?: number;
  /** 罫線の位相オフセット(px)。未指定時は 0。 */
  ruledPhasePx?: number;

  /** カード表面に重ねる overlay（例: インク層、選択ハイライト、UIレイヤなど） */
  overlay?: React.ReactNode;
}

/**
 * forwardRef:
 * - 親が CardShell の DOM を掴めるようにする（計測、スクロール制御、focus、DND等で必要になりがち）
 */
export const CardFrame = React.forwardRef<HTMLDivElement, CardFrameProps>(
  (
    {
      children,

      // カードの“基準幅”。ここを変えるとスケールやレイアウト基準が変わる
      baseWidth = CARD_BASE_WIDTH,

      // 画面側の余白。小さいと画面端ギリギリまでカードが来て事故りやすい
      contentPaddingPx = 12,
      allowUpscale = false,
      maxScale = 1.6,
      scaleMultiplier = 1,

      // 追加のクラス（標準の見た目に合成）
      className,

      // 罫線背景の設定（紙っぽいカード前提）
      ruled = true,
      ruledRowPx = CARD_ROW_PX,
      ruledOffsetPx = CARD_RULED_OFFSET_TOP_PX,
      ruledBottomOffsetPx = CARD_RULED_OFFSET_BOTTOM_PX,
      ruledPhasePx = 0,
      ruledOpacity = 1,

      // 表面に重ねるUIレイヤ（例: インク、選択状態、ガイド）
      overlay,

      // CardShell に渡す style（外から上書きできる）
      style,

      // CardShell に渡すそれ以外の props（onClick 等）
      ...shellProps
    },
    ref
  ) => {
    return (
      /**
       * ScaleToFitFrame:
       * - 画面サイズに合わせて「カード全体」を縮小/拡大して収めるラッパー
       * - baseWidth を基準にスケール計算する
       * - contentPaddingPx は「カード周囲の安全余白」としてスケール計算に使う
       */
      <ScaleToFitFrame
        baseWidth={baseWidth}
        contentPaddingPx={contentPaddingPx}
        allowUpscale={allowUpscale}
        maxScale={maxScale}
        scaleMultiplier={scaleMultiplier}
      >
        {/* スケール後のカードを中央寄せしたいので mx-auto ラッパー */}
        <div className="mx-auto">
          {/**
           * CardShell:
           * - カード外枠（角丸/影/背景/ボーダーなど）を担う“器”
           * - ここが「カードの物理感」を作る中核
           */}
          <CardShell
            ref={ref}
            className={cn(
              // 標準スタイル: 中央寄せ、ボーダー無し、角丸をデバイス幅で変える
              'mx-auto border-none rounded-[32px] md:rounded-[40px]',
              className
            )}
            style={{
              // 外から渡された style を尊重しつつ
              ...(style as React.CSSProperties | undefined),

              /**
               * CSS 変数 --card-base-width:
               * - カード内の別コンポーネント（例えば横幅計算やレイアウト）で参照するための共有値
               * - baseWidth が 0/負にならないよう最低 1px に丸める
               */
              ['--card-base-width' as any]: `${Math.max(1, baseWidth)}px`,
            }}
            {...shellProps}
          >
            {/**
             * CardSurface:
             * - カードの“紙面”部分（罫線背景、内側padding、overlayレイヤなど）を担当
             * - CardShell が「外側」なら CardSurface は「中身の紙」
             */}
            <CardSurface
              ruled={ruled}
              ruledRowPx={ruledRowPx}
              ruledOffsetPx={ruledOffsetPx}
              ruledBottomOffsetPx={ruledBottomOffsetPx}
              ruledPhasePx={ruledPhasePx}
              ruledOpacity={ruledOpacity}
              overlay={overlay}
            >
              {/* 実際のカード内容（ブロック群、テキスト、メディアなど） */}
              {children}
            </CardSurface>
          </CardShell>
        </div>
      </ScaleToFitFrame>
    );
  }
);

CardFrame.displayName = 'CardFrame';

import React from 'react';
import { cn } from '@/lib/utils';
import {
  cardHeightPxToLayoutRows,
  layoutRowsToCardHeightPx,
  snapMinCardHeightPx,
} from '@/components/card/common/constants';
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from '@/components/ui/dropdown-menu';

interface CardShellProps extends React.HTMLAttributes<HTMLDivElement> {
  actions?: React.ReactNode;
  actionsTopLeft?: React.ReactNode;
  actionsTopRight?: React.ReactNode;
  children: React.ReactNode;
  drawMode?: boolean;
  resizable?: boolean;
  resizeStepPx?: number;
  resizeStorageKey?: string;
  heightPx?: number | null;
  onHeightChange?: (heightPx: number) => void;
  onMinHeightChange?: (heightPx: number) => void;
  onResizeStart?: () => void;
  onResizeEnd?: () => void;
  showResizeHandle?: boolean;
  lockHeight?: boolean;
}

export const CardShell = React.forwardRef<HTMLDivElement, CardShellProps>(
  ({
    actions,
    actionsTopLeft,
    actionsTopRight,
    children,
    className,
    style,
    drawMode = false,
    resizable = false,
    resizeStepPx = 24,
    resizeStorageKey,
    heightPx,
    onHeightChange,
    onMinHeightChange,
    onResizeStart,
    onResizeEnd,
    showResizeHandle = true,
    lockHeight = false,
    ...props
  }, ref) => {
    const shellRef = React.useRef<HTMLDivElement | null>(null);
    const [panZoom, setPanZoom] = React.useState({ x: 0, y: 0, scale: 1 });
    const pointersRef = React.useRef(new Map<number, { x: number; y: number }>());
    const panRef = React.useRef<{
      pointerId: number;
      startX: number;
      startY: number;
      originX: number;
      originY: number;
    } | null>(null);
    const pinchRef = React.useRef<{
      distance: number;
      center: { x: number; y: number };
      startScale: number;
      startTranslate: { x: number; y: number };
    } | null>(null);

    const clamp = (value: number, min: number, max: number) => Math.min(max, Math.max(min, value));
    const [customHeightPx, setCustomHeightPx] = React.useState<number | null>(null);
    const resizeRef = React.useRef<{
      pointerId: number;
      startY: number;
      baseHeight: number;
      baseRows: number;
    } | null>(null);
    const resizeRafRef = React.useRef<number | null>(null);
    const resizePendingHeightRef = React.useRef<number | null>(null);

    const computeMinHeight = React.useCallback(() => {
      const element = shellRef.current;
      const contentBaseMin = resizeStepPx * 2;
      if (!element) return contentBaseMin;

      const widthRatio = resizable ? (1 / 8) : (3 / 4);
      const widthBasedMin = Math.ceil(((element.clientWidth || element.offsetWidth || 0) * widthRatio) / resizeStepPx) * resizeStepPx;
      const baseMin = Math.max(contentBaseMin, widthBasedMin || 0);

      const body = element.querySelector('.card-shell-body') as HTMLElement | null;
      if (!body) return baseMin;

      const blockRows = Array.from(body.querySelectorAll('[data-block-row="true"]')) as HTMLElement[];
      if (blockRows.length > 0) {
        const surface = body.querySelector('[data-card-surface="true"]') as HTMLElement | null;
        const surfaceStyle = surface ? window.getComputedStyle(surface) : null;
        const ruledBottomOffsetPx = Math.max(
          0,
          Number.parseFloat(surfaceStyle?.getPropertyValue('--ruled-bottom-offset-px') || '0') || 0
        );
        // NOTE:
        // getBoundingClientRect() is affected by parent transforms (ScaleToFitFrame).
        // Using offset metrics keeps min-height calculation in layout space and
        // prevents underestimation when scaled down.
        const bodyRect = body.getBoundingClientRect();
        const bodyScaleY =
          body.offsetHeight > 0 ? bodyRect.height / body.offsetHeight : 1;
        const safeBodyScaleY =
          Number.isFinite(bodyScaleY) && bodyScaleY > 0 ? bodyScaleY : 1;
        let maxBottom = 0;
        for (const row of blockRows) {
          const measureTarget =
            (row.querySelector('[data-block-measure-root="true"]') as HTMLElement | null) ?? row;
          const style = window.getComputedStyle(row);
          const marginBottom = Number.parseFloat(style.marginBottom || '0') || 0;
          const targetOffsetTop = measureTarget === row ? 0 : measureTarget.offsetTop;
          const layoutBottom =
            row.offsetTop +
            targetOffsetTop +
            Math.max(measureTarget.offsetHeight, measureTarget.scrollHeight) +
            marginBottom;
          const targetRect = measureTarget.getBoundingClientRect();
          const visualBottom = ((targetRect.bottom - bodyRect.top) / safeBodyScaleY) + marginBottom;
          const rowBottom = Math.max(layoutBottom, visualBottom);
          if (rowBottom > maxBottom) {
            maxBottom = rowBottom;
          }
        }

        const contentHeight = Math.max(0, maxBottom);
        const requiredHeight = contentHeight + ruledBottomOffsetPx;
        // Subtract sub-pixel tolerance: getBoundingClientRect() can return fractional
        // CSS pixels (esp. on high-DPI screens), causing requiredHeight to land just
        // above a grid boundary and snapMinCardHeightPx (Math.ceil) to add an extra row.
        const snappedContentHeight = snapMinCardHeightPx(requiredHeight - 0.9);
        return Math.max(baseMin, snappedContentHeight || baseMin);
      }

      return baseMin;
    }, [resizable, resizeStepPx]);

    const computeMaxHeight = React.useCallback(() => {
      if (resizable) return Number.POSITIVE_INFINITY;
      if (typeof window === 'undefined') return 900;
      return Math.max(Math.floor(window.innerHeight * 0.9), 420);
    }, [resizable]);

    const clampHeight = React.useCallback((height: number) => {
      return clamp(height, computeMinHeight(), computeMaxHeight());
    }, [computeMaxHeight, computeMinHeight]);

    const isControlledResize = typeof onHeightChange === 'function';
    const resolvedHeightPx = heightPx ?? customHeightPx;
    const commitHeight = React.useCallback((nextHeight: number) => {
      if (isControlledResize && onHeightChange) {
        onHeightChange(nextHeight);
        return;
      }
      setCustomHeightPx(nextHeight);
    }, [isControlledResize, onHeightChange]);

    const isInteractiveTarget = (target: EventTarget | null) => {
      const element = target as HTMLElement | null;
      if (!element) return false;
      return Boolean(
        element.closest('button, a, input, textarea, select, [role="button"], [data-card-no-pan="true"]')
      );
    };

    React.useEffect(() => {
      const element = shellRef.current;
      if (!element || typeof ResizeObserver === 'undefined') return;

      const updateWidth = () => {
        const width = element.clientWidth || element.offsetWidth;
        if (!width) return;

        element.style.setProperty('--card-w', `${width}px`);

        setCustomHeightPx((prev) => {
          if (prev == null) return prev;
          if (resizeRef.current) return prev;
          return clampHeight(prev);
        });

        if (onMinHeightChange && !resizeRef.current) {
          onMinHeightChange(computeMinHeight());
        }
      };

      updateWidth();
      const observer = new ResizeObserver(updateWidth);
      observer.observe(element);

      return () => observer.disconnect();
    }, [clampHeight, computeMinHeight, onMinHeightChange]);

    React.useEffect(() => {
      if (!resizable || !resizeStorageKey || typeof window === 'undefined') return;

      const raw = window.localStorage.getItem(resizeStorageKey);
      if (!raw) return;

      const parsed = Number(raw);
      if (!Number.isFinite(parsed)) return;
      setCustomHeightPx(clampHeight(parsed));
    }, [clampHeight, resizeStorageKey, resizable]);

    React.useEffect(() => {
      if (!resizable || !resizeStorageKey || customHeightPx == null || typeof window === 'undefined') return;
      window.localStorage.setItem(resizeStorageKey, String(customHeightPx));
    }, [customHeightPx, resizeStorageKey, resizable]);

    React.useEffect(() => {
      if (!onMinHeightChange || typeof ResizeObserver === 'undefined') return;

      const element = shellRef.current;
      if (!element) return;

      const body = element.querySelector('.card-shell-body') as HTMLElement | null;
      if (!body) return;

      let rafId: number | null = null;
      const scheduleNotify = () => {
        if (rafId != null || typeof window === 'undefined') return;
        rafId = window.requestAnimationFrame(() => {
          rafId = null;
          if (resizeRef.current) return;
          onMinHeightChange(computeMinHeight());
        });
      };

      const rowElements = new Set<HTMLElement>();
      const rowObserver = new ResizeObserver(() => scheduleNotify());

      const syncRowObservers = () => {
        const nextRows = new Set(
          Array.from(body.querySelectorAll('[data-block-row="true"]')) as HTMLElement[]
        );

        rowElements.forEach((row) => {
          if (!nextRows.has(row)) {
            rowObserver.unobserve(row);
            rowElements.delete(row);
          }
        });

        nextRows.forEach((row) => {
          if (!rowElements.has(row)) {
            rowObserver.observe(row);
            rowElements.add(row);
          }
        });
      };

      scheduleNotify();
      const bodyObserver = new ResizeObserver(() => scheduleNotify());
      bodyObserver.observe(body);
      syncRowObservers();

      const mutationObserver = new MutationObserver(() => {
        syncRowObservers();
        scheduleNotify();
      });

      mutationObserver.observe(body, {
        childList: true,
        subtree: true,
        characterData: true,
      });

      body.addEventListener('input', scheduleNotify, true);

      return () => {
        body.removeEventListener('input', scheduleNotify, true);
        mutationObserver.disconnect();
        bodyObserver.disconnect();
        rowObserver.disconnect();
        if (rafId != null && typeof window !== 'undefined') {
          window.cancelAnimationFrame(rafId);
        }
      };
    }, [computeMinHeight, onMinHeightChange]);

    React.useEffect(() => {
      if (!drawMode) {
        setPanZoom({ x: 0, y: 0, scale: 1 });
      }
    }, [drawMode]);

    const setRefs = React.useCallback((node: HTMLDivElement | null) => {
      shellRef.current = node;
      if (!ref) return;
      if (typeof ref === 'function') {
        ref(node);
      } else {
        ref.current = node;
      }
    }, [ref]);

    const topLeftItems = React.Children.toArray(actionsTopLeft).filter(Boolean);
    const topRightItems = React.Children.toArray(actionsTopRight ?? actions).filter(Boolean);
    const primaryTopRight = topRightItems.slice(0, 2);
    const overflowTopRight = topRightItems.slice(2);


    const handlePointerDown = (event: React.PointerEvent<HTMLDivElement>) => {
      if (!drawMode) return;
      if (isInteractiveTarget(event.target)) return;

      pointersRef.current.set(event.pointerId, { x: event.clientX, y: event.clientY });

      panRef.current = {
        pointerId: event.pointerId,
        startX: event.clientX,
        startY: event.clientY,
        originX: panZoom.x,
        originY: panZoom.y,
      };

      if (pointersRef.current.size === 2) {
        const points = Array.from(pointersRef.current.values());
        const distance = Math.hypot(points[1].x - points[0].x, points[1].y - points[0].y);
        const center = {
          x: (points[0].x + points[1].x) / 2,
          y: (points[0].y + points[1].y) / 2,
        };
        panRef.current = null;

        pinchRef.current = {
          distance,
          center,
          startScale: panZoom.scale,
          startTranslate: { x: panZoom.x, y: panZoom.y },
        };
      }
    };

    const handlePointerMove = (event: React.PointerEvent<HTMLDivElement>) => {
      if (!drawMode) return;
      if (!pointersRef.current.has(event.pointerId)) return;

      pointersRef.current.set(event.pointerId, { x: event.clientX, y: event.clientY });

      if (pointersRef.current.size >= 2 && pinchRef.current) {
        event.preventDefault();
        const points = Array.from(pointersRef.current.values());
        const distance = Math.hypot(points[1].x - points[0].x, points[1].y - points[0].y);
        const center = {
          x: (points[0].x + points[1].x) / 2,
          y: (points[0].y + points[1].y) / 2,
        };

        const nextScale = clamp(
          pinchRef.current.startScale * (distance / pinchRef.current.distance),
          0.5,
          3
        );
        const nextX =
          center.x -
          ((pinchRef.current.center.x - pinchRef.current.startTranslate.x) / pinchRef.current.startScale) * nextScale;
        const nextY =
          center.y -
          ((pinchRef.current.center.y - pinchRef.current.startTranslate.y) / pinchRef.current.startScale) * nextScale;

        setPanZoom({ x: nextX, y: nextY, scale: nextScale });
        return;
      }

      if (panRef.current?.pointerId === event.pointerId) {
        event.preventDefault();
        const deltaX = event.clientX - panRef.current.startX;
        const deltaY = event.clientY - panRef.current.startY;
        setPanZoom({
          x: panRef.current.originX + deltaX,
          y: panRef.current.originY + deltaY,
          scale: panZoom.scale,
        });
      }
    };

    const handlePointerEnd = (event: React.PointerEvent<HTMLDivElement>) => {
      if (!drawMode) return;
      pointersRef.current.delete(event.pointerId);
      if (panRef.current?.pointerId === event.pointerId) panRef.current = null;
      if (pointersRef.current.size < 2) pinchRef.current = null;
    };

    const enforcedShellOverflowStyle: React.CSSProperties = {
      overflowY: 'visible',
      overflowX: 'visible',
    };

    const shell = (
      <div
        ref={setRefs}
        className={cn('card-shell', drawMode && 'card-shell--paper', resizable && !drawMode && 'card-shell--resizable', className)}
        style={
          resolvedHeightPx != null
            ? ({
                ...(style ?? {}),
                ...enforcedShellOverflowStyle,
                ['--card-resize-height' as any]: `${resolvedHeightPx}px`,
                minHeight: `${resolvedHeightPx}px`,
                ...(lockHeight
                  ? {
                      height: `${resolvedHeightPx}px`,
                      maxHeight: `${resolvedHeightPx}px`,
                    }
                  : {}),
              } as React.CSSProperties)
            : ({
                ...(style ?? {}),
                ...enforcedShellOverflowStyle,
              } as React.CSSProperties)
        }
        {...props}
        onClick={(e) => {
          // ★ card-shell-actions 内のボタン等からのバブリングは無視する
          // overflow:hidden によるクリッピングで stopPropagation が効かない場合の保険
          if ((e.target as HTMLElement).closest('.card-shell-header, .card-shell-footer, .card-shell-action, .card-shell-overflow')) return;
          props.onClick?.(e);
        }}
      >
        {(topLeftItems.length > 0 || topRightItems.length > 0) && (
          <div className="card-shell-header">
            <div className="card-shell-header-side">
              {topLeftItems.map((action, index) => (
                <div key={`top-left-${index}`} className="card-shell-action">
                  {action}
                </div>
              ))}
            </div>
            <div className="card-shell-header-side card-shell-header-side-right">
              {primaryTopRight.map((action, index) => (
                <div key={`action-${index}`} className="card-shell-action">
                  {action}
                </div>
              ))}
              {overflowTopRight.length > 0 && (
                <DropdownMenu>
                  <DropdownMenuTrigger asChild>
                    <button
                      type="button"
                      className="card-shell-overflow"
                      onClick={(event) => event.stopPropagation()}
                      aria-label="More actions"
                    >
                      ...
                    </button>
                  </DropdownMenuTrigger>
                  <DropdownMenuContent align="end" sideOffset={6}>
                    {overflowTopRight.map((action, index) => (
                      <DropdownMenuItem key={`overflow-${index}`} asChild>
                        {React.isValidElement(action) ? action : <span>{action}</span>}
                      </DropdownMenuItem>
                    ))}
                  </DropdownMenuContent>
                </DropdownMenu>
              )}
            </div>
          </div>
        )}
        <div
          className="card-shell-body"
          style={{ overflowY: 'clip', overflowX: 'visible' }}
        >
          {children}
        </div>
        
        {resizable && !drawMode && showResizeHandle && (
          <button
            type="button"
            aria-label="カードの高さを変更"
            className="card-shell-resize-handle"
            onPointerDown={(event) => {
              const element = shellRef.current;
              if (!element) return;

              event.preventDefault();
              event.stopPropagation();

              const pointerId = event.pointerId;
              onResizeStart?.();
              resizeRef.current = {
                pointerId,
                startY: event.clientY,
                baseHeight: resolvedHeightPx ?? element.offsetHeight,
                baseRows: cardHeightPxToLayoutRows(resolvedHeightPx ?? element.offsetHeight),
              };

              const target = event.currentTarget;
              target.setPointerCapture(pointerId);

              const onMove = (moveEvent: PointerEvent) => {
                if (!resizeRef.current || moveEvent.pointerId !== resizeRef.current.pointerId) return;
                moveEvent.preventDefault();

                const deltaY = moveEvent.clientY - resizeRef.current.startY;
                const snappedSteps =
                  deltaY >= 0
                    ? Math.max(0, Math.floor((deltaY + resizeStepPx * 0.75) / resizeStepPx))
                    : Math.min(0, Math.ceil((deltaY - resizeStepPx * 0.25) / resizeStepPx));
                const nextRowsRaw = resizeRef.current.baseRows + snappedSteps;
                const nextHeightRaw = layoutRowsToCardHeightPx(nextRowsRaw);
                const nextHeight = clampHeight(nextHeightRaw);

                resizePendingHeightRef.current = nextHeight;
                if (resizeRafRef.current != null) return;

                resizeRafRef.current = window.requestAnimationFrame(() => {
                  resizeRafRef.current = null;
                  const pendingHeight = resizePendingHeightRef.current;
                  resizePendingHeightRef.current = null;
                  if (pendingHeight == null) return;
                  commitHeight(pendingHeight);
                });
              };

              const onEnd = (endEvent: PointerEvent) => {
                if (!resizeRef.current || endEvent.pointerId !== resizeRef.current.pointerId) return;
                resizeRef.current = null;
                if (resizeRafRef.current != null) {
                  window.cancelAnimationFrame(resizeRafRef.current);
                  resizeRafRef.current = null;
                }
                const pendingHeight = resizePendingHeightRef.current;
                resizePendingHeightRef.current = null;
                if (pendingHeight != null) {
                  commitHeight(pendingHeight);
                }
                if (typeof window !== 'undefined') {
                  window.requestAnimationFrame(() => {
                    onResizeEnd?.();
                  });
                } else {
                  onResizeEnd?.();
                }
                window.removeEventListener('pointermove', onMove);
                window.removeEventListener('pointerup', onEnd);
                window.removeEventListener('pointercancel', onEnd);
              };

              window.addEventListener('pointermove', onMove);
              window.addEventListener('pointerup', onEnd);
              window.addEventListener('pointercancel', onEnd);
            }}
          >
            <span className="card-shell-resize-knob" />
          </button>
        )}
      </div>
    );

    if (!drawMode) {
      return shell;
    }

    return (
      <div
        className="card-shell-viewport"
        onPointerDown={handlePointerDown}
        onPointerMove={handlePointerMove}
        onPointerUp={handlePointerEnd}
        onPointerCancel={handlePointerEnd}
      >
        <div
          className="card-shell-panzoom"
          style={{ transform: `translate(${panZoom.x}px, ${panZoom.y}px) scale(${panZoom.scale})` }}
        >
          {shell}
        </div>
      </div>
    );
  }
);

CardShell.displayName = 'CardShell';

