import React, { useCallback, useEffect, useMemo, useState } from 'react';
import { useKeyboardShortcuts } from '@/hooks/useKeyboardShortcuts';
import { Flashcard } from './Flashcard';
import { useUserSettings } from '@/hooks/useUserSettings';
import { CANONICAL_CARD_WIDTH, CARD_SAFE_PADDING_PX } from '../common/constants';
import { MobileScalableCard } from './MobileScalableCard';

// アプリに合わせてちゃんとした型に置き換えてね（最低限の例）
export type Card = {
  id: string;
  // 必要なフィールドを追加
  [key: string]: unknown;
};

type CardViewerProps = {
  cards: Card[];
  currentIndex: number;
  onIndexChange: (index: number) => void;
  onEdit: (card: Card) => void;
  onToggleUncertainty: (card: Card) => void;
  onToggleBookmark: (card: Card) => void;
};

function clamp(n: number, min: number, max: number) {
  return Math.max(min, Math.min(max, n));
}

function isTypingTarget(target: EventTarget | null) {
  if (!target || !(target instanceof HTMLElement)) return false;

  const tag = target.tagName;
  if (tag === 'INPUT' || tag === 'TEXTAREA' || tag === 'SELECT') return true;
  if (target.isContentEditable) return true;

  // shadcn/ui みたいに div に role="textbox" を付けるケースも吸う
  const role = target.getAttribute('role');
  if (role === 'textbox' || role === 'combobox') return true;

  return false;
}

export default function CardViewer({
  cards,
  currentIndex,
  onIndexChange,
  onEdit,
  onToggleUncertainty,
  onToggleBookmark
}: CardViewerProps) {
  const { settings } = useUserSettings();
  const [isFlipped, setIsFlipped] = useState(false);

  // cards が減ったり差し替わったりして index が範囲外になったときの安全装置
  useEffect(() => {
    if (cards.length === 0) return;
    const next = clamp(currentIndex, 0, cards.length - 1);
    if (next !== currentIndex) {
      onIndexChange(next);
      // 表示カードが変わるので flip もリセット
      setIsFlipped(false);
    }
  }, [cards.length, currentIndex, onIndexChange]);

  const handleIndexChange = useCallback(
    (newIndex: number) => {
      setIsFlipped(false);
      onIndexChange(newIndex);
    },
    [onIndexChange]
  );

  const handlePrev = useCallback(() => {
    if (currentIndex > 0) handleIndexChange(currentIndex - 1);
  }, [currentIndex, handleIndexChange]);

  const handleNext = useCallback(() => {
    if (currentIndex < cards.length - 1) handleIndexChange(currentIndex + 1);
  }, [currentIndex, cards.length, handleIndexChange]);

  const handleFlip = useCallback(() => {
    setIsFlipped(prev => !prev);
  }, []);

  // useKeyboardShortcuts が「Eventを渡してくれる」設計じゃない場合があるので
  // ここでは「無効条件」もショートカット定義に持たせる想定（後述のフック修正で対応）
  const shortcuts = useMemo(
    () => [
      {
        key: 'ArrowLeft',
        action: handlePrev,
        description: '前のカードへ移動',
        when: (e: KeyboardEvent) => !isTypingTarget(e.target)
      },
      {
        key: 'ArrowRight',
        action: handleNext,
        description: '次のカードへ移動',
        when: (e: KeyboardEvent) => !isTypingTarget(e.target)
      },
      {
        // できれば event.code === 'Space' で判定したいけど、フック次第なので key で置く
        key: ' ',
        action: (e?: KeyboardEvent) => {
          // Space のデフォスクロール殺す
          if (e) e.preventDefault();
          handleFlip();
        },
        description: '裏表を切り替え',
        when: (e: KeyboardEvent) => !isTypingTarget(e.target)
      }
    ],
    [handlePrev, handleNext, handleFlip]
  );

  useKeyboardShortcuts(shortcuts as any);

  const card = cards[currentIndex];

  if (!card) {
    return <div className="text-center py-12 text-gray-500">カードがありません</div>;
  }

  return (
    <div className="mx-auto w-full" style={{ maxWidth: `${CANONICAL_CARD_WIDTH + 40}px` }}>
      <MobileScalableCard cardDesignWidth={CANONICAL_CARD_WIDTH} safePadding={CARD_SAFE_PADDING_PX}>
        <Flashcard
          card={card}
          isFlipped={isFlipped}
          onFlip={handleFlip}
          onEdit={onEdit}
          onToggleUncertainty={onToggleUncertainty}
          onToggleBookmark={onToggleBookmark}
          onPrev={handlePrev}
          onNext={handleNext}
          hasNext={currentIndex < cards.length - 1}
          hasPrev={currentIndex > 0}
          currentIndex={currentIndex}
          totalCards={cards.length}
          editorSharedHeightPx={settings?.cardEditorHeightPx ?? null}
        />
      </MobileScalableCard>
    </div>
  );
}

import React, { useState, useEffect, useRef } from 'react';
import { Button } from '@/components/ui/button';
import { ChevronLeft, ChevronRight, Edit, Image as ImageIcon, X, Volume2 } from '@/ui/icons';
import { Link } from '@/ui/icons';
import { Dialog, DialogContent } from '@/components/ui/dialog';
import { cn } from '@/lib/utils';
import { AudioPlayer } from '../media/CardMedia';
import { ReferencePopup } from '../overlays/ReferencePopup';
import type { CardBlock, ReferenceBlockData } from '@/types';
import { InkLayer, InkToolbar, type InkHistoryState, type InkLayerHandle } from '@/components/ink/InkLayer';
import { resolveInkDocument } from '@/components/ink/inkStorage';
import { INK_DOCUMENT_VERSION, type InkDocument, type InkEditTool } from '@/components/ink/inkTypes';
import { CardFrame } from './CardFrame';
import { CardCornerActions } from './CardCornerActions';
import { SharedCardContent } from '../common/SharedCardContent';
import {
  CANONICAL_CARD_WIDTH,
  CARD_ACTION_BG_CLASS,
  CARD_ACTION_COLOR_IDLE_CLASS,
  CARD_ACTION_ICON_CLASS,
  layoutRowsToCardHeightPx,
} from '../common/constants';
import { sortBlocksByOrderIndex } from '../blocks/blockOrdering';
import {
  DEFAULT_LAYOUT_ROWS,
  LEGACY_BASE_LAYOUT_ROWS,
  normalizeExtraRows,
  normalizeLayoutRows,
} from '@/domain/card/extraRows';
import { useCards } from '@/hooks/useCards';

type FlashcardMediaLike =
  | string
  | {
      remoteUrl?: string | null;
      localUrl?: string | null;
      url?: string | null;
    };

type FlashcardCardLike = {
  id?: string;
  cardId?: string;
  has_uncertainty?: boolean;
  hasUncertainty?: boolean;
  is_bookmarked?: boolean;
  isBookmarked?: boolean;
  question_text?: string;
  questionText?: string;
  answer_text?: string;
  answerText?: string;
  question_images?: FlashcardMediaLike[];
  questionImages?: FlashcardMediaLike[];
  answer_images?: FlashcardMediaLike[];
  answerImages?: FlashcardMediaLike[];
  question_audios?: FlashcardMediaLike[];
  questionAudios?: FlashcardMediaLike[];
  answer_audios?: FlashcardMediaLike[];
  answerAudios?: FlashcardMediaLike[];
  questionCode?: { code?: string; language?: string } | null;
  question_code?: { code?: string; language?: string } | null;
  answerCode?: { code?: string; language?: string } | null;
  answer_code?: { code?: string; language?: string } | null;
  questionBlocks?: CardBlock[];
  answerBlocks?: CardBlock[];
  layoutRows?: number;
  layout_rows?: number;
  /** @deprecated Read-only legacy field. Use layoutRows/layout_rows. */
  questionExtraRows?: number;
  /** @deprecated Read-only legacy field. Use layoutRows/layout_rows. */
  question_extra_rows?: number;
  /** @deprecated Read-only legacy field. Use layoutRows/layout_rows. */
  answerExtraRows?: number;
  /** @deprecated Read-only legacy field. Use layoutRows/layout_rows. */
  answer_extra_rows?: number;
  inkQuestion?: InkDocument | null;
  inkAnswer?: InkDocument | null;
  [key: string]: unknown;
};

interface FlashcardProps {
  card: FlashcardCardLike | null | undefined;
  isFlipped?: boolean;
  onFlip?: () => void;
  onEdit?: (card: FlashcardCardLike) => void;
  onToggleUncertainty?: (card: FlashcardCardLike) => void;
  onToggleBookmark?: (card: FlashcardCardLike) => void;
  className?: string;
  showNavigation?: boolean;
  onNext?: () => void;
  onPrev?: () => void;
  hasNext?: boolean;
  hasPrev?: boolean;
  currentIndex?: number;
  totalCards?: number;
  previewMode?: boolean;
  extraHeaderLeft?: React.ReactNode;
  extraHeaderRight?: React.ReactNode;
  extraFooter?: React.ReactNode;
  drawMode?: boolean;
  inkEditingEnabled?: boolean;
  onInkDocumentChange?: (side: 'question' | 'answer', nextDocument: InkDocument) => void;
  allowUpscale?: boolean;
  maxScale?: number;
  scaleMultiplier?: number;
  contentPaddingPx?: number;
}

export function Flashcard({
  card,
  isFlipped,
  onFlip,
  onEdit,
  onToggleUncertainty,
  onToggleBookmark,
  className,
  showNavigation,
  onNext,
  onPrev,
  hasNext,
  hasPrev,
  currentIndex,
  totalCards,
  previewMode,
  extraHeaderLeft,
  extraHeaderRight,
  extraFooter,
  drawMode,
  inkEditingEnabled = false,
  onInkDocumentChange,
  allowUpscale = false,
  maxScale = 1.6,
  scaleMultiplier = 1,
  contentPaddingPx,
}: FlashcardProps) {
  const cardData = card;
  const { updateCard } = useCards();

  const [previewFlipped, setPreviewFlipped] = useState(false);

  const [isImageModalOpen, setIsImageModalOpen] = useState(false);
  const [isReferencePopupOpen, setIsReferencePopupOpen] = useState(false);
  const [isImagePopupOpen, setIsImagePopupOpen] = useState(false);
  const [isAudioPopupOpen, setIsAudioPopupOpen] = useState(false);

  const previewInkRef = useRef<InkLayerHandle | null>(null);
  const contentRef = useRef<HTMLDivElement | null>(null);
  const [previewInkTool, setPreviewInkTool] = useState<InkEditTool | null>(null);
  const [previewInkHistory, setPreviewInkHistory] = useState<InkHistoryState>({
    canUndo: false,
    canRedo: false,
    strokeCount: 0,
  });
  const [layoutStable, setLayoutStable] = useState(false);

  // ✅ side も含めて保持（debounce中のflipでも保存先を間違えない）
  const pendingInkRef = useRef<{ side: 'question' | 'answer'; doc: InkDocument } | null>(null);
  const inkSaveTimerRef = useRef<number | null>(null);

  // ---- 先に派生値を確定（TDZ回避） ----
  const cardIdForInk = cardData?.id ?? cardData?.cardId ?? null;
  const enableDrawMode = drawMode ?? false;
  const effectiveIsFlipped = isFlipped ?? (previewMode ? previewFlipped : false);
  const activeInkSide: 'question' | 'answer' = effectiveIsFlipped ? 'answer' : 'question';

  useEffect(() => {
    if (!previewMode) return;
    setPreviewFlipped(false);
  }, [previewMode, cardData?.id]);

  useEffect(() => {
    if (!inkEditingEnabled) {
      setPreviewInkTool(null);
      return;
    }
