      cardIdForInk,
      pending.side === 'question' ? { inkQuestion: pending.doc } : { inkAnswer: pending.doc }
    ).catch((error) => {
      console.error('[Flashcard] Failed to persist ink document', error);
    });
  }, [cardIdForInk, updateCard]);

