                    </div>
                    <div className="mt-1 flex items-center gap-2">
                      <span className="text-[10px] text-slate-400 truncate font-serif">
                        {(() => {
                          try {
                            return new URL(ref.url).hostname;
                          } catch (e) {
                            return ref.url;
                          }
                        })()}
                      </span>
                    </div>
                  </div>
                </div>
              </a>
            );
          })}
        </div>
      </DialogContent>
    </Dialog>
  );
};

