import { useEffect, useMemo, useState } from "react";
import { useSearchParams } from "react-router-dom";
import { Line, LineChart, ResponsiveContainer, XAxis, YAxis } from "recharts";

import { RatingCountTiles } from "@/features/study/RatingCountTiles";
import { SurfaceButton } from "@/components/ui/surface-button";
import { Switch } from "@/components/ui/switch";
import { TagInput } from "@/components/ui/tag-input";
import { EmptyMetaPanel } from "@/components/card/panels/EmptyMetaPanel";
import { MetaPanelLeadSection } from "@/components/card/panels/MetaPanelShell";
import type { Card, ReviewLog } from "@/types";
import { calculateResistanceScore } from "@/utils/reviewMetrics";
import { useTags, resolveCardTagNames } from "@/hooks/useTags";

type Period = "7d" | "30d" | "all";

type CardMetaPanelProps = {
  card: Card | null;
  reviewLogs?: ReviewLog[];
  onUpdateTags: (nextTags: string[]) => void;
  onToggleDraft: (isDraft: boolean) => void;
  onUpdateTitle: (nextTitle: string) => void;
  mode?: "full" | "calendar";
};

const META_DATE_FORMATTER = new Intl.DateTimeFormat("ja-JP", {
  year: "numeric",
  month: "2-digit",
  day: "2-digit",
  hour: "2-digit",
  minute: "2-digit",
});


function toValidDate(value: unknown): Date | null {
  if (value instanceof Date) {
    return Number.isNaN(value.getTime()) ? null : value;
  }
  if (
    typeof value === "object" &&
    value !== null &&
    "toDate" in value &&
    typeof (value as { toDate?: unknown }).toDate === "function"
  ) {
    const date = (value as { toDate: () => Date }).toDate();
    return Number.isNaN(date.getTime()) ? null : date;
  }
  if (typeof value === "string") {
    const date = new Date(value);
    return Number.isNaN(date.getTime()) ? null : date;
  }
  return null;
}


function formatDateLabel(value: unknown) {
  const date = toValidDate(value);
  if (!date) return "未設定";
  return META_DATE_FORMATTER.format(date);
}


export function CardMetaPanel({
  card,
  reviewLogs = [],
  onUpdateTags,
  onToggleDraft,
  onUpdateTitle,
  mode = "full",
}: CardMetaPanelProps) {
  const isCalendarMode = mode === "calendar";
  const infoRowClass = "h-[var(--meta-row-px)] leading-[var(--meta-row-px)] text-[length:var(--meta-font-size)] text-[var(--sidebar-text)]";
  const actionRowClass = "h-[var(--meta-row-px)] min-h-[var(--meta-row-px)] flex items-center";
  const [period, setPeriod] = useState<Period>("30d");
  const [titleInput, setTitleInput] = useState(card?.title ?? "");
  const [draftChecked, setDraftChecked] = useState(Boolean(card?.isDraft ?? (card as any)?.is_draft));
  const [, setSearchParams] = useSearchParams();
  const { tagById } = useTags();

  useEffect(() => {
    setTitleInput(card?.title ?? "");
  }, [card?.id, card?.title]);

  useEffect(() => {
    setDraftChecked(Boolean(card?.isDraft ?? (card as any)?.is_draft));
  }, [card?.id, card?.isDraft, (card as any)?.is_draft]);

  const safeLogs = useMemo(
    () => [...reviewLogs].sort((a, b) => {
      const aTs = toValidDate(a.reviewedAt)?.getTime() ?? Number.NEGATIVE_INFINITY;
      const bTs = toValidDate(b.reviewedAt)?.getTime() ?? Number.NEGATIVE_INFINITY;
      return aTs - bTs;
    }),
    [reviewLogs]
  );

  const latestReview = safeLogs.at(-1);

  const currentResistanceScore = useMemo(() => {
    if (!card) return null;
    if (latestReview?.resistanceScore != null && latestReview.resistanceScore > 0) {
      return latestReview.resistanceScore;
    }
    const next = toValidDate(card.nextReviewDate ?? (card as any).next_review_date);
    const last = toValidDate(card.lastReviewAt ?? (card as any).last_review_at);
    if (!next || !last) return null;
    const intervalDays = Math.max(0, (next.getTime() - last.getTime()) / (1000 * 60 * 60 * 24));
    return calculateResistanceScore(intervalDays);
  }, [card, latestReview]);

  // reviewCount は snake_case で入ってくるケースがあるので両対応しておく（UI側は事故らないのが正義）
  const rawReviewCount = (card?.reviewCount ?? (card as any)?.review_count ?? 0) as unknown;
  const normalizedReviewCount = Number.isFinite(Number(rawReviewCount))
    ? Math.max(0, Math.trunc(Number(rawReviewCount)))
    : 0;

  // SSOT は card.reviewCount（互換あり）。ログはあってもなくても表示が壊れないよう max を取る。
  const completedReviewCount = Math.max(normalizedReviewCount, safeLogs.length);
  const nextReviewAttempt = completedReviewCount + 1;

  const distribution20 = useMemo(() => {
    const base = { forgot: 0, vague: 0, remembered: 0, easy: 0 };
    for (const log of safeLogs.slice(-20)) {
      if (log.rating === 1) base.forgot += 1;
      else if (log.rating === 2) base.vague += 1;
      else if (log.rating === 3) base.remembered += 1;
      else if (log.rating === 4) base.easy += 1;
    }
    return base;
  }, [safeLogs]);

  const chartData = useMemo(() => {
    const all = safeLogs
      .filter((log) => log.resistanceScore != null)
      .map((log, idx) => ({ reviewIndex: idx + 1, resistanceScore: log.resistanceScore }));
    if (period === "all") return all;
    const count = period === "7d" ? 7 : 30;
    return all.slice(-count);
  }, [safeLogs, period]);

  const xTicks = useMemo(() => {
    if (chartData.length <= 1) return chartData.map((d) => d.reviewIndex);
    return chartData
      .filter((_, idx) => idx % 5 === 0 || idx === chartData.length - 1)
      .map((d) => d.reviewIndex);
  }, [chartData]);

  // tagIds 優先、fallback: card.tags（移行期間互換）
  const tags = resolveCardTagNames(card?.tagIds, card?.tags, tagById);

  const commitTitle = () => {
    const next = titleInput.trim();
    const current = (card?.title ?? "").trim();
    if (next === current) return;
    onUpdateTitle(next);
  };

  const openTagSettings = () => {
    setSearchParams((prev) => {
      const next = new URLSearchParams(prev);
      next.set("settings", "true");
      next.set("settingsTab", "tags");
      return next;
    }, { replace: true });
  };

  return (
    <EmptyMetaPanel>
          <MetaPanelLeadSection>
              {!isCalendarMode && (
                <>
                  <div className={actionRowClass}>
                    <input
                      value={titleInput}
                      onChange={(e) => setTitleInput(e.target.value)}
                      onBlur={commitTitle}
                      disabled={!card}
                      onKeyDown={(e) => {
                        if (e.key === "Enter") {
                          e.preventDefault();
                          commitTitle();
                        }
                      }}
                      className="h-[var(--meta-row-px)] w-full rounded-md border border-[var(--surface-border)] bg-white px-2 text-[length:var(--surface-placeholder-font-size)] leading-[var(--meta-row-px)] text-[#6e6466] surface-concave outline-none placeholder:text-[var(--surface-placeholder-text)] focus:border-[#cfcfcf] focus:bg-white"
                      placeholder="タイトル"
                    />
                  </div>
                  <div className={`${actionRowClass} justify-start gap-2`}>
                    <Switch
                      checked={draftChecked}
                      onCheckedChange={(next) => {
                        setDraftChecked(next);
                        if (!card) return;
                        void Promise.resolve(onToggleDraft(next)).catch(() => {
                          setDraftChecked(Boolean(card?.isDraft ?? (card as any)?.is_draft));
                        });
                      }}
                      disabled={!card}
                    />
                    <span className="text-[length:var(--meta-font-size)] font-medium leading-[var(--meta-row-px)] text-[var(--sidebar-text-muted)]">下書き</span>
                  </div>
                  <section>
                    <div className={`${actionRowClass} justify-between`}>
                      <h3 className="h-[var(--meta-row-px)] text-[length:var(--meta-font-size)] leading-[var(--meta-row-px)] font-semibold tracking-wide text-[var(--sidebar-text-muted)] uppercase">タグ管理</h3>
                      <SurfaceButton
                        type="button"
                        surface="convex"
                        size="xs"
                        className="h-[var(--meta-row-px)] text-[length:var(--meta-font-size)] leading-[var(--meta-row-px)]"
                        onClick={openTagSettings}
                      >
                        設定で管理
                      </SurfaceButton>
                    </div>
                    <div className="mt-2 rounded-md border border-[var(--surface-border)] bg-white px-2 py-1 surface-concave">
                      <TagInput
                        tags={tags}
                        onChange={(nextTags) => {
                          if (!card) return;
                          onUpdateTags(nextTags);
                        }}
                        placeholder="タグを選択・追加"
                        quietHover
                        className={`bg-transparent ${!card ? "pointer-events-none opacity-60" : ""}`}
                      />
                    </div>
                  </section>
                </>
              )}
              {!isCalendarMode && (
                <div className="space-y-0">
                  <p className={infoRowClass}>作成日: {formatDateLabel(card?.createdAt ?? (card as any)?.created_at)}</p>
                  <p className={infoRowClass}>更新日: {formatDateLabel(card?.updatedAt ?? (card as any)?.updated_at)}</p>
                  <p className={infoRowClass}>最終復習日: {latestReview ? formatDateLabel(latestReview.reviewedAt) : formatDateLabel(card?.lastReviewAt ?? (card as any)?.last_review_at)}</p>
                  <p className={infoRowClass}>次回復習日 ({nextReviewAttempt}回目): {formatDateLabel(card?.nextReviewDate ?? (card as any)?.next_review_date)}</p>
                </div>
              )}
          </MetaPanelLeadSection>

          {!isCalendarMode && (
            <section>
              <div className="mt-3 space-y-2">
              </div>
              <RatingCountTiles counts={distribution20} compact disableHover singleRow surface="concave" className="mt-3" />
            </section>
          )}

          {!isCalendarMode && <section>
            {currentResistanceScore !== null && (
              <div className="mb-3 flex min-h-[var(--meta-action-min-h)] items-center justify-between rounded border border-[var(--sidebar-border)] bg-[var(--sidebar-active-bg)] px-2">
                <span className="text-[length:var(--meta-font-size)] font-medium leading-[var(--meta-row-px)] text-[var(--sidebar-text-muted)]">現在の耐性スコア</span>
                <span className="text-[length:var(--meta-font-size)] font-semibold leading-[var(--meta-row-px)] tabular-nums text-[var(--sidebar-text)]">{currentResistanceScore}%</span>
              </div>
            )}
            <div className="flex min-h-[var(--meta-action-min-h)] items-center justify-between">
              <h3 className="h-[var(--meta-row-px)] text-[length:var(--meta-font-size)] leading-[var(--meta-row-px)] font-semibold tracking-wide text-[var(--sidebar-text-muted)] uppercase">耐性スコア推移</h3>
              <div className="flex bg-white rounded border border-[var(--surface-border)] p-0.5 shadow-sm text-[length:var(--meta-font-size)]">
                {(["7d", "30d", "all"] as const).map((p) => (
                  <SurfaceButton
                    key={p}
                    surface={period === p ? "convexActive" : "concave"}
                    size="xs"
                    className="h-[var(--meta-row-px)] leading-[var(--meta-row-px)]"
                    onClick={() => setPeriod(p)}
                  >
                    {p === "all" ? "全期間" : p === "7d" ? "直近7" : "直近30"}
                  </SurfaceButton>
                ))}
              </div>
            </div>
            <div className="mt-3 h-40 w-full rounded border border-[var(--sidebar-border)] bg-[var(--sidebar-active-bg)] p-1.5">
              {chartData.length === 0 ? (
                <div className="flex h-full items-center justify-center text-sm text-[var(--sidebar-text-muted)]">データなし</div>
              ) : (
                <ResponsiveContainer width="100%" height="100%">
                  <LineChart data={chartData}>
                    <XAxis
                      dataKey="reviewIndex"
                      ticks={xTicks}
                      tick={{ fontSize: 10 }}
                      label={{ value: "復習回数", position: "insideBottomRight", offset: -4, fontSize: 10 }}
                    />
                    <YAxis
                      domain={[0, 100]}
                      tickCount={6}
                      allowDecimals={false}
                      width={36}
                      tick={{ fontSize: 10 }}
                    />
                    <Line type="monotone" dataKey="resistanceScore" stroke="#0f172a" strokeWidth={2} dot={false} />
                  </LineChart>
                </ResponsiveContainer>
              )}
            </div>
          </section>}
    </EmptyMetaPanel>
  );
}

import React, { Component, type ErrorInfo, type ReactNode } from 'react';
import { Button } from '../ui/button';
import { Card, CardContent, CardHeader, CardTitle } from '../ui/card';
import { AlertTriangle, RefreshCw, Trash2 } from '@/ui/icons';
import { getActiveTabCountEstimate } from '@/utils/tabPresence';

interface Props {
  children: ReactNode;
}

interface State {
  hasError: boolean;
  error: Error | null;
}

/**
 * 致命的なクラッシュをキャッチし、復旧UIを表示するコンポーネント
 */
export class ErrorBoundary extends Component<Props, State> {
  public state: State = {
    hasError: false,
    error: null,
  };

  public static getDerivedStateFromError(error: Error): State {
    return { hasError: true, error };
  }

  public componentDidCatch(error: Error, errorInfo: ErrorInfo) {
    console.error('[ErrorBoundary] Uncaught error:', error, errorInfo);
  }

  private handleReset = () => {
    window.location.reload();
  };

  private async getPendingSyncCount(): Promise<number | null> {
    try {
      const { getLocalDb } = await import('../../services/localDB');
      const db = await getLocalDb();
      const pending = await db.syncQueue.where('status').equals('pending').count();
      const processing = await db.syncQueue.where('status').equals('processing').count();
      return pending + processing;
    } catch (error) {
      console.warn('[ErrorBoundary] Failed to read pending sync count', error);
      return null;
    }
  }

  private getSyncWarningMessage(pendingSyncCount: number | null): string {
    if (pendingSyncCount === null) {
      return '未同期状況を確認できません。';
    }
    if (pendingSyncCount === 0) {
      return '未同期は検出されません。';
    }
    return `未同期の可能性: ${pendingSyncCount}件`;
  }

  private getTabHint(): string {
    const tabs = getActiveTabCountEstimate();
    if (tabs === null) {
      return '（同一サイトの他タブ状況: 不明）';
    }
    return `（同一サイトの推定タブ数: ${tabs}）`;
  }

  private deleteDatabaseByName(name: string): Promise<void> {
    return new Promise((resolve, reject) => {
      let settled = false;
      const request = window.indexedDB.deleteDatabase(name);
      const timeoutId = window.setTimeout(() => {
        if (settled) return;
        settled = true;
        reject(new Error(`Delete database timed out: ${name}`));
      }, 5000);

      const complete = (handler: () => void) => {
        if (settled) return;
        settled = true;
        window.clearTimeout(timeoutId);
        handler();
      };

      request.onsuccess = () => complete(resolve);
      request.onerror = () =>
        complete(() => reject(request.error ?? new Error(`Failed to delete database: ${name}`)));
      request.onblocked = () =>
        complete(() => reject(new Error(`Delete database blocked by another tab: ${name}`)));
    });
  }

  private async clearIndexedDbDatabases(): Promise<void> {
    if (!window.indexedDB.databases) return;
    const databases = await window.indexedDB.databases();
    const names = databases.map((db) => db.name).filter((name): name is string => Boolean(name));
    await Promise.all(names.map((name) => this.deleteDatabaseByName(name)));
  }

  private async closeLocalDbBestEffort(): Promise<void> {
    try {
      const { getLocalDb } = await import('../../services/localDB');
      const db = await getLocalDb();
      (db as any)?.close?.();
    } catch {
      // ignore: recovery flow should proceed even if local DB cannot be obtained
    }
  }

  private handleClearCache = async () => {
    const pendingSyncCount = await this.getPendingSyncCount();
    const syncWarning = this.getSyncWarningMessage(pendingSyncCount);
    const tabHint = this.getTabHint();

    const firstConfirmation = confirm(
      `キャッシュ復旧の最終手段を実行します。\n${syncWarning}\n\n` +
      `実行前に、このアプリの他タブを閉じてください。${tabHint}\n\n` +
      '実行内容:\n' +
      '- Cache API 全削除\n' +
      '- Service Worker 登録解除\n' +
      '- IndexedDB 削除\n' +
      '- Local/Session Storage クリア\n\n' +
      '続行しますか？'
    );
    if (!firstConfirmation) return;

    const secondConfirmation = confirm(
      `本当に実行しますか？\n` +
      `この操作は取り消せません。\n${syncWarning}\n${tabHint}`
    );
    if (!secondConfirmation) return;

    try {
      if ('caches' in window) {
        const cacheKeys = await caches.keys();
        await Promise.all(cacheKeys.map((key) => caches.delete(key)));
      }

      if ('serviceWorker' in navigator) {
        const registrations = await navigator.serviceWorker.getRegistrations();
        await Promise.all(registrations.map((registration) => registration.unregister()));
      }

      await this.closeLocalDbBestEffort();
      await this.clearIndexedDbDatabases();

      localStorage.clear();
      sessionStorage.clear();
      window.location.reload();
    } catch (error) {
      console.error('[ErrorBoundary] Cache recovery failed', error);
      const isBlocked = String((error as Error)?.message ?? '').includes('blocked');
      const message = isBlocked
        ? `復旧操作が他タブにブロックされました。${tabHint}\n他タブを閉じて再実行してください。`
        : `復旧操作の一部に失敗しました。${tabHint}\nアプリの他タブを閉じてから再実行してください。`;
      alert(message);
    }
  };

  public render() {
    if (this.state.hasError) {
      return (
        <div className="min-h-screen flex items-center justify-center bg-slate-50 p-4">
          {/* @ts-ignore */}
          <Card className="max-w-md w-full rounded-[32px] border-none shadow-xl overflow-hidden">
            {/* @ts-ignore */}
            <CardHeader className="bg-red-50 pb-6 pt-8">
              <div className="w-16 h-16 bg-red-100 rounded-full flex items-center justify-center mx-auto mb-4">
                <AlertTriangle className="w-8 h-8 text-red-500" />
              </div>
              {/* @ts-ignore */}
              <CardTitle className="text-center text-red-800">問題が発生しました</CardTitle>
            </CardHeader>
            {/* @ts-ignore */}
            <CardContent className="p-8 pt-6">
              <p className="text-sm text-slate-600 text-center mb-6 leading-relaxed">
                アプリケーションの実行中に予期せぬエラーが発生しました。
                データの不整合またはメモリ不足の可能性があります。
              </p>
              
              <div className="bg-slate-50 p-4 rounded-2xl mb-8 overflow-auto max-h-32">
                <pre className="text-[10px] text-slate-500 font-serif">
                  {this.state.error?.message || 'Unknown error'}
                  {this.state.error?.stack && `\n\n${this.state.error.stack}`}
                </pre>
              </div>

              <div className="space-y-3">
                <Button 
                  onClick={this.handleReset}
                  className="w-full bg-primary-600 hover:bg-primary-700 text-white rounded-xl h-12 font-bold shadow-md transition-all active:scale-[0.98]"
                >
                  <RefreshCw className="w-4 h-4 mr-2" />
                  アプリを再読み込み
                </Button>
                
                <Button 
                  variant="outline"
                  onClick={this.handleClearCache}
                  className="w-full border-slate-200 text-slate-500 hover:bg-red-50 hover:text-red-600 hover:border-red-200 rounded-xl h-12 font-bold transition-all"
                >
                  <Trash2 className="w-4 h-4 mr-2" />
                  キャッシュをクリアして修復
                </Button>
              </div>
              
              <p className="text-[10px] text-slate-400 text-center mt-6">
                何度もこの画面が表示される場合は、サポートにお問い合わせください。
              </p>
            </CardContent>
          </Card>
        </div>
      );
    }

    return (this as any).props.children;
  }
}

import React, { useEffect } from 'react';
import { useUserSettings } from '@/hooks/useUserSettings';

// Helper to convert hex to RGB object
const hexToRgb = (hex: string) => {
  const result = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(hex);
  return result
    ? {
        r: parseInt(result[1], 16),
        g: parseInt(result[2], 16),
        b: parseInt(result[3], 16)
      }
    : { r: 104, g: 154, b: 152 }; // Default primary color RGB
};

// Helper to mix colors in JS (Color mix fallback)
const mixColor = (color1: {r:number, g:number, b:number}, color2: {r:number, g:number, b:number}, weight: number) => {
    const w1 = weight;
    const w2 = 1 - weight;
    const r = Math.round(color1.r * w1 + color2.r * w2);
    const g = Math.round(color1.g * w1 + color2.g * w2);
    const b = Math.round(color1.b * w1 + color2.b * w2);
    return `#${r.toString(16).padStart(2,'0')}${g.toString(16).padStart(2,'0')}${b.toString(16).padStart(2,'0')}`;
};

const generatePalette = (baseHex: string) => {
    const base = hexToRgb(baseHex);
    const white = { r: 255, g: 255, b: 255 };
    const black = { r: 0, g: 0, b: 0 };

    return {
        50: mixColor(white, base, 0.95),
        100: mixColor(white, base, 0.90),
        200: mixColor(white, base, 0.70),
        300: mixColor(white, base, 0.50),
        400: mixColor(white, base, 0.30),
        500: mixColor(white, base, 0.10),
        600: baseHex, // Base
        700: mixColor(black, base, 0.10),
        800: mixColor(black, base, 0.20),
        900: mixColor(black, base, 0.30),
    };
};

export function ThemeManager() {
  const { settings } = useUserSettings();
  const accentColor = settings?.accentColor || '#689A98'; // Default fallback

  useEffect(() => {
    const root = document.documentElement;
    const rgb = hexToRgb(accentColor);
    
    // Set Base RGB for Tailwind opacity (e.g. bg-primary-600/50)
    // The format must be "r g b" (space separated)
    root.style.setProperty('--color-primary-600', `${rgb.r} ${rgb.g} ${rgb.b}`);
    // Set Base Hex for non-Tailwind usage (e.g. Scrollbar)
    root.style.setProperty('--color-primary-600-hex', accentColor);
    
    const palette = generatePalette(accentColor);

    // Set other shades as Hex strings
    root.style.setProperty('--color-primary-50', palette[50]);
    root.style.setProperty('--color-primary-100', palette[100]);
    root.style.setProperty('--color-primary-200', palette[200]);
    root.style.setProperty('--color-primary-300', palette[300]);
    root.style.setProperty('--color-primary-400', palette[400]);
    root.style.setProperty('--color-primary-500', palette[500]);
    // 600 is special (handled above)
    root.style.setProperty('--color-primary-700', palette[700]);
    root.style.setProperty('--color-primary-800', palette[800]);
    root.style.setProperty('--color-primary-900', palette[900]);

    // Update Meta Theme Color (for Safari/Mobile address bar)
    // We use the 50 shade for light background feel or white
    let metaThemeColor = document.querySelector("meta[name='theme-color']");
    if (!metaThemeColor) {
        metaThemeColor = document.createElement('meta');
        metaThemeColor.setAttribute('name', 'theme-color');
        document.head.appendChild(metaThemeColor);
    }
    // Set to white or primary-50 depending on design preference. 
    // User asked for "accent color at top" -> likely means the header color or status bar.
    // If header is white, this should be white. If header uses primary, this should use primary.
    // Our Layout header is bg-white. But let's check if user meant the Safe Area.
    // Usually matching the header background is safe.
    // However, if the user complained "accent color doesn't change", maybe they want the browser UI to match?
    // Let's set it to the accent color (or a dark shade) if they want it branded.
    // But typical modern apps use white/background color.
    // WAIT: User said "safariで表示した時画面上部のアクセントカラーが変更されない".
    // This implies they expect it TO CHANGE.
    // Let's set it to the accent color (base) or a lighter variant?
    // Actually, widespread practice is `theme-color` matches the header.
    // If the header is white, setting `theme-color` to accent might look odd unles header is also accent.
    // But maybe they refer to the "Status Bar" component I have?
    // Let's try setting it to `primary-50` (very light tint) to show *some* change, or the accent color itself if appropriate.
    // Let's default to the base accent color since they specifically asked about "accent color changing".
    // Actually, setting it to #ffffff is standard.
    // Let's look at StatusBar.tsx later.
    // For now, I will set meta theme-color to the `accentColor` itself (or maybe slightly darkened?)
    // to be very obvious that it has changed.
    metaThemeColor.setAttribute('content', accentColor); 
    
    // Save to localStorage for index.html head script to prevent green flash on reload
    localStorage.setItem('flashcard-accent-color', accentColor);
  }, [accentColor]);

  return null;
}

