import React, { useState, useMemo, useRef, useEffect } from 'react';
import { Filter, Search, Tag } from '@/ui/icons';
import { useExplorerStore } from '@/hooks/useExplorerStore';
import { useTags } from '@/hooks/useTags';
import { cn } from '@/lib/utils';
import { Popover, PopoverContent, PopoverTrigger } from '@/components/ui/popover';
import { TagBadge } from '@/components/tag/TagBadge';
import { Switch } from '@/components/ui/switch';
import { SurfaceButton } from '@/components/ui/surface-button';

interface TagFilterPopoverProps {
  allTags: string[]; // 全タグ一覧（呼び出し元から渡す）
  className?: string;
}

export function TagFilterPopover({ allTags, className }: TagFilterPopoverProps) {
  const { getTagColor } = useTags();
  const {
    tagFilter,
    tagMatchMode,
    uncertaintyFilter,
    bookmarkedFilter,
    draftFilter,
    contentTypeFilter,
    toggleTag,
    clearAllFilters,
    setTagMatchMode,
    setUncertaintyFilter,
    setBookmarkedFilter,
    setDraftFilter,
    toggleContentType,
  } = useExplorerStore();

  const [searchQuery, setSearchQuery] = useState('');
  const [isOpen, setIsOpen] = useState(false);
  const inputRef = useRef<HTMLInputElement>(null);

  // ダイアログ開いた時に検索ボックスフォーカス
  useEffect(() => {
    if (isOpen) {
      setTimeout(() => {
        inputRef.current?.focus();
      }, 100);
    } else {
      setSearchQuery(''); // 閉じたら検索クリア
    }
  }, [isOpen]);

  // タグ検索フィルタリング
  const filteredTags = useMemo(() => {
    if (!searchQuery.trim()) return allTags;
    return allTags.filter(tag =>
      tag.toLowerCase().includes(searchQuery.toLowerCase())
    );
  }, [allTags, searchQuery]);

  // フィルタ有効状態
  const isFilterActive =
    tagFilter.length > 0 ||
    uncertaintyFilter !== 'any' ||
    bookmarkedFilter !== 'any' ||
    draftFilter !== 'any' ||
    contentTypeFilter.length < 3;

  return (
    <Popover open={isOpen} onOpenChange={setIsOpen}>
      <PopoverTrigger asChild>
        <button
          className={cn(
            "flex items-center justify-center px-2 py-1 text-xs font-medium transition-colors relative whitespace-nowrap",
            "hover:text-primary-700",
            isFilterActive ? "text-primary-700" : "text-slate-500",
            className
          )}
        >
          <Filter className="w-4 h-4" />
          {isFilterActive && (
            <div className="absolute bottom-0 left-1 right-1 h-0.5 bg-primary-500 rounded-full" />
          )}
        </button>
      </PopoverTrigger>

      {/* 透け対策：bg-white/95 + blur + shadow + ring */}
      <PopoverContent
        align="center"
        className={cn(
          "w-64 p-0 rounded-xl surface-dialog-convex",
          "overflow-hidden"
        )}
      >
        <div className="flex flex-col max-h-[400px]">
          {/* Header & Search */}
          <div className="p-3 border-b border-[var(--surface-border)]">
            <div className="flex items-center justify-between mb-2">
              <span className="text-xs font-semibold text-slate-800">タグで絞り込み</span>
              {isFilterActive && (
                <SurfaceButton
                  onClick={clearAllFilters}
                  surface="convex"
                  size="xs"
                  className="rounded-md hover:text-[#5f5557]"
                >
                  すべてクリア
                </SurfaceButton>
              )}
            </div>

            <div className="relative">
              <Search className="absolute left-2 top-1/2 -translate-y-1/2 w-3.5 h-3.5 text-slate-400" />
              <input
                ref={inputRef}
                type="text"
                className={cn(
                  "w-full pl-8 pr-2 py-1.5 text-xs rounded",
                  "border border-[var(--surface-border)] bg-white text-[#202123]",
                  "surface-concave",
                  "focus:bg-white focus:outline-none focus:ring-0 focus:border-[#cfcfcf]",
                  "placeholder:text-[var(--surface-placeholder-text)]",
                  "transition-colors"
                )}
                placeholder="タグを検索..."
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
              />
            </div>
          </div>

          {/* AND,ORトグル */}
          <div className="px-3 py-2 border-b border-[var(--surface-border)] flex items-center gap-2 text-[11px] bg-white/70">
            <span className="text-slate-500">条件:</span>
            <div className="flex bg-white rounded border border-[var(--surface-border)] p-0.5 shadow-sm">
              <SurfaceButton
                onClick={() => setTagMatchMode('any')}
                surface={tagMatchMode === 'any' ? 'convexActive' : 'concave'}
                size="xs"
              >
                いずれか (OR)
              </SurfaceButton>
              <SurfaceButton
                onClick={() => setTagMatchMode('all')}
                surface={tagMatchMode === 'all' ? 'convexActive' : 'concave'}
                size="xs"
              >
                すべて (AND)
              </SurfaceButton>
            </div>
          </div>

          <div className="px-3 py-2 border-b border-[var(--surface-border)] bg-white/70 space-y-2">
            <div className="flex items-center justify-between gap-2 text-[11px]">
              <span className="text-slate-600">表示:</span>
              <div className="flex bg-white rounded border border-[var(--surface-border)] p-0.5 shadow-sm">
                {[
                  { label: 'カード', value: 'card' as const },
                  { label: 'PDF', value: 'pdf' as const },
                  { label: 'PPTX', value: 'pptx' as const },
                ].map((item) => (
                  <SurfaceButton
                    key={item.value}
                    onClick={() => toggleContentType(item.value)}
                    surface={contentTypeFilter.includes(item.value) ? 'convexActive' : 'concave'}
                    size="xs"
                  >
                    {item.label}
                  </SurfaceButton>
                ))}
              </div>
            </div>
            {[
              {
                label: 'はてな',
                value: uncertaintyFilter,
                onChange: setUncertaintyFilter,
              },
              {
                label: 'お気に入り',
                value: bookmarkedFilter,
                onChange: setBookmarkedFilter,
              },
              {
                label: '下書き',
                value: draftFilter,
                onChange: setDraftFilter,
              },
            ].map((item) => (
              <div key={item.label} className="flex items-center justify-between gap-2 text-[11px]">
                <span className="text-slate-600">{item.label}:</span>
                <div className="flex bg-white rounded border border-[var(--surface-border)] p-0.5 shadow-sm">
                  <SurfaceButton
                    onClick={() => item.onChange('any')}
                    surface={item.value === 'any' ? 'convexActive' : 'concave'}
                    size="xs"
                  >
                    指定なし
                  </SurfaceButton>
                  <SurfaceButton
                    onClick={() => item.onChange('on')}
                    surface={item.value === 'on' ? 'convexActive' : 'concave'}
                    size="xs"
                  >
                    あり
                  </SurfaceButton>
                  <SurfaceButton
                    onClick={() => item.onChange('off')}
                    surface={item.value === 'off' ? 'convexActive' : 'concave'}
                    size="xs"
                  >
                    なし
                  </SurfaceButton>
                </div>
              </div>
            ))}
          </div>

          {/* タグリスト */}
          <div className="flex-1 overflow-y-auto min-h-[150px] p-1 bg-white/60">
            {filteredTags.length === 0 ? (
              <div className="flex flex-col items-center justify-center py-8 text-slate-500 text-xs">
                <Tag className="w-8 h-8 opacity-20 mb-2" />
                <p>タグが見つかりません</p>
              </div>
            ) : (
              <div className="space-y-0.5">
                {filteredTags.map(tag => {
                  const isSelected = tagFilter.includes(tag);
                  return (
                    <div
                      key={tag}
                      onClick={() => toggleTag(tag)}
                      className={cn(
                        "w-full flex items-center px-2 py-1 text-xs rounded transition-colors text-left group",
                        isSelected
                          ? "bg-slate-100 text-slate-800"
                          : "hover:bg-slate-100 text-slate-800"
                      )}
                    >
                      <Switch
                        checked={isSelected}
                        onCheckedChange={() => toggleTag(tag)}
                        onClick={(e) => e.stopPropagation()}
                        className="mr-2"
                        aria-label={`${tag} を${isSelected ? '除外' : '追加'}`}
                      />
                      <div className="min-w-0 flex-1">
                        <TagBadge
                          label={tag}
                          size="xs"
                          colorClass={getTagColor(tag)}
                          className="max-w-full"
                        />
                      </div>
                    </div>
                  );
                })}
              </div>
            )}
          </div>
        </div>
      </PopoverContent>
    </Popover>
  );
}

import React, { useEffect, useState } from 'react';
import { useAuth } from '@/contexts/AuthContext';
import { useLiveQuery } from 'dexie-react-hooks';
import {
  getLocalDb,
  getLocalDBRuntimeStatus,
  subscribeLocalDBRuntimeStatus,
} from '@/services/localDB';
import { snapshotService } from '@/services/SnapshotService';
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogDescription,
  DialogFooter,
} from '@/components/ui/dialog';
import { Button } from '@/components/ui/button';
import { RadioGroup, RadioGroupItem } from '@/components/ui/radio-group';
import { Label } from '@/components/ui/label';
import { AlertTriangle, Folder, Loader2, CheckCircle } from '@/ui/icons';
import { Download } from '@/ui/icons';
import { Database } from '@/ui/icons';

interface ExportDialogProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
}

export default function ExportDialog({ open, onOpenChange }: ExportDialogProps) {
  const { currentUser } = useAuth();
  const [exportType, setExportType] = useState<'all' | 'folder'>('all');
  const [selectedFolderId, setSelectedFolderId] = useState<string | null>(null);
  const [isExporting, setIsExporting] = useState(false);
  const [exportComplete, setExportComplete] = useState(false);
  const [runtimeStatus, setRuntimeStatus] = useState(getLocalDBRuntimeStatus());

  useEffect(() => {
    return subscribeLocalDBRuntimeStatus(setRuntimeStatus);
  }, []);

  const isFallbackMode = runtimeStatus.mode === 'fallback';

  // フォルダ一覧を取得
  const folders = useLiveQuery(
    async () => {
      if (!currentUser) return [];
      const db = await getLocalDb();
      const allFolders = await db.getAllFolders();
      return allFolders.filter(f => !f.isDeleted);
    },
    [currentUser],
    []
  );

  const handleExport = async () => {
    if (!currentUser || isFallbackMode) return;
    
    setIsExporting(true);
    setExportComplete(false);
    
    try {
      if (exportType === 'all') {
        await snapshotService.exportToFile(currentUser.uid);
      } else if (selectedFolderId) {
        await snapshotService.exportFolder(currentUser.uid, selectedFolderId);
      }
      setExportComplete(true);
      
      // 3秒後にダイアログを閉じる
      setTimeout(() => {
        onOpenChange(false);
        setExportComplete(false);
      }, 2000);
    } catch (error) {
      console.error('Export failed:', error);
      alert('エクスポートに失敗しました');
    } finally {
      setIsExporting(false);
    }
  };

  const selectedFolder = folders?.find(f => f.id === selectedFolderId);

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="sm:max-w-md">
        <DialogHeader>
          <DialogTitle className="flex items-center gap-2">
            <Download className="w-5 h-5 text-primary-600" />
            データエクスポート
          </DialogTitle>
          <DialogDescription>
            カードとフォルダのデータをJSONファイルとしてエクスポートします。
            このファイルはバックアップとして保存したり、別のデバイスにインポートできます。
          </DialogDescription>
        </DialogHeader>

        {exportComplete ? (
          <div className="py-8 text-center">
            <CheckCircle className="w-16 h-16 mx-auto mb-4 text-green-500" />
            <p className="text-lg font-medium text-gray-900">エクスポート完了！</p>
            <p className="text-sm text-gray-500 mt-1">ファイルがダウンロードされました</p>
          </div>
        ) : (
          <>
            <div className="py-4">
              {isFallbackMode && (
                <div className="mb-4 rounded-lg border border-amber-300 bg-amber-50 px-3 py-2 text-sm text-amber-900">
                  <div className="flex items-center gap-2 font-semibold">
                    <AlertTriangle className="h-4 w-4" />
                    ローカル保存が無効なため、このセッションではエクスポートできません
                  </div>
                </div>
              )}

              <RadioGroup
                value={exportType}
                onValueChange={(value) => setExportType(value as 'all' | 'folder')}
                className="space-y-3"
                disabled={isFallbackMode}
              >
                <div className="flex items-center space-x-3 p-3 rounded-lg border hover:bg-gray-50 cursor-pointer">
                  <RadioGroupItem value="all" id="all" />
                  <Label htmlFor="all" className="flex items-center gap-2 cursor-pointer flex-1">
                    <Database className="w-5 h-5 text-gray-500" />
                    <div>
                      <div className="font-medium">すべてのデータ</div>
                      <div className="text-sm text-gray-500">
                        全フォルダ・全カードをエクスポート
                      </div>
                    </div>
                  </Label>
                </div>

                <div className="flex items-center space-x-3 p-3 rounded-lg border hover:bg-gray-50 cursor-pointer">
                  <RadioGroupItem value="folder" id="folder" />
                  <Label htmlFor="folder" className="flex items-center gap-2 cursor-pointer flex-1">
                    <Folder className="w-5 h-5 text-gray-500" />
                    <div>
                      <div className="font-medium">フォルダを選択</div>
                      <div className="text-sm text-gray-500">
                        特定のフォルダのみエクスポート
                      </div>
                    </div>
                  </Label>
                </div>
              </RadioGroup>

              {exportType === 'folder' && (
                <div className="mt-4 pl-8">
                  <Label className="text-sm text-gray-600 mb-2 block">
                    エクスポートするフォルダを選択:
                  </Label>
                  <select
                    value={selectedFolderId || ''}
                    onChange={(e) => setSelectedFolderId(e.target.value || null)}
                    className="w-full p-2 border rounded-lg text-sm"
                    disabled={isFallbackMode}
                  >
                    <option value="">選択してください</option>
                    {folders?.map((folder) => (
                      <option key={folder.id} value={folder.id}>
                        {folder.folderName || folder.folder_name}
                      </option>
                    ))}
                  </select>
                </div>
              )}
            </div>

            <div className="bg-amber-50 border border-amber-200 rounded-lg p-3 text-sm">
              <p className="text-amber-800">
                💡 <strong>ヒント:</strong> 定期的にエクスポートしてバックアップを取ることをお勧めします。
                エクスポートしたファイルは安全な場所に保存してください。
              </p>
            </div>
          </>
        )}

        <DialogFooter>
          <Button variant="outline" onClick={() => onOpenChange(false)}>
            キャンセル
          </Button>
          {!exportComplete && (
            <Button
              onClick={handleExport}
              disabled={isFallbackMode || isExporting || (exportType === 'folder' && !selectedFolderId)}
              className="bg-primary-600 hover:bg-primary-700"
            >
              {isExporting ? (
                <>
                  <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                  エクスポート中...
                </>
              ) : (
                <>
                  <Download className="w-4 h-4 mr-2" />
                  エクスポート
                </>
              )}
            </Button>
          )}
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}

import React, { useEffect, useState, useRef } from 'react';
import { useAuth } from '@/contexts/AuthContext';
import { useLiveQuery } from 'dexie-react-hooks';
import {
  getLocalDb,
  getLocalDBRuntimeStatus,
  subscribeLocalDBRuntimeStatus,
} from '@/services/localDB';
import { snapshotService } from '@/services/SnapshotService';
import type { AppSnapshot, SnapshotComparison } from '@/types/snapshot';
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogDescription,
  DialogFooter,
} from '@/components/ui/dialog';
import { Button } from '@/components/ui/button';
import { RadioGroup, RadioGroupItem } from '@/components/ui/radio-group';
import { Label } from '@/components/ui/label';
import { CheckCircle, Loader2, ArrowRight, AlertTriangle } from '@/ui/icons';
import { Upload } from '@/ui/icons';
import { FileJson } from '@/ui/icons';

interface ImportDialogProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
}

type ImportStep = 'select' | 'preview' | 'confirm' | 'processing' | 'complete';
type ImportAction = 'replace' | 'keep' | 'cancel';

export default function ImportDialog({ open, onOpenChange }: ImportDialogProps) {
  const { currentUser } = useAuth();
  const fileInputRef = useRef<HTMLInputElement>(null);
  
  const [step, setStep] = useState<ImportStep>('select');
  const [selectedFile, setSelectedFile] = useState<File | null>(null);
  const [parsedSnapshot, setParsedSnapshot] = useState<AppSnapshot | null>(null);
  const [comparison, setComparison] = useState<SnapshotComparison | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [importAction, setImportAction] = useState<ImportAction>('keep');
  const [runtimeStatus, setRuntimeStatus] = useState(getLocalDBRuntimeStatus());

  useEffect(() => {
    return subscribeLocalDBRuntimeStatus(setRuntimeStatus);
  }, []);

  const isFallbackMode = runtimeStatus.mode === 'fallback';

  const resetState = () => {
    setStep('select');
    setSelectedFile(null);
    setParsedSnapshot(null);
    setComparison(null);
    setError(null);
    setImportAction('keep');
  };

  const handleFileSelect = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (isFallbackMode) return;
    const file = e.target.files?.[0];
    if (!file) return;

    setSelectedFile(file);
    setError(null);

    try {
      const snapshot = await snapshotService.parseSnapshotFile(file);
      setParsedSnapshot(snapshot);

      if (currentUser) {
        const comp = await snapshotService.compareWithLocal(snapshot, currentUser.uid);
        setComparison(comp);
      }

      setStep('preview');
    } catch (err: unknown) {
      setError(err.message || 'ファイルの読み込みに失敗しました');
    }
  };

  const handleImport = async () => {
    if (isFallbackMode || !parsedSnapshot || !currentUser || importAction === 'cancel') {
      onOpenChange(false);
      resetState();
      return;
    }

    if (importAction === 'keep') {
      onOpenChange(false);
      resetState();
      return;
    }

    // replace: インポートしたデータで上書き
      setStep('processing');

    try {
      // 全データをクリアして新しいデータをインポート
      // 注意: これは危険な操作なので、事前にバックアップを推奨
      const db = await getLocalDb();

      // カードをインポート
      for (const card of parsedSnapshot.data.cards) {
        await db.table('cards').put(card);
      }

      // フォルダをインポート
      for (const folder of parsedSnapshot.data.folders) {
        await db.table('folders').put(folder);
      }

      setStep('complete');
      
      setTimeout(() => {
        onOpenChange(false);
        resetState();
        window.location.reload(); // データを反映するためにリロード
      }, 2000);
    } catch (err: unknown) {
      setError(err.message || 'インポートに失敗しました');
      setStep('preview');
    }
  };

  return (
    <Dialog open={open} onOpenChange={(o) => {
      if (!o) resetState();
      onOpenChange(o);
    }}>
      <DialogContent className="sm:max-w-lg">
        <DialogHeader>
          <DialogTitle className="flex items-center gap-2">
            <Upload className="w-5 h-5 text-primary-600" />
            データインポート
          </DialogTitle>
          <DialogDescription>
            以前エクスポートしたJSONファイルからデータを復元します。
          </DialogDescription>
        </DialogHeader>

        {/* Step: Select File */}
        {step === 'select' && (
          <div className="py-6">
            {isFallbackMode && (
              <div className="mb-4 rounded-lg border border-amber-300 bg-amber-50 px-3 py-2 text-sm text-amber-900">
                <AlertTriangle className="mr-1 inline h-4 w-4" />
                ローカル保存が無効なため、このセッションではインポートできません。
              </div>
            )}
            <input
              type="file"
              accept=".json"
              onChange={handleFileSelect}
              ref={fileInputRef}
              className="hidden"
              disabled={isFallbackMode}
            />
            
            <div 
              onClick={() => {
                if (!isFallbackMode) fileInputRef.current?.click();
              }}
              className={`border-2 border-dashed rounded-xl p-8 text-center transition-all ${
                isFallbackMode
                  ? 'cursor-not-allowed border-gray-200 bg-gray-50 opacity-70'
                  : 'cursor-pointer border-gray-300 hover:border-primary-600 hover:bg-gray-50'
              }`}
            >
              <FileJson className="w-12 h-12 mx-auto mb-3 text-gray-400" />
              <p className="text-sm font-medium text-gray-700">
                クリックしてJSONファイルを選択
              </p>
              <p className="text-xs text-gray-500 mt-1">
                または、ファイルをドラッグ＆ドロップ
              </p>
            </div>

            {error && (
              <div className="mt-4 p-3 bg-red-50 border border-red-200 rounded-lg text-sm text-red-700">
                <AlertTriangle className="w-4 h-4 inline mr-1" />
                {error}
              </div>
            )}
          </div>
        )}

        {/* Step: Preview */}
        {step === 'preview' && parsedSnapshot && comparison && (
          <div className="py-4 space-y-4">
            {/* ファイル情報 */}
            <div className="bg-gray-50 rounded-lg p-3">
              <p className="text-xs text-gray-500 mb-1">選択したファイル</p>
              <p className="text-sm font-medium">{selectedFile?.name}</p>
            </div>

            {/* 比較結果 */}
            <div className="space-y-3">
              <div className="flex items-center justify-between p-3 bg-blue-50 rounded-lg">
                <div>
                  <p className="text-xs text-blue-600 font-medium">インポートファイル</p>
                  <p className="text-sm">
                    カード: {parsedSnapshot.data.cards.length}枚 / 
                    フォルダ: {parsedSnapshot.data.folders.length}件
                  </p>
                  <p className="text-xs text-gray-500">
                    世代: {comparison.importedGeneration}
                  </p>
                </div>
                <ArrowRight className="w-5 h-5 text-gray-400" />
                <div className="text-right">
                  <p className="text-xs text-green-600 font-medium">現在のデータ</p>
                  <p className="text-sm">世代: {comparison.localGeneration}</p>
                </div>
              </div>

              {comparison.newerSnapshot === 'imported' && (
                <div className="p-3 bg-amber-50 border border-amber-200 rounded-lg text-sm text-amber-800">
                  <AlertTriangle className="w-4 h-4 inline mr-1" />
                  インポートファイルの方が新しいデータです
                </div>
              )}

              {comparison.newerSnapshot === 'local' && (
                <div className="p-3 bg-green-50 border border-green-200 rounded-lg text-sm text-green-800">
                  <CheckCircle className="w-4 h-4 inline mr-1" />
                  現在のデータの方が新しいです
                </div>
              )}
            </div>

            {/* アクション選択 */}
            <div className="space-y-2">
              <p className="text-sm font-medium text-gray-700">どうしますか？</p>
              <RadioGroup value={importAction} onValueChange={(v) => setImportAction(v as ImportAction)}>
                <div className="flex items-center space-x-2 p-3 border rounded-lg hover:bg-gray-50">
                  <RadioGroupItem value="replace" id="replace" />
                  <Label htmlFor="replace" className="flex-1 cursor-pointer">
                    <span className="font-medium text-red-600">上書きする</span>
                    <p className="text-xs text-gray-500">現在のデータを破棄してインポート</p>
                  </Label>
                </div>
                <div className="flex items-center space-x-2 p-3 border rounded-lg hover:bg-gray-50">
                  <RadioGroupItem value="keep" id="keep" />
                  <Label htmlFor="keep" className="flex-1 cursor-pointer">
                    <span className="font-medium">現在のデータを保持</span>
                    <p className="text-xs text-gray-500">インポートをキャンセル</p>
                  </Label>
                </div>
              </RadioGroup>
            </div>

            {importAction === 'replace' && (
              <div className="p-3 bg-red-50 border border-red-200 rounded-lg text-sm text-red-700">
                <AlertTriangle className="w-4 h-4 inline mr-1" />
                <strong>警告:</strong> 現在のデータは上書きされます。事前にバックアップを取ることをお勧めします。
              </div>
            )}
          </div>
        )}

        {/* Step: Processing */}
        {step === 'processing' && (
          <div className="py-8 text-center">
            <Loader2 className="w-12 h-12 mx-auto mb-4 text-primary-600 animate-spin" />
            <p className="text-sm text-gray-600">インポート中...</p>
          </div>
        )}

        {/* Step: Complete */}
        {step === 'complete' && (
          <div className="py-8 text-center">
            <CheckCircle className="w-16 h-16 mx-auto mb-4 text-green-500" />
            <p className="text-lg font-medium text-gray-900">インポート完了！</p>
            <p className="text-sm text-gray-500 mt-1">ページをリロードしています...</p>
          </div>
        )}

        <DialogFooter>
          {step === 'select' && (
            <Button variant="outline" onClick={() => onOpenChange(false)}>
              キャンセル
            </Button>
          )}
          {step === 'preview' && (
            <>
              <Button variant="outline" onClick={() => { resetState(); }}>
                戻る
              </Button>
              <Button
                onClick={handleImport}
                disabled={isFallbackMode}
                className={importAction === 'replace' ? 'bg-red-600 hover:bg-red-700' : 'bg-primary-600 hover:bg-primary-700'}
              >
                {importAction === 'replace' ? '上書きインポート' : '閉じる'}
              </Button>
            </>
          )}
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}

import React, { useEffect, useRef, useState } from "react";
import { DragDropContext } from "@hello-pangea/dnd";
import { ChevronLeft, ChevronRight } from '@/ui/icons';

import {
  CardEditorLoadingState,
  EmptySelectionState,
  NewCardIdleState,
} from "@/components/card/editor/CardEditorPaneStates";
import { SharedCardContent } from "@/components/card/common/SharedCardContent";
import { CARD_ROW_PX, CANONICAL_CARD_WIDTH, layoutRowsToCardHeightPx } from "@/components/card/common/constants";
import { useCardEditorContentController } from "@/components/card/editor/useCardEditorContentController";
import { LinkEditor } from "@/components/card/editor/LinkEditor";
import { useCardEditorSession } from "@/components/card/editor/useCardEditorSession";
import { useLayoutRowsController } from "@/components/card/editor/useLayoutRowsController";
import { CardCornerActions } from "@/components/card/frame/CardCornerActions";
import { CardFrame } from "@/components/card/frame/CardFrame";
import { Flashcard } from "@/components/card/frame/Flashcard";
import MediaUploader from "@/components/card/media/MediaUploader";
import { CardMetaPanel } from "@/components/card/panels/CardMetaPanel";
import { DEFAULT_LAYOUT_ROWS, normalizeLayoutRows } from "@/domain/card/extraRows";
import { useToast } from "@/contexts/ToastContext";
import { useCards } from "@/hooks/useCards";
import { useTags } from "@/hooks/useTags";
import { useUserSettings } from "@/hooks/useUserSettings";
import { cn } from "@/lib/utils";
import { Button } from "@/components/ui/button";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import type { UploadedImage } from "@/types";

interface CardEditorPaneProps {
  selectedCardId: string | null;
  folderId?: string;
  autoEdit?: boolean;
  onCardUpdated?: () => void;
  onSelectCardId?: (cardId: string) => void;
}

export function CardEditorPane({ selectedCardId, folderId, autoEdit, onCardUpdated, onSelectCardId }: CardEditorPaneProps) {
  const { settings } = useUserSettings();
  const { success: toastSuccess, error: toastError } = useToast();
