import React, { useEffect, useMemo, useState } from 'react';
import { BookOpen, ChevronDown, ChevronRight, FolderTree } from '@/ui/icons';
import { cn } from '@/lib/utils';
import type { Card, SelectedExplorerItem } from '@/types';
import type { TreeNode } from './viewTypes';
import { ExplorerRow } from './explorer/rows/ExplorerRow';
import { ExplorerRowContent } from './explorer/rows/ExplorerRowContent';

interface VirtualTreeViewProps {
  nodes: TreeNode[];
  cards: Card[];
  selectedItem: SelectedExplorerItem;
  onItemSelect: (item: SelectedExplorerItem) => void;
}

const getCardTitle = (card: Card): string => {
  if (typeof card.title === 'string' && card.title.trim()) return card.title;
  if (typeof card.questionText === 'string' && card.questionText.trim()) {
    const plain = card.questionText.replace(/<[^>]*>/g, '').trim();
    if (plain) return plain.length > 50 ? `${plain.slice(0, 50)}...` : plain;
  }
  return '無題のカード';
};

export function VirtualTreeView({ nodes, cards, selectedItem, onItemSelect }: VirtualTreeViewProps) {
  const [expandedGroupIds, setExpandedGroupIds] = useState<Set<string>>(new Set());

  const cardById = useMemo(() => {
    const map = new Map<string, Card>();
    for (const card of cards) map.set(card.id, card);
    return map;
  }, [cards]);

  useEffect(() => {
    const ancestorIds = new Set<string>();

    const visit = (entries: TreeNode[], path: string[]) => {
      for (const entry of entries) {
        if (entry.type === 'card') {
          if (selectedItem?.type === 'card' && selectedItem.id === entry.cardId) {
            for (const ancestorId of path) ancestorIds.add(ancestorId);
          }
          continue;
        }
        visit(entry.children, [...path, entry.id]);
      }
    };

    visit(nodes, []);
    if (ancestorIds.size === 0) return;

    setExpandedGroupIds((prev) => new Set([...prev, ...ancestorIds]));
  }, [nodes, selectedItem]);

  const toggleGroup = (groupId: string) => {
    setExpandedGroupIds((prev) => {
      const next = new Set(prev);
      if (next.has(groupId)) next.delete(groupId);
      else next.add(groupId);
      return next;
    });
  };

  const renderNode = (node: TreeNode, depth: number): React.ReactNode => {
    if (node.type === 'card') {
      const card = cardById.get(node.cardId);
      if (!card) return null;
      const isSelected = selectedItem?.type === 'card' && selectedItem.id === node.cardId;
      return (
        <ExplorerRow
          key={node.id}
          depth={depth + 1}
          selected={isSelected}
          className={cn('pr-2 cursor-pointer')}
          onClick={() => onItemSelect({ type: 'card', id: node.cardId })}
        >
          <div className="flex h-full min-w-0 flex-1 items-center pr-1">
            <BookOpen className={cn('sidebar-icon mr-1 h-4 w-4 shrink-0 text-[#6E6E80]', isSelected && 'text-primary-700')} />
            <ExplorerRowContent
              title={getCardTitle(card)}
              titleClassName={cn(
                'lining-nums tabular-nums',
                isSelected ? 'font-medium text-primary-700' : 'text-[#202123]'
              )}
            />
          </div>
        </ExplorerRow>
      );
    }

    const isExpanded = expandedGroupIds.has(node.id);
    return (
      <div key={node.id}>
        <ExplorerRow
          depth={depth}
          className="pr-2 cursor-pointer"
          onClick={() => toggleGroup(node.id)}
        >
          <div className="flex h-full min-w-0 flex-1 items-center pr-1">
            <div className="mr-0 flex h-4 w-4 flex-shrink-0 items-center justify-center">
              {isExpanded ? (
                <ChevronDown className="sidebar-icon h-4 w-4 text-[#6E6E80]" />
              ) : (
                <ChevronRight className="sidebar-icon h-4 w-4 text-[#6E6E80]" />
              )}
            </div>
            <FolderTree className="sidebar-icon mr-0 h-4 w-4 flex-shrink-0 text-[#6E6E80]" />
            <ExplorerRowContent
              title={node.label}
              titleClassName="font-medium text-[#202123] lining-nums tabular-nums"
            />
          </div>
        </ExplorerRow>
        {isExpanded ? <div>{node.children.map((child) => renderNode(child, depth + 1))}</div> : null}
      </div>
    );
  };

  if (nodes.length === 0) {
    return (
      <div className="p-4">
        <div className="rounded-lg border border-dashed border-slate-200 bg-white/70 p-4 text-sm text-slate-500">
          表示できるタグがありません。
        </div>
      </div>
    );
  }

  return <div className="space-y-0.5 p-2">{nodes.map((node) => renderNode(node, 0))}</div>;
}

import React from 'react';
import { FileText, MoreVertical } from '@/ui/icons';
import { Draggable } from '@hello-pangea/dnd';
import { cn } from '@/lib/utils';
import { ContextMenu } from '../../ContextMenu';
import { lockToVerticalTransform } from '../dnd/lockToVertical';
import { DnDHelpers } from '@/hooks/useFolderDnD';
import type { Card, SelectedExplorerItem } from '@/types';
import { getExplorerRowStyle } from './shared';

interface CardRowProps {
  card: Card;
  depth: number;
  index: number;
  isSelected: boolean;
  isEditing: boolean;
  editingId: string | null;
  setEditingId: (id: string | null) => void;
  editingName: string;
  setEditingName: (name: string) => void;
  editingNameRef: React.MutableRefObject<string>;
  editInputRef: React.RefObject<HTMLInputElement>;
  onItemSelect: (item: SelectedExplorerItem) => void;
  handleMoveCard: (id: string) => void;
  handleDelete: (id: string, type: 'card') => Promise<void>;
  handleRenameConfirm: () => Promise<void>;
  renameCancelledRef: React.MutableRefObject<boolean>;
  isPinned: boolean;
  handleTogglePin: () => void;
  rowBaseClassName: string;
  setRowRef: (id: string, node: HTMLElement | null) => void;
  isDragging: boolean;
  hasUpdateOrDelete: boolean;
  isNewlyCreated?: boolean;
  menuOpen: boolean;
  onMenuOpenChange: (open: boolean) => void;
}

export const CardRow: React.FC<CardRowProps> = ({
  card,
  depth,
  index,
  isSelected,
  isEditing,
  setEditingId,
  editingName,
  setEditingName,
  editingNameRef,
  editInputRef,
  onItemSelect,
  handleMoveCard,
  handleDelete,
  handleRenameConfirm,
  renameCancelledRef,
  isPinned,
  handleTogglePin,
  rowBaseClassName,
  setRowRef,
  isDragging,
  hasUpdateOrDelete,
  isNewlyCreated,
  menuOpen,
  onMenuOpenChange,
}) => {
  const cardId = card.id;
  
  // タイトルがない場合は questionText の最初の部分を表示
  const getCardTitle = () => {
    if (card.title) return card.title;
    if (isNewlyCreated) return '新規カード';
    
    // questionText から最初の50文字を取得（HTMLタグを除去）
    const questionText = (card as any).questionText || (card as any).question_text || '';
    const textOnly = questionText.replace(/<[^>]*>/g, '').trim();
    if (textOnly.length > 0) {
      return textOnly.length > 50 ? textOnly.substring(0, 50) + '...' : textOnly;
    }
    
    return '無題のカード';
  };
  
  const cardTitle = getCardTitle();
  const isOptimisticCard = Boolean((card as any).__optimistic);
  const isDragDisabled = isOptimisticCard || isEditing;
  const hasContextMenu = !isOptimisticCard && hasUpdateOrDelete;
  return (
    <Draggable
      key={cardId}
      draggableId={DnDHelpers.createCardDraggableId(cardId)}
      index={index}
      isDragDisabled={isDragDisabled}
    >
      {(provided, snapshot) => {
        const lockedStyle = lockToVerticalTransform(provided.draggableProps.style);
        return (
          <div 
            ref={(node) => {
              provided.innerRef(node);
              setRowRef(cardId, node);
            }}
            {...provided.draggableProps}
            {...provided.dragHandleProps}
            className={cn(
              rowBaseClassName,
              "pr-9",
              snapshot.isDragging && "bg-white shadow-lg opacity-90 z-50 ring-1 ring-primary-200",
              snapshot.isDragging && "pointer-events-none"
            )}
            data-selected={isSelected ? 'true' : undefined}
            style={{
              ...lockedStyle,
              ...getExplorerRowStyle(depth),
              pointerEvents: snapshot.isDragging ? "none" : "auto", 
            }}
            onClick={() => {
              if (snapshot.isDragging) return;
              if (!isEditing) onItemSelect({ type: 'card', id: cardId });
            }}
          >
            <div
              className={cn(
                "flex-1 flex min-w-0 cursor-pointer",
                "items-center h-full"
              )}
            >
              <FileText
                className={cn(
                  "sidebar-icon w-4 h-4 flex-shrink-0 mr-1 text-[#6E6E80] group-hover:text-[#202123]",
                  isSelected && "text-primary-700"
                )}
              />

              {isEditing ? (
                <input
                  ref={editInputRef}
                  aria-label="カード名の編集"
                  className="text-sm bg-white border border-primary-300 rounded px-1 outline-none ring-1 ring-primary-100 h-6 w-full leading-5"
                  value={editingName}
                  onChange={(e) => {
                    setEditingName(e.target.value);
                    editingNameRef.current = e.target.value;
                  }}
                  onKeyDown={(e) => {
                    if (e.key === 'Enter') {
                      e.preventDefault();
                      e.currentTarget.blur();
                    }
                    if (e.key === 'Escape') {
                      e.preventDefault();
                      e.stopPropagation();
                      renameCancelledRef.current = true;
                      e.currentTarget.blur();
                    }
                  }}
                  onBlur={() => void handleRenameConfirm()}
                  onClick={(e) => e.stopPropagation()}
                />
              ) : (
                <div
                  className={cn(
                    "flex gap-1 flex-1 overflow-hidden pr-1",
                    "items-center"
                  )}
                >
                  <span
                    className={cn(
                      "sidebar-title text-sm lining-nums tabular-nums",
                      "truncate",
                      isSelected ? "text-primary-700 font-medium" : "text-[#202123]"
                    )}
                  >
                    {cardTitle}
                  </span>
                </div>
              )}
            </div>

            {hasContextMenu && !isEditing && (
              <div className="absolute right-1 top-0 h-full flex items-center pointer-events-none">
                <ContextMenu
                  open={menuOpen}
                  onOpenChange={onMenuOpenChange}
                  type="card"
                  onRename={() => {
                    setEditingId(cardId);
                    setEditingName(cardTitle);
                  }}
                  onMove={() => handleMoveCard(cardId)}
                  onDelete={() => handleDelete(cardId, 'card')}
                  isPinned={isPinned}
                  onTogglePin={handleTogglePin}
                >
                  <button
                    type="button"
                    aria-label="カードメニューを開く"
                    className={cn(
                      "sidebar-action h-6 w-6 p-0 grid place-items-center rounded-md hover:bg-slate-200 text-[#6E6E80] hover:text-[#202123] outline-none pointer-events-auto transition-all shrink-0",
                      "opacity-0 group-hover:opacity-100",
                      (isSelected || menuOpen) && "opacity-100"
                    )}
                    onClick={(e) => e.stopPropagation()}
                    onPointerDown={(e) => e.stopPropagation()}
                  >
                    <MoreVertical className="sidebar-icon h-4 w-4" />
                  </button>
                </ContextMenu>
              </div>
            )}
          </div>
        );
      }}
    </Draggable>
  );
};

import React from 'react';
import { FileText, MoreVertical } from '@/ui/icons';
import { cn } from '@/lib/utils';
import { DocumentRowMenu } from '../../DocumentRowMenu';
import type { Card, DocumentItem, FolderTreeNode } from '../model/utils';
