import React, { useEffect, useState, useRef } from 'react';
import { DragDropContext, Droppable, Draggable } from '@hello-pangea/dnd';
import type { DropResult } from '@hello-pangea/dnd';
import { Switch } from '@/components/ui/switch';
import { GripVertical } from '@/ui/icons';
import { Type } from '@/ui/icons';
import { Code } from '@/ui/icons';
import { ImageIcon } from '@/ui/icons';
import { Sigma } from '@/ui/icons';
import { cn } from '@/lib/utils';
import type { BlockConfig } from '@/types';
import { useUserSettings } from '@/hooks/useUserSettings';

// Icon mapping
const ICONS = {
  text: Type,
  code: Code,
  image: ImageIcon,
  math: Sigma
};

const sanitizeBlockSettings = (items: BlockConfig[]) =>
  items
    .filter((item) => item.type !== 'reference' && item.type !== 'audio')
    .sort((a, b) => a.orderIndex - b.orderIndex)
    .map((item, index) => ({ ...item, orderIndex: index }));

export const BlockOrdering = () => {
  const { settings, updateSettings } = useUserSettings();
  const [blocks, setBlocks] = useState<BlockConfig[]>([]);
  const [enabled, setEnabled] = useState(false);
  const isDraggingRef = useRef(false);

  // StrictMode workaround for @hello-pangea/dnd
  useEffect(() => {
    const animation = requestAnimationFrame(() => setEnabled(true));
    return () => {
      cancelAnimationFrame(animation);
      setEnabled(false);
    };
  }, []);

  useEffect(() => {
    // ドラッグ中または更新中は何もしない
    if (isDraggingRef.current) return;

    if (settings?.editorBlockSettings) {
      const sorted = sanitizeBlockSettings([...settings.editorBlockSettings]);
      
      // 文字列表現で比較し、実際に変更がある場合のみステートを更新する（チラツキ防止）
      setBlocks(prev => {
        if (JSON.stringify(prev) === JSON.stringify(sorted)) return prev;
        return sorted;
      });
    } else {
        const defaults: BlockConfig[] = [
            { id: 'text', type: 'text', label: 'テキスト', isVisible: true, orderIndex: 0 },
            { id: 'code', type: 'code', label: 'コード', isVisible: true, orderIndex: 1 },
            { id: 'image', type: 'image', label: '画像', isVisible: true, orderIndex: 2 },
            { id: 'math', type: 'math', label: '数式', isVisible: true, orderIndex: 3 },
            { id: 'markdown', type: 'markdown', label: 'Markdown', isVisible: true, orderIndex: 4 },
        ];
        setBlocks(sanitizeBlockSettings(defaults));
    }
  }, [settings?.editorBlockSettings]);

  const onDragStart = () => {
    isDraggingRef.current = true;
  };

  const handleDragEnd = async (result: DropResult) => {
    if (!result.destination) {
      isDraggingRef.current = false;
      return;
    }

    // 1. まずローカルステートを即座に入れ替える
    const items = Array.from(blocks);
    const [reorderedItem] = items.splice(result.source.index, 1);
    items.splice(result.destination.index, 0, reorderedItem);

    const updatedItems = items.map((item, index) => ({
      ...item,
      orderIndex: index
    }));

    setBlocks(updatedItems);

    // 2. DB（Dexie）を更新する。await することで同期完了を待つ。
    // この間 isDraggingRef.current は true のままなので useEffect による上書きが防がれる。
    await updateSettings({ editorBlockSettings: updatedItems });
    
    // 3. 少し遅延させてからフラグを下ろす（ReactのレンダリングサイクルとDB更新の反映タイミングのズレを吸収）
    setTimeout(() => {
      isDraggingRef.current = false;
    }, 100);
  };

  const handleToggleVisibility = (id: string, checked: boolean) => {
    const updatedItems = blocks.map(item => 
      item.id === id ? { ...item, isVisible: checked } : item
    );
    setBlocks(updatedItems);
    updateSettings({ editorBlockSettings: updatedItems });
  };

  if (!enabled) return null;

  return (
    <div className="space-y-4">
      <div className="flex items-center justify-between">
         <div className="font-bold text-slate-200 text-sm">ブロックエディタ設定</div>
      </div>
      <div className="text-xs text-slate-400 mb-2">
         エディタで使用するブロックの表示・非表示と並び順をカスタマイズできます。ドラッグして並び替えてください。
      </div>

      <DragDropContext onDragStart={onDragStart} onDragEnd={handleDragEnd}>
        <Droppable droppableId="block-ordering">
          {(provided) => (
            <div
              {...provided.droppableProps}
              ref={provided.innerRef}
              className="space-y-2"
            >
              {blocks.map((block, index) => {
                const Icon = ICONS[block.type as keyof typeof ICONS] || Type;
                
                return (
                  <Draggable key={block.id} draggableId={block.id} index={index}>
                    {(provided, snapshot) => (
                      <div
                        ref={provided.innerRef}
                        {...provided.draggableProps}
                        className={cn(
                          "flex items-center gap-3 p-3 bg-white/5 rounded-xl border border-white/10 text-slate-200",
                          // ドラッグ中は transition-all を無効化して挙動を安定させる
                          !snapshot.isDragging && "transition-all hover:bg-white/10",
                          snapshot.isDragging && "shadow-[0_0_15px_rgba(123,172,170,0.3)] scale-[1.02] z-50 border-primary-400 ring-2 ring-primary-500/20 bg-slate-800/90 backdrop-blur-md"
                        )}
                        style={{
                          ...provided.draggableProps.style,
                          // Force vertical movement only by resetting X translation to 0
                          transform: provided.draggableProps.style?.transform 
                            ? `translate(0px, ${provided.draggableProps.style.transform.split(',').pop()?.split(')')[0].trim() || '0px'})`
                            : undefined,
                          '--drag-z-index': snapshot.isDragging ? 9999 : 1,
                          zIndex: 'var(--drag-z-index)'
                        } as any}
                      >
                        <div
                          {...provided.dragHandleProps}
                          className="text-slate-400 hover:text-slate-200 cursor-grab active:cursor-grabbing p-1"
                        >
                          <GripVertical className="w-4 h-4" />
                        </div>
                        
                        <div className={cn(
                            "p-2 rounded-lg bg-white/10",
                            !block.isVisible && "opacity-50 grayscale"
                        )}>
                            <Icon className="w-4 h-4 text-slate-300" />
                        </div>

                        <span className={cn(
                            "flex-1 text-sm font-bold text-slate-200",
                            !block.isVisible && "text-slate-500"
                        )}>
                          {block.label}
                        </span>

                        <Switch
                          checked={block.isVisible}
                          onCheckedChange={(checked) => handleToggleVisibility(block.id, checked)}
                        />
                      </div>
                    )}
                  </Draggable>
                );
              })}
              {provided.placeholder}
            </div>
          )}
        </Droppable>
      </DragDropContext>
    </div>
  );
};

import { useState, useEffect } from 'react';
import Dexie from 'dexie';
import { useLiveQuery } from 'dexie-react-hooks';
import { Button } from '@/components/ui/button';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { LocalDB, initializeDB, getLocalDb } from '@/services/localDB';
import { useAuth } from '@/contexts/AuthContext';
import { Clock, RefreshCw, AlertTriangle, CheckCircle, Loader2, Folder, FileText, ChevronDown, ChevronRight } from '@/ui/icons';
import { useToast } from '@/contexts/ToastContext';
import { Collapsible, CollapsibleTrigger, CollapsibleContent } from '@/components/ui/collapsible';

export default function DataRescuePanel() {
  const { currentUser } = useAuth();
  const { success, error } = useToast();
  
  const [databases, setDatabases] = useState<(IDBDatabaseInfo & { counts?: unknown, tableDetails?: unknown, isCurrent?: boolean })[]>([]);
  const [loading, setLoading] = useState(false);
  const [importing, setImporting] = useState<string | null>(null);
  const [progressMsg, setProgressMsg] = useState<string>('');
  const [logs, setLogs] = useState<string[]>([]);
  const [scanResult, setScanResult] = useState<string>('');
  const [expandedDb, setExpandedDb] = useState<string | null>(null);
  const [isAdvancedOpen, setIsAdvancedOpen] = useState(false);

  // Live Stats for Summary Section
  const currentStats = useLiveQuery(async () => {
    if (!currentUser) return { folders: 0, cards: 0 };
    const db = await getLocalDb();
    const folders = await db.folders.count();
    const cards = await db.cards.count();
    return { folders, cards };
  }, [currentUser], { folders: 0, cards: 0 });

  const refreshList = async () => {
    setLoading(true);
    setScanResult('データベース一覧を取得中...');
      try {
        const dbs = await LocalDB.listDatabases();
        const db = await getLocalDb();
        const currentDbName = db.name;
        
        const enriched: unknown[] = [];
        console.log(`[Rescue] Scanning ${dbs.length} databases...`);

        for (let i = 0; i < dbs.length; i++) {
            const d = dbs[i];
            if (!d.name) {
                enriched.push(d);
                continue;
            }

            // Skip internal Firebase Auth/Heartbeat DBs to prevent locking/login issues
            if (d.name.includes('firebaseLocalStorage') || d.name.includes('heat-database') || d.name.includes('heartbeat')) {
                continue;
            }

            setScanResult(`分析中 (${i+1}/${dbs.length}): ${d.name}...`);
            
            try {
                const tempDb = new Dexie(d.name);
                // 3秒でタイムアウトさせる（スキャン時は短めで良い）
                await Promise.race([
                    tempDb.open(),
                    new Promise((_, reject) => setTimeout(() => reject(new Error('Timeout')), 3000))
                ]);

                const tableDetails: unknown = {};
                for (const table of tempDb.tables) {
                    try {
                        const count = await table.count();
                        tableDetails[table.name] = count;
                    } catch (e) {}
                }

                const counts: unknown = {
                    folders: tableDetails['folders'] || tableDetails['folder'] || tableDetails['folder_list'] || 0,
                    cards: tableDetails['cards'] || tableDetails['card'] || tableDetails['flashcards'] || tableDetails['flash_cards'] || 0,
                    logs: tableDetails['studyLogs'] || tableDetails['study_logs'] || tableDetails['learning_history'] || tableDetails['history'] || 0,
                    total: Object.values(tableDetails).reduce((a: unknown, b: unknown) => a + b, 0)
                };

                tempDb.close();
                
                // Only include if it has data
                if (counts.total > 0) {
                    enriched.push({ 
                        ...d, 
                        counts, 
                        tableDetails, 
                        isCurrent: d.name === currentDbName 
                    });
                }
            } catch (e: unknown) {
                console.warn(`[Rescue] Skipping ${d.name} due to scan error/timeout:`, e.message);
            }
        }

        // Sort: databases with actual cards/folders first
        enriched.sort((a, b) => {
            const aVal = (a.counts?.cards || 0) + (a.counts?.folders || 0);
            const bVal = (b.counts?.cards || 0) + (b.counts?.folders || 0);
            if (aVal !== bVal) return bVal - aVal;
            return (b.counts?.total || 0) - (a.counts?.total || 0);
        });

        setDatabases(enriched);
        setScanResult(`スキャン完了 (${enriched.length}個のバックアップが見つかりました)`);
    } catch (e: unknown) {
      console.error('Failed to list databases', e);
      setScanResult(`スキャン失敗: ${e.message}`);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    refreshList();
  }, []);

  const handleImport = async (targetDbName: string) => {
    if (!currentUser) return;
    
    setLogs([]); // Clear logs
    setImporting(targetDbName);
    setProgressMsg('初期化中...');
    const addLog = (m: string) => {
        setLogs(prev => [...prev.slice(-500), `${new Date().toLocaleTimeString()}: ${m}`]);
    };

      addLog(`復元開始: ${targetDbName}`);
      try {
      initializeDB(currentUser.uid);
      const targetUserDb = await getLocalDb();

      const result = await targetUserDb.importFromDatabase(targetDbName, currentUser.uid, (msg) => {
          setProgressMsg(msg);
          addLog(msg);
      });
      addLog(`完了！ フォルダ: ${result.folders}, カード: ${result.cards}`);
      
      success(`復元が完了しました。反映には【再読み込み】が必要です。`);
      setTimeout(() => window.location.reload(), 1500);
    } catch (e: unknown) {
      console.error(e);
      addLog(`エラー: ${e.message}`);
      error(`復元失敗: ${e.message}`);
    } finally {
      setImporting(null);
    }
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
        
      {/* 1. Summary Section */}
        <div className="grid grid-cols-2 gap-4">
            <Card className="bg-white/5 border-white/10 shadow-sm rounded-xl">
                <CardContent className="p-6 flex items-center gap-4">
                    <div className="p-3 bg-emerald-500/10 rounded-full text-emerald-400">
                        <Folder className="w-6 h-6" />
                    </div>
                    <div>
                        <div className="text-2xl font-bold text-white">{currentStats?.folders || 0}</div>
                        <div className="text-xs font-bold text-slate-400">作成済みフォルダ</div>
                    </div>
                </CardContent>
            </Card>
            <Card className="bg-white/5 border-white/10 shadow-sm rounded-xl">
                <CardContent className="p-6 flex items-center gap-4">
                    <div className="p-3 bg-blue-500/10 rounded-full text-blue-400">
                        <FileText className="w-6 h-6" />
                    </div>
                    <div>
                        <div className="text-2xl font-bold text-white">{currentStats?.cards || 0}</div>
                        <div className="text-xs font-bold text-slate-400">作成済みカード</div>
                    </div>
                </CardContent>
            </Card>
        </div>

      {/* 2. Restoration Section */}
      <div className="space-y-4">
        <div className="flex items-center justify-between">
            <div>
                <h3 className="text-lg font-bold text-slate-200 flex items-center gap-2">
                    <HistoryIcon className="w-5 h-5 text-slate-400" />
                    バックアップからの復元
                </h3>
                <p className="text-xs text-slate-400 mt-1">
                    このブラウザに保存されている過去のデータから復元できます
                </p>
            </div>
            <Button variant="ghost" size="sm" onClick={refreshList} disabled={loading} className="text-slate-400 hover:text-emerald-400 hover:bg-emerald-500/10 rounded-lg">
                <RefreshCw className={`w-4 h-4 mr-2 ${loading ? 'animate-spin' : ''}`} />
                再スキャン
            </Button>
        </div>

        {databases.length === 0 && !loading ? (
             <Card className="border-dashed border-white/20 bg-white/5 rounded-xl">
                <CardContent className="flex flex-col items-center justify-center py-12 text-slate-400">
                    <Folder className="w-12 h-12 mb-4 opacity-50" />
                    <p className="text-sm">復元可能なバックアップは見つかりませんでした</p>
                </CardContent>
            </Card>
        ) : (
            <div className="grid gap-3">
                {databases.filter(d => !d.isCurrent).map(d => (
                    <Card key={d.name} className="overflow-hidden border-white/10 hover:border-emerald-500/50 bg-white/5 transition-colors group rounded-xl">
                        <CardContent className="p-0">
                            <div className="flex items-center justify-between p-4 bg-white/5 backdrop-blur-md">
                                <div className="flex items-center gap-4">
                                    <div className="p-2 bg-white/10 rounded-lg text-slate-400 group-hover:bg-emerald-500/20 group-hover:text-emerald-400 transition-colors">
                                        <Folder className="w-5 h-5" />
                                    </div>
                                    <div>
                                        <div className="flex items-center gap-2">
                                            <span className="font-bold text-slate-200 text-sm">
                                                Backup Data
                                            </span>
                                            <span className="text-[10px] bg-white/10 text-slate-400 px-1.5 py-0.5 rounded font-serif border border-white/10">
                                                {d.name?.slice(-8)}
                                            </span>
                                        </div>
                                        <div className="text-xs text-slate-400 mt-0.5 flex gap-3">
                                            <span>Folders: <b>{d.counts?.folders || 0}</b></span>
                                            <span>Cards: <b>{d.counts?.cards || 0}</b></span>
                                        </div>
                                    </div>
                                </div>
                                <Button 
                                    size="sm" 
                                    className="bg-slate-700/50 hover:bg-emerald-600 text-white transition-colors border border-white/10 backdrop-blur-sm"
                                    onClick={() => handleImport(d.name || '')}
                                    disabled={importing !== null}
                                >
                                    {importing === d.name ? (
                                        <Loader2 className="w-4 h-4 animate-spin" />
                                    ) : (
                                        <>
                                            <RefreshCw className="w-3 h-3 mr-2" />
                                            復元する
                                        </>
                                    )}
                                </Button>
                            </div>
                        </CardContent>
                    </Card>
                ))}
            </div>
        )}
      </div>

      {/* 3. Advanced Tools (Collapsible) */}
      <Collapsible open={isAdvancedOpen} onOpenChange={setIsAdvancedOpen} className="border-t border-white/10 pt-6">
        <CollapsibleTrigger asChild>
            <Button variant="ghost" className="w-full flex justify-between text-slate-400 hover:text-white hover:bg-white/5 h-12 rounded-xl">
                <span className="flex items-center gap-2 text-xs font-bold">
                    <RefreshCw className="w-4 h-4" />
                    高度な機能 / トラブルシューティング
                </span>
                {isAdvancedOpen ? <ChevronDown className="w-4 h-4" /> : <ChevronRight className="w-4 h-4" />}
            </Button>
        </CollapsibleTrigger>
        <CollapsibleContent className="space-y-4 pt-4">
            
            {/* Integrity Repair */}
            <Card className="border-sky-500/20 bg-sky-500/10 rounded-xl">
                <CardHeader className="pb-2">
                    <CardTitle className="text-sm font-bold text-sky-300 flex items-center gap-2">
                        <CheckCircle className="w-4 h-4" />
                        データの正規化 (Normalization)
                    </CardTitle>
                    <CardDescription className="text-xs text-sky-200/70">
                        重複してしまったフォルダなどを整理し、データを正しい状態に修復します。
                    </CardDescription>
                </CardHeader>
                <CardContent>
                    <Button 
                        size="sm" 
                        className="bg-sky-600 hover:bg-sky-500 text-white w-full border border-sky-400/30"
                        onClick={async () => {
                                if (!currentUser) return;
                            setLoading(true);
                            try {
                                initializeDB(currentUser.uid);
                                const userDb = await getLocalDb();
                                const result = await userDb.repairDataIntegrity(currentUser.uid, setProgressMsg);
                                success(`修復完了: ${result.folders}個のフォルダ、${result.cards}件のカードを整理しました。`);
                                window.location.reload();
                            } catch (err: unknown) {
                                error(`エラー: ${err.message}`);
                            } finally {
                                setLoading(false);
                            }
                        }}
                        disabled={loading}
                    >
                        {loading ? <Loader2 className="w-4 h-4 animate-spin mr-2" /> : <RefreshCw className="w-4 h-4 mr-2" />}
                        修復を実行
                    </Button>
                </CardContent>
            </Card>

            {/* Forensic Audit */}
            <Card className="border-red-500/20 bg-red-500/10 rounded-xl">
                 <CardHeader className="pb-2">
                    <CardTitle className="text-sm font-bold text-red-300 flex items-center gap-2">
                        <AlertTriangle className="w-4 h-4" />
                        詳細スキャン (Forensic Audit)
                    </CardTitle>
                    <CardDescription className="text-xs text-red-200/70">
                        ブラウザ内の全ての領域を強制スキャンし、隠れたデータを探します（上級者向け）。
                    </CardDescription>
                </CardHeader>
                <CardContent>
                    <Button 
                        size="sm" 
                        variant="destructive" 
                        className="w-full bg-red-500/20 hover:bg-red-500/30 text-red-300 border border-red-500/30 backdrop-blur-sm"
                        onClick={async () => {
                            if (!confirm("大量のログが出力されますがよろしいですか？")) return;
                            try {
                                await LocalDB.fullOriginForensicAudit((msg) => console.log(msg));
                                alert("完了しました。F12コンソールを確認してください。");
                            } catch (err: unknown) {
                                alert(err.message);
                            }
                        }}
                    >
                        完全スキャンを実行
                    </Button>
                </CardContent>
            </Card>
            
            {/* Logs Area */}
            {logs.length > 0 && (
                <div className="p-3 bg-black/40 rounded-lg border border-white/10 font-serif text-[9px] text-emerald-400 max-h-40 overflow-y-auto custom-scrollbar">
                    {logs.map((log, i) => (
                        <div key={i}>{log}</div>
                    ))}
                </div>
            )}

        </CollapsibleContent>
      </Collapsible>
    </div>
  );
}

function HistoryIcon(props: unknown) {
    return (
      <svg
        {...props}
        xmlns="http://www.w3.org/2000/svg"
        width="24"
        height="24"
        viewBox="0 0 24 24"
        fill="none"
        stroke="currentColor"
        strokeWidth="2"
        strokeLinecap="round"
        strokeLinejoin="round"
      >
        <path d="M3 12a9 9 0 1 0 9-9 9.75 9.75 0 0 0-6.74 2.74L3 12" />
        <path d="M3 3v9h9" />
        <path d="M12 7v5l4 2" />
      </svg>
    )
}

import React, { useEffect, useState } from 'react';
import { firestoreDb } from '../../services/firebase';
import { collection, query, getDocs, Timestamp } from 'firebase/firestore';
import { useAuth } from '../../contexts/AuthContext';
import type { SyncMetadata } from '../../types';
import { format } from 'date-fns';
import { ja } from 'date-fns/locale';
import { SyncService } from '../../services/syncService';
import { initializeDB, getLocalDb } from '../../services/localDB';
import { RefreshCw, Pencil, Check, X, Trash2 } from '@/ui/icons';
import { Smartphone } from '@/ui/icons';
import { SyncServiceFactory } from '../../services/SyncServiceFactory';
import type { UserStats } from '../../types';
import { useSyncSettings } from '../../hooks/useSyncSettings';
import { Switch } from '../ui/switch';

export const DeviceSyncSettings: React.FC = () => {
  const { currentUser } = useAuth();
  const [devices, setDevices] = useState<SyncMetadata[]>([]);
  const [stats, setStats] = useState<UserStats | null>(null);
  const [loading, setLoading] = useState(true);
  const [removingId, setRemovingId] = useState<string | null>(null);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editName, setEditName] = useState('');
  const [cleaning, setCleaning] = useState(false);
  const [cleanupMessage, setCleanupMessage] = useState<string | null>(null);
  const { settings: syncSettings, updateSettings: updateSyncSettings } = useSyncSettings();

  const fetchStats = async () => {
    if (!currentUser) return;
    initializeDB(currentUser.uid);
    const db = await getLocalDb();
    const s = await db.userStats.get('current') || await db.userStats.toCollection().first();
    setStats(s || null);
  };

  const fetchDevices = async () => {
    if (!currentUser) return;
    setLoading(true);
    try {
      const q = query(collection(firestoreDb, `sync_metadata/${currentUser.uid}/devices`));
      const snapshot = await getDocs(q);
      const deviceList = snapshot.docs.map(doc => doc.data() as SyncMetadata);
      // 最終同期時刻で降順ソート（新しい順）
      deviceList.sort((a, b) => {
        const timeA = a.lastSyncTime instanceof Timestamp ? a.lastSyncTime.toMillis() : new Date(a.lastSyncTime || 0).getTime();
        const timeB = b.lastSyncTime instanceof Timestamp ? b.lastSyncTime.toMillis() : new Date(b.lastSyncTime || 0).getTime();
        return timeB - timeA;
      });
      setDevices(deviceList);
    } catch (error) {
      console.error('[DeviceSyncSettings] Failed to fetch devices:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleDisconnect = async (deviceId: string) => {
    if (!currentUser) return;
    if (!window.confirm('この端末の同期を解除しますか？')) return;
    
    setRemovingId(deviceId);
    try {
      const syncService = await SyncServiceFactory.getInstance(currentUser.uid);
      await syncService.removeDevice(deviceId);
      await fetchDevices();
    } catch (error) {
      console.error('[DeviceSyncSettings] Failed to remove device:', error);
    } finally {
      setRemovingId(null);
    }
  };

  const handleCleanup = async () => {
    if (!currentUser) return;
    if (!window.confirm('60日以上同期がない古いセッションを一括解除しますか？\n(シークレットモード等の残骸を掃除します)')) return;

    setCleaning(true);
    try {
      const syncService = await SyncServiceFactory.getInstance(currentUser.uid);
      const cleanedCount = await syncService.cleanupInactiveDevices();
      setCleanupMessage(`${cleanedCount}台の古いセッションを解除しました。`);
      setTimeout(() => setCleanupMessage(null), 3000);
      await fetchDevices();
    } catch (error) {
      console.error('[DeviceSyncSettings] Cleanup failed:', error);
    } finally {
      setCleaning(false);
    }
  };

  const handleUpdateName = async (deviceId: string) => {
    if (!currentUser || !editName.trim()) {
      setEditingId(null);
      return;
    }
    
    try {
      const syncService = await SyncServiceFactory.getInstance(currentUser.uid);
      await syncService.updateDeviceName(deviceId, editName.trim());
      setEditingId(null);
      await fetchDevices();
    } catch (error) {
      console.error('[DeviceSyncSettings] Failed to update device name:', error);
    }
  };

  const startEditing = (device: SyncMetadata) => {
    setEditingId(device.deviceId);
    setEditName(device.deviceName || '');
  };

  useEffect(() => {
    fetchDevices();
    fetchStats();
  }, [currentUser]);

  const formatDate = (date: unknown) => {
    if (!date) return '未同期';
    const d = date instanceof Timestamp ? date.toDate() : new Date(date);
    return format(d, 'yyyy/MM/dd HH:mm', { locale: ja });
  };

  const totalUsed = stats?.totalStorageUsedBytes || 0;
  const highResUsed = stats?.totalHighResBytes || 0;
  const thumbnailUsed = stats?.totalThumbnailBytes || 0;
  const MAX_QUOTA = 500 * 1024 * 1024; // 500MB
  const quotaPercent = Math.min((totalUsed / MAX_QUOTA) * 100, 100);
  const highResPercent = (highResUsed / MAX_QUOTA) * 100;
  const thumbnailPercent = (thumbnailUsed / MAX_QUOTA) * 100;

  const formatSize = (bytes: number) => {
    if (bytes === 0) return '0 B';
    const k = 1024;
    const sizes = ['B', 'KB', 'MB', 'GB'];
    const i = Math.floor(Math.log(bytes) / Math.log(k));
    return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <h2 className="text-2xl font-bold mb-6 flex items-center gap-3 text-white">
        <div className="p-2.5 bg-primary-400/20 text-primary-300 rounded-xl shadow-[0_0_10px_rgba(123,172,170,0.3)]">
          <Smartphone className="w-6 h-6" />
        </div>
        同期・ストレージ管理
      </h2>

      {/* Sync Settings Toggles */}
      <div className="p-6 bg-white/5 border border-white/10 rounded-2xl shadow-sm mb-6">
        <div className="flex items-center justify-between">
          <div>
            <h4 className="text-sm font-bold text-slate-200">非アクティブ端末の自動整理</h4>
              <p className="text-[10px] text-slate-400 font-medium mt-1">
                60日以上同期がない古いセッションを自動的に解除します（シークレットモード等の残骸の掃除）。
              </p>
          </div>
          <Switch 
            checked={syncSettings?.autoCleanupDevices ?? true}
            onCheckedChange={(checked) => updateSyncSettings({ autoCleanupDevices: checked })}
          />
        </div>
      </div>

      {/* Storage Usage Bar */}
      <div className="p-6 bg-white/5 border border-white/10 rounded-2xl shadow-sm">
        <div className="flex justify-between items-end mb-3">
          <span className="text-xs font-bold text-slate-400 uppercase tracking-widest">クラウドストレージ使用量</span>
          <span className={`text-[10px] font-bold ${quotaPercent > 90 ? 'text-red-400 animate-pulse' : 'text-slate-400'}`}>
            {formatSize(totalUsed)} / {formatSize(MAX_QUOTA)}
            {quotaPercent > 90 && ' (残りわずか!)'}
          </span>
        </div>
        <div className="h-2 w-full bg-white/10 rounded-full overflow-hidden flex">
          <div 
            style={{ '--progress': `${highResPercent}%`, '--progress-color': quotaPercent > 90 ? '#ef4444' : 'var(--primary-color)' } as React.CSSProperties} 
            className="h-full progress-bar-fill opacity-80"
          />
          <div 
            style={{ '--progress': `${thumbnailPercent}%`, '--progress-color': '#a5b4fc' } as React.CSSProperties} 
            className="h-full progress-bar-fill opacity-60"
          />
        </div>
        <div className="mt-4 flex gap-6 text-[10px] text-slate-400 font-bold uppercase tracking-wider">
          <div className="flex items-center gap-2">
            <span className="w-2 h-2 bg-primary-400 rounded-full shadow-[0_0_5px_rgba(123,172,170,0.5)]"></span>
            高解像度画像 ({formatSize(highResUsed)})
          </div>
          <div className="flex items-center gap-2">
            <span className="w-2 h-2 bg-indigo-300 rounded-full"></span>
            サムネイル ({formatSize(thumbnailUsed)})
          </div>
        </div>
      </div>

      {loading ? (
        <div className="flex justify-center py-10">
          <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-blue-400"></div>
        </div>
      ) : (
        <div className="space-y-4">
          <div className="flex justify-between items-center px-1">
            <h3 className="text-xs font-bold text-slate-400 uppercase tracking-[0.2em]">登録デバイス ({devices.filter(d => d.isActive).length})</h3>
            <div className="flex items-center gap-3">
              {cleanupMessage && (
                <span className="text-[10px] text-emerald-500 font-bold animate-in slide-in-from-right-2 fade-in">
                  {cleanupMessage}
                </span>
              )}
              <button 
                onClick={handleCleanup}
                disabled={cleaning}
                className="flex items-center gap-1.5 px-3 py-1.5 text-[10px] font-bold text-slate-400 hover:text-red-500 hover:bg-red-50 rounded-lg transition-all border border-transparent hover:border-red-100 disabled:opacity-50"
                title="60日以上動いていない端末を掃除"
              >
                <Trash2 className={`w-3 h-3 ${cleaning ? 'animate-bounce' : ''}`} />
                古いセッションを掃除
              </button>
            </div>
          </div>
          {devices.length === 0 ? (
            <p className="text-slate-400 text-center py-10 font-bold text-sm bg-white/5 rounded-2xl border border-dashed border-white/20">
                同期されているデバイスはありません。
            </p>
          ) : (
            devices.map((device) => {
              const isRevoked = device.status === 'revoked';
              const isCurrentDevice = device.deviceId === localStorage.getItem('deviceId');
              
              return (
                <div 
                  key={device.deviceId} 
                  className={`p-5 rounded-2xl border transition-all ${
                    isRevoked 
                      ? 'bg-white/5 border-white/10 opacity-60' // Revoked style (glass)
                      : device.isActive 
                        ? 'bg-white/5 border-white/10 shadow-sm hover:shadow-md hover:border-white/20 hover:bg-white/10' 
                        : 'bg-white/5 border-white/5 grayscale opacity-70' // Disconnected style
                  } ${isCurrentDevice ? 'ring-1 ring-primary-400/30' : ''}`}
                >
                  <div className={`w-10 h-10 rounded-xl flex items-center justify-center ${
                    isRevoked ? 'bg-white/10 text-slate-500' : 'bg-orange-500/10 text-orange-400'
                  }`}>
                  <Smartphone className="w-5 h-5" />
                </div>
                  <div className="flex justify-between items-start mb-2">
                    <div className="flex-1">
                      {editingId === device.deviceId ? (
                        <div className="flex items-center gap-2">
                          <input 
                            autoFocus
                            type="text"
                            title="デバイス名を編集"
                            value={editName}
                            onChange={(e) => setEditName(e.target.value)}
                            onKeyDown={(e) => e.key === 'Enter' && handleUpdateName(device.deviceId)}
                            className="text-sm font-bold text-white bg-black/40 border border-primary-500/30 rounded-lg px-2 py-1 outline-none focus:ring-2 focus:ring-primary-500/20 flex-1"
                          />
                          <button onClick={() => handleUpdateName(device.deviceId)} title="保存" className="p-1 text-primary-400 hover:bg-primary-500/20 rounded-md transition-colors">
                            <Check className="w-4 h-4" />
                          </button>
                          <button onClick={() => setEditingId(null)} title="キャンセル" className="p-1 text-slate-400 hover:bg-white/10 rounded-md transition-colors">
