import { getLocalDb } from './localDB';
import { StorageStateManager } from './StorageStateManager';
import { SafeIndexedDBWriter } from './SafeIndexedDBWriter';

/**
 * 圧縮された履歴データの型定義
 */
interface CompressedHistory {
  id: string;
  userId: string;
  cardId: string;
  date: Date; // 日単位
  reviewCount: number;
  correctCount: number;
  avgInterval: number;
}

/**
 * 履歴圧縮サービス
 * 
 * ルール:
 * - 直近30日: raw event
 * - 31日〜90日: 日単位に圧縮
 * - 91日以降: 統計値のみ
 * 
 * 🔥 重要: 圧縮は贅沢処理。READ_ONLY 中は実行しない。
 */
export class HistoryCompressionService {
  /**
   * 古い履歴を圧縮
   * 
   * @param userId ユーザーID
   */
  async compress(userId: string): Promise<void> {
    // READ_ONLY 中は圧縮しない（無意味な計算を避ける）
    if (StorageStateManager.isReadOnly(userId)) {
      console.log(`[Compression:${userId}] Skipped (READ_ONLY mode)`);
      return;
    }
    
    const db = await getLocalDb(userId);
    
    try {
      // 30日以前の raw event を取得
      const thirtyDaysAgo = new Date();
      thirtyDaysAgo.setDate(thirtyDaysAgo.getDate() - 30);
      
      const oldEvents = await db.levelHistories
        .where('changedAt')
        .below(thirtyDaysAgo)
        .toArray();
      
      if (oldEvents.length === 0) {
        console.log(`[Compression:${userId}] No old events to compress`);
        return;
      }
      
      // 日単位に圧縮
      const compressed = this.compressByDay(oldEvents, userId);
      
      // TODO: 圧縮データを保存するテーブルを追加
      // 現時点では圧縮データの保存先がないため、ログのみ
      console.log(`[Compression:${userId}] Compressed ${oldEvents.length} events into ${compressed.length} daily summaries`);
      
      // TODO: raw event を削除
      // await SafeIndexedDBWriter.write(
      //   userId,
      //   () => db.levelHistories
      //     .where('changedAt')
      //     .below(thirtyDaysAgo)
      //     .delete(),
      //   'deleteOldEvents'
      // );
      
    } catch (error) {
      console.error(`[Compression:${userId}] Failed:`, error);
      // 失敗してもアプリは継続
    }
  }
  
  /**
   * イベントを日単位に圧縮
   */
  private compressByDay(events: unknown[], userId: string): CompressedHistory[] {
    // 日ごとにグループ化
    const byDay = new Map<string, any[]>();
    
    for (const event of events) {
      const changedAt = event.changedAt instanceof Date 
        ? event.changedAt 
        : new Date(event.changedAt);
      const day = changedAt.toISOString().split('T')[0];
      const key = `${event.cardId}_${day}`;
      
      if (!byDay.has(key)) {
        byDay.set(key, []);
      }
      byDay.get(key)!.push(event);
    }
    
    // 統計値を計算
    const compressed: CompressedHistory[] = [];
    
    for (const [key, dayEvents] of byDay.entries()) {
      const [cardId, day] = key.split('_');
      
      // 正解数をカウント
      const correctCount = dayEvents.filter(e => {
        // correct フィールドがある場合
        if (typeof e.correct === 'boolean') return e.correct;
        // level の変化で判定（増加 = 正解）
        if (e.newLevel !== undefined && e.oldLevel !== undefined) {
          return e.newLevel > e.oldLevel;
        }
        return false;
      }).length;
      
      // 平均間隔を計算
      const intervals = dayEvents
        .map(e => e.interval)
        .filter(i => typeof i === 'number' && i > 0);
      const avgInterval = intervals.length > 0
        ? intervals.reduce((sum, i) => sum + i, 0) / intervals.length
        : 0;
      
      compressed.push({
        id: `${userId}_${cardId}_${day}`,
        userId,
        cardId,
        date: new Date(day),
        reviewCount: dayEvents.length,
        correctCount,
        avgInterval
      });
    }
    
    return compressed;
  }
}

import { storage } from './firebase';
import { ref, uploadBytes, getDownloadURL } from 'firebase/storage';
import { initializeDB, getLocalDb } from './localDB';
import type { UploadedImage } from '@/types';
import type { BlobUrl, StorageUrl } from '@/types/branded';
import { createStorageUrl, revokeBlobUrl } from '@/types/branded';
import { assertImageInvariant } from '@/utils/imageAssertions';

/**
 * 画像同期のオーケストレーター
 * 
 * 責務:
 * - 画像のアップロードとDB更新を一貫して行う
 * - 状態機械による同期状態の管理
 * - この関数以外から upload / DB update を呼ばせない
 */
export class ImageSyncOrchestrator {
  private userId: string;

  constructor(userId: string) {
    this.userId = userId;
    initializeDB(userId);
  }

  /**
   * 画像の同期とDB更新を一貫して行う唯一の関数
   * 
   * 正式な同期順序（変更不可）:
   * 1. local image 存在確認
   * 2. Storage アップロード
   * 3. remoteUrl 確定
   * 4. Assert（最終防衛線）
   * 5. DB 更新
   * 6. local cleanup
   * 
   * @throws {Error} アップロード失敗時
   */
  async syncImageAndUpdateCard(
    cardId: string,
    imageField: 'questionImages' | 'answerImages',
    imageIndex: number,
    image: UploadedImage
  ): Promise<UploadedImage> {
    // 1. local image 存在確認
    if (!image.localUrl) {
      throw new Error('[ImageSync] No local image to sync');
    }

    // 2. Storage アップロード
    const remoteUrl = await this.uploadLocalImage(image.localUrl, image.id);

    // 3. remoteUrl 確定
    const syncedImage: UploadedImage = {
      ...image,
      remoteUrl,
      status: 'ready',
      source: 'cloud',
      uploadState: 'completed',
      lastAttempt: new Date()
    };

    // 4. Assert（最終防衛線）
    assertImageInvariant(syncedImage);

    // 5. DB 更新
    await this.updateCardImage(cardId, imageField, imageIndex, syncedImage);

    // 6. local cleanup
    if (image.localUrl) {
      revokeBlobUrl(image.localUrl);
    }

    return syncedImage;
  }

  /**
   * 状態機械による画像同期の処理
   * 
   * 状態遷移:
   * PENDING → (upload success) → READY
   * PENDING → (upload fail) → FAILED
   * FAILED → (retry) → PENDING
   */
  async processImageByState(
    cardId: string,
    imageField: 'questionImages' | 'answerImages',
    imageIndex: number,
    image: UploadedImage
  ): Promise<void> {
    switch (image.status) {
      case 'uploading':
        // PENDING 状態: アップロードを試行
        try {
          await this.syncImageAndUpdateCard(cardId, imageField, imageIndex, image);
        } catch (error) {
          console.error('[ImageSync] Upload failed:', error);
          // FAILED 状態に遷移
          await this.markImageAsFailed(cardId, imageField, imageIndex, error as Error);
        }
        break;

      case 'failed':
        // FAILED 状態: リトライロジック（後で実装）
        console.warn('[ImageSync] Image in failed state, retry later:', image.id);
        break;

      case 'ready':
        // READY 状態: 何もしない
        break;

      default:
        console.warn('[ImageSync] Unknown image status:', image.status);
    }
  }

  /**
   * ローカル画像を Storage にアップロード
   * @private
   */
  private async uploadLocalImage(localUrl: BlobUrl, imageId: string): Promise<StorageUrl> {
    // Blob URL から Blob を取得
    const response = await fetch(localUrl);
    const blob = await response.blob();

    // Storage パスを生成
    const storagePath = `users/${this.userId}/images/${imageId}_full`;
    const storageRef = ref(storage, storagePath);

    // アップロード
    await uploadBytes(storageRef, blob);

    // Download URL を取得
    const downloadUrl = await getDownloadURL(storageRef);

    return createStorageUrl(downloadUrl);
  }

  /**
   * カードの画像を更新
   * @private
   */
  private async updateCardImage(
    cardId: string,
    imageField: 'questionImages' | 'answerImages',
    imageIndex: number,
    syncedImage: UploadedImage
  ): Promise<void> {
    const db = await getLocalDb();
    const card = await db.cards.get(cardId);
    if (!card) {
      throw new Error(`[ImageSync] Card not found: ${cardId}`);
    }

    const images = card[imageField] || [];
    images[imageIndex] = syncedImage;

    const updateData: unknown = {
      [imageField]: images,
      updatedAt: new Date()
    };

    await db.cards.update(cardId, updateData);
  }

  /**
   * 画像を失敗状態にマーク
   * @private
   */
  private async markImageAsFailed(
    cardId: string,
    imageField: 'questionImages' | 'answerImages',
    imageIndex: number,
    error: Error
  ): Promise<void> {
    const db = await getLocalDb();
    const card = await db.cards.get(cardId);
    if (!card) return;

    const images = card[imageField] || [];
    const image = images[imageIndex];

    if (image) {
      images[imageIndex] = {
        ...image,
        status: 'failed',
        uploadState: 'failed',
        lastAttempt: new Date()
      };

      const updateData: unknown = {
        [imageField]: images,
        updatedAt: new Date()
      };

      await db.cards.update(cardId, updateData);
    }
  }

  /**
   * すべての未同期画像を処理
   */
  async syncAllPendingImages(onProgress?: (msg: string) => void): Promise<void> {
    onProgress?.('未同期画像を検索中...');
    
    const db = await getLocalDb();
    const cards = await db.cards.toArray();
    let totalProcessed = 0;

    for (const card of cards) {
      // questionImages の処理
      if (card.questionImages) {
        for (let i = 0; i < card.questionImages.length; i++) {
          const image = card.questionImages[i];
          if (image.status === 'uploading' && image.localUrl) {
            onProgress?.(`アップロード中: ${card.id.substring(0, 8)}... (${totalProcessed + 1})`);
            await this.processImageByState(card.id, 'questionImages', i, image);
            totalProcessed++;
          }
        }
      }

      // answerImages の処理
      if (card.answerImages) {
        for (let i = 0; i < card.answerImages.length; i++) {
          const image = card.answerImages[i];
          if (image.status === 'uploading' && image.localUrl) {
            onProgress?.(`アップロード中: ${card.id.substring(0, 8)}... (${totalProcessed + 1})`);
            await this.processImageByState(card.id, 'answerImages', i, image);
            totalProcessed++;
          }
        }
      }
    }

    onProgress?.(`完了: ${totalProcessed} 件の画像を同期しました`);
  }
}

import { nanoid } from 'nanoid';
import { normalizeCard, normalizeFolder } from '../utils';
import { getDeviceName, getOrCreateDeviceId } from '../utils/device';
import type { Card, Folder, SyncQueueItem } from '../types';

type KeyPath = string | string[];
type Predicate<T> = (value: T) => boolean;

const toTimestamp = (value: unknown): number => {
  if (value instanceof Date) return value.getTime();
  if (value && typeof value?.toDate === 'function') {
    const date = value.toDate();
    return date instanceof Date ? date.getTime() : Number(date) || 0;
  }
  if (typeof value === 'number') return value;
  if (typeof value === 'string') {
    const parsed = Date.parse(value);
    return Number.isFinite(parsed) ? parsed : 0;
  }
  return 0;
};

const normalizeComparable = (value: unknown): unknown => {
  if (value instanceof Date || (value && typeof value?.toDate === 'function')) {
    return toTimestamp(value);
  }
  if (Array.isArray(value)) return value.map((v) => normalizeComparable(v));
  return value;
};

const compareValues = (left: unknown, right: unknown): number => {
  const a = normalizeComparable(left);
  const b = normalizeComparable(right);

  if (Array.isArray(a) && Array.isArray(b)) {
    const len = Math.max(a.length, b.length);
    for (let i = 0; i < len; i += 1) {
      if (i >= a.length) return -1;
      if (i >= b.length) return 1;
      const cmp = compareValues(a[i], b[i]);
      if (cmp !== 0) return cmp;
    }
    return 0;
  }

  if (a === b) return 0;
  if (a === undefined || a === null) return -1;
  if (b === undefined || b === null) return 1;
  if (a > b) return 1;
  if (a < b) return -1;
  return 0;
};

const isEqual = (left: unknown, right: unknown): boolean => compareValues(left, right) === 0;

const parseIndexKeys = (index: string): string[] => {
  if (index.startsWith('[') && index.endsWith(']')) {
    return index.slice(1, -1).split('+').map((s) => s.trim()).filter(Boolean);
  }
  return [index];
};

const serializeKey = (key: unknown): string => {
  if (Array.isArray(key)) return JSON.stringify(key);
  if (typeof key === 'object' && key !== null) return JSON.stringify(key);
  return String(key);
};

const ensureObject = <T extends Record<string, any>>(value: T): T => ({ ...value });

class InMemoryCollection<T extends Record<string, any>> {
  constructor(
    private readonly table: InMemoryTable<T>,
    private readonly predicates: Predicate<T>[] = [],
    private readonly indexKeys: string[] | null = null,
    private readonly orderByKeys: string[] | null = null,
    private readonly reversed = false,
    private readonly maxItems: number | null = null
  ) {}

  private clone(next: Partial<{
    predicates: Predicate<T>[];
    indexKeys: string[] | null;
    orderByKeys: string[] | null;
    reversed: boolean;
    maxItems: number | null;
  }>): InMemoryCollection<T> {
    return new InMemoryCollection(
      this.table,
      next.predicates ?? this.predicates,
      next.indexKeys ?? this.indexKeys,
      next.orderByKeys ?? this.orderByKeys,
      next.reversed ?? this.reversed,
      next.maxItems ?? this.maxItems
    );
  }

  private getIndexedValue(item: T): unknown {
    if (!this.indexKeys || this.indexKeys.length === 0) return undefined;
    if (this.indexKeys.length === 1) return item[this.indexKeys[0]];
    return this.indexKeys.map((key) => item[key]);
  }

  private withIndexPredicate(predicate: (indexValue: unknown) => boolean): InMemoryCollection<T> {
    return this.clone({
      predicates: [
        ...this.predicates,
        (item) => predicate(this.getIndexedValue(item)),
      ],
    });
  }

  private resolveEntries(): Array<{ key: string; value: T }> {
    let entries = this.table.entries();

    if (this.predicates.length > 0) {
      entries = entries.filter(({ value }) => this.predicates.every((predicate) => predicate(value)));
    }

    if (this.orderByKeys && this.orderByKeys.length > 0) {
      entries.sort((a, b) => {
        const left = this.orderByKeys!.length === 1
          ? a.value[this.orderByKeys![0]]
          : this.orderByKeys!.map((key) => a.value[key]);
        const right = this.orderByKeys!.length === 1
          ? b.value[this.orderByKeys![0]]
          : this.orderByKeys!.map((key) => b.value[key]);
        return compareValues(left, right);
      });
    }

    if (this.reversed) entries.reverse();
    if (typeof this.maxItems === 'number') entries = entries.slice(0, this.maxItems);

    return entries;
  }

  equals(value: unknown): InMemoryCollection<T> {
    return this.withIndexPredicate((indexedValue) => isEqual(indexedValue, value));
  }

  above(value: unknown): InMemoryCollection<T> {
    return this.withIndexPredicate((indexedValue) => compareValues(indexedValue, value) > 0);
  }

  aboveOrEqual(value: unknown): InMemoryCollection<T> {
    return this.withIndexPredicate((indexedValue) => compareValues(indexedValue, value) >= 0);
  }

  below(value: unknown): InMemoryCollection<T> {
    return this.withIndexPredicate((indexedValue) => compareValues(indexedValue, value) < 0);
  }

  belowOrEqual(value: unknown): InMemoryCollection<T> {
    return this.withIndexPredicate((indexedValue) => compareValues(indexedValue, value) <= 0);
  }

  between(
    lowerValue: unknown,
    upperValue: unknown,
    includeLower = true,
    includeUpper = true
  ): InMemoryCollection<T> {
    return this.withIndexPredicate((indexedValue) => {
      const lowerOk = includeLower
        ? compareValues(indexedValue, lowerValue) >= 0
        : compareValues(indexedValue, lowerValue) > 0;
      const upperOk = includeUpper
        ? compareValues(indexedValue, upperValue) <= 0
        : compareValues(indexedValue, upperValue) < 0;
      return lowerOk && upperOk;
    });
  }

  startsWith(prefix: string): InMemoryCollection<T> {
    return this.withIndexPredicate((indexedValue) => {
      if (typeof indexedValue !== 'string') return false;
      return indexedValue.startsWith(prefix);
    });
  }

  anyOf(values: unknown[]): InMemoryCollection<T> {
    return this.withIndexPredicate((indexedValue) => values.some((value) => isEqual(indexedValue, value)));
  }

  and(predicate: Predicate<T>): InMemoryCollection<T> {
    return this.clone({ predicates: [...this.predicates, predicate] });
  }

  filter(predicate: Predicate<T>): InMemoryCollection<T> {
    return this.and(predicate);
  }

  reverse(): InMemoryCollection<T> {
    return this.clone({ reversed: !this.reversed });
  }

  limit(limit: number): InMemoryCollection<T> {
    return this.clone({ maxItems: Math.max(0, limit) });
  }

  async toArray(): Promise<T[]> {
    return this.resolveEntries().map(({ value }) => ensureObject(value));
  }

  async first(): Promise<T | undefined> {
    const first = this.resolveEntries()[0];
    return first ? ensureObject(first.value) : undefined;
  }

  async count(): Promise<number> {
    return this.resolveEntries().length;
  }

  async delete(): Promise<number> {
    const entries = this.resolveEntries();
    entries.forEach(({ key }) => this.table.deleteBySerializedKey(key));
    return entries.length;
  }

  async modify(changes: Partial<T> | ((item: T) => void)): Promise<number> {
    const entries = this.resolveEntries();
    entries.forEach(({ key, value }) => {
      const next = ensureObject(value);
      if (typeof changes === 'function') {
        changes(next);
      } else {
        Object.assign(next, changes);
      }
      this.table.replaceBySerializedKey(key, next);
    });
    return entries.length;
  }

  async sortBy(field: keyof T | string): Promise<T[]> {
    const rows = await this.toArray();
    rows.sort((a, b) => compareValues((a as any)[field], (b as any)[field]));
    return rows;
  }

  // Dexie compatibility guard: fail fast for unsupported query operators.
  offset(): never {
    throw new Error('[InMemoryLocalDB] Unsupported Dexie API: Collection.offset()');
  }

  until(): never {
    throw new Error('[InMemoryLocalDB] Unsupported Dexie API: Collection.until()');
  }

  startsWithIgnoreCase(): never {
    throw new Error('[InMemoryLocalDB] Unsupported Dexie API: Collection.startsWithIgnoreCase()');
  }

  equalsIgnoreCase(): never {
    throw new Error('[InMemoryLocalDB] Unsupported Dexie API: Collection.equalsIgnoreCase()');
  }

  or(): never {
    throw new Error('[InMemoryLocalDB] Unsupported Dexie API: Collection.or()');
  }

  keys(): never {
    throw new Error('[InMemoryLocalDB] Unsupported Dexie API: Collection.keys()');
  }

  primaryKeys(): never {
    throw new Error('[InMemoryLocalDB] Unsupported Dexie API: Collection.primaryKeys()');
  }

  each(): never {
    throw new Error('[InMemoryLocalDB] Unsupported Dexie API: Collection.each()');
  }
}

class InMemoryTable<T extends Record<string, any>> {
  private readonly rows = new Map<string, T>();

  constructor(
    public readonly name: string,
    private readonly keyPath: KeyPath = 'id'
  ) {}

  private deriveKeyFromRecord(record: T): unknown {
    if (Array.isArray(this.keyPath)) {
      return this.keyPath.map((path) => record[path]);
    }
    return record[this.keyPath];
  }

  private ensureRecordKey(record: T): unknown {
    let key = this.deriveKeyFromRecord(record);
    if (Array.isArray(this.keyPath)) {
      return key;
    }
    if (key === undefined || key === null || key === '') {
      key = typeof crypto !== 'undefined' && typeof crypto.randomUUID === 'function'
        ? crypto.randomUUID()
        : nanoid();
      (record as any)[this.keyPath] = key;
    }
    return key;
  }

  private serializeRecord(record: T): string {
    const key = this.ensureRecordKey(record);
    return serializeKey(key);
  }

  private serializeInputKey(key: unknown): string {
    return serializeKey(key);
  }

  entries(): Array<{ key: string; value: T }> {
    return Array.from(this.rows.entries()).map(([key, value]) => ({ key, value }));
  }

  deleteBySerializedKey(serializedKey: string): void {
    this.rows.delete(serializedKey);
  }

  replaceBySerializedKey(oldSerializedKey: string, value: T): void {
    const nextSerializedKey = this.serializeRecord(value);
    if (nextSerializedKey !== oldSerializedKey) {
      this.rows.delete(oldSerializedKey);
    }
    this.rows.set(nextSerializedKey, value);
  }

  async add(record: T): Promise<any> {
    const value = ensureObject(record);
    const serialized = this.serializeRecord(value);
    if (this.rows.has(serialized)) {
      throw new Error(`[InMemoryLocalDB] Duplicate key on add: ${this.name}`);
    }
    this.rows.set(serialized, value);
    return this.deriveKeyFromRecord(value);
  }

  async put(record: T): Promise<any> {
    const value = ensureObject(record);
    const serialized = this.serializeRecord(value);
    this.rows.set(serialized, value);
    return this.deriveKeyFromRecord(value);
  }

  async bulkPut(records: T[]): Promise<void> {
    for (const record of records) {
      await this.put(record);
    }
  }

  bulkAdd(): never {
    throw new Error('[InMemoryLocalDB] Unsupported Dexie API: Table.bulkAdd()');
  }

  bulkGet(): never {
    throw new Error('[InMemoryLocalDB] Unsupported Dexie API: Table.bulkGet()');
  }

  async get(key: unknown): Promise<T | undefined> {
    const found = this.rows.get(this.serializeInputKey(key));
    return found ? ensureObject(found) : undefined;
  }

  async update(key: unknown, changes: Partial<T>): Promise<number> {
    const serialized = this.serializeInputKey(key);
    const current = this.rows.get(serialized);
    if (!current) return 0;
    const next = { ...current, ...changes };
    this.replaceBySerializedKey(serialized, next as T);
    return 1;
  }

  async delete(key: unknown): Promise<void> {
    this.rows.delete(this.serializeInputKey(key));
  }

  async bulkDelete(keys: unknown[]): Promise<void> {
    keys.forEach((key) => this.rows.delete(this.serializeInputKey(key)));
  }

  async clear(): Promise<void> {
    this.rows.clear();
  }

  async count(): Promise<number> {
    return this.rows.size;
  }

  async toArray(): Promise<T[]> {
    return Array.from(this.rows.values()).map((value) => ensureObject(value));
  }

  where(index: string | Record<string, any>): InMemoryCollection<T> {
    if (typeof index === 'string') {
      return new InMemoryCollection<T>(this, [], parseIndexKeys(index), null, false, null);
    }

    const query = Object.entries(index).reduce(
      (collection, [key, value]) => collection.and((item) => isEqual(item[key], value)),
      new InMemoryCollection<T>(this)
    );
    return query;
  }

  filter(predicate: Predicate<T>): InMemoryCollection<T> {
    return new InMemoryCollection<T>(this).filter(predicate);
  }

  orderBy(index: string): InMemoryCollection<T> {
    return new InMemoryCollection<T>(this, [], null, parseIndexKeys(index), false, null);
  }

  toCollection(): InMemoryCollection<T> {
    return new InMemoryCollection<T>(this);
  }
}

const normalizeFolderWithSilent = (raw: unknown) => {
  if (!raw) return raw;
  const hasSilent = raw?.silent !== undefined;
  const hasIsSilent = raw?.isSilent !== undefined || raw?.is_silent !== undefined;
  const normalizedInput = !hasIsSilent && hasSilent
    ? { ...raw, isSilent: raw.silent }
    : raw;
  return normalizeFolder(normalizedInput);
};

const SYNCABLE_TABLES = new Set(['cards', 'folders', 'cardRelations', 'projectMaps']);

const ENTITY_MAP: Record<string, SyncQueueItem['entity']> = {
  cards: 'card',
  folders: 'folder',
  cardRelations: 'cardRelation',
  projectMaps: 'projectMap',
};

export class InMemoryLocalDB {
  public readonly name: string;
  public version: number = 0; // Add version as well just in case
  public readonly isInMemoryFallback = true;
  public userId?: string;

  folders!: InMemoryTable<any>;
  cards!: InMemoryTable<any>;
  documents!: InMemoryTable<any>;
  users!: InMemoryTable<any>;
  userSettings!: InMemoryTable<any>;
  userStats!: InMemoryTable<any>;
  syncMetadata!: InMemoryTable<any>;
  levelHistories!: InMemoryTable<any>;
  deviceMeta!: InMemoryTable<any>;
  syncErrors!: InMemoryTable<any>;
  syncHistory!: InMemoryTable<any>;
  syncSettings!: InMemoryTable<any>;
  syncQueue!: InMemoryTable<any>;
  conflicts!: InMemoryTable<any>;
  metadata!: InMemoryTable<any>;
  images!: InMemoryTable<any>;
  cardRelations!: InMemoryTable<any>;
  projectMaps!: InMemoryTable<any>;
  tags!: InMemoryTable<any>;
  tags_v2!: InMemoryTable<any>;
  tags_v3!: InMemoryTable<any>;

  tables: InMemoryTable<any>[] = [];
  private readonly tableMap = new Map<string, InMemoryTable<any>>();
  private opened = true;
  private syncTrigger: (() => void) | null = null;

  constructor(userId?: string, name?: string) {
    this.userId = userId;
    this.name = name ?? `FlashcardMasterDB_mem_${userId ?? 'anonymous'}`;

    this.folders = this.registerTable('folders', 'id');
    this.cards = this.registerTable('cards', 'id');
    this.documents = this.registerTable('documents', 'id');
    this.users = this.registerTable('users', 'id');
    this.userSettings = this.registerTable('userSettings', 'id');
    this.userStats = this.registerTable('userStats', 'id');
    this.syncMetadata = this.registerTable('syncMetadata', 'userId');
    this.levelHistories = this.registerTable('levelHistories', 'id');
    this.deviceMeta = this.registerTable('deviceMeta', 'deviceId');
    this.syncErrors = this.registerTable('syncErrors', 'id');
    this.syncHistory = this.registerTable('syncHistory', 'id');
    this.syncSettings = this.registerTable('syncSettings', 'id');
    this.syncQueue = this.registerTable('syncQueue', 'id');
    this.conflicts = this.registerTable('conflicts', 'id');
    this.metadata = this.registerTable('metadata', 'key');
    this.images = this.registerTable('images', 'id');
    this.cardRelations = this.registerTable('cardRelations', 'id');
    this.projectMaps = this.registerTable('projectMaps', 'id');
    this.tags = this.registerTable('tags', ['rootFolderId', 'name']);
    this.tags_v2 = this.registerTable('tags_v2', ['userId', 'name']);
    this.tags_v3 = this.registerTable('tags_v3', 'id');
    this.registerTable('studyLogs', 'id');
  }

  private registerTable(name: string, keyPath: KeyPath): InMemoryTable<any> {
    const table = new InMemoryTable(name, keyPath);
    this.tableMap.set(name, table);
    this.tables.push(table);
    return table;
  }

  table(name: string): InMemoryTable<any> {
    const table = this.tableMap.get(name);
    if (!table) {
      throw new Error(`[InMemoryLocalDB] Unknown table requested: ${name}`);
    }
    return table;
  }

  async open(): Promise<this> {
    this.opened = true;
    return this;
  }

  isOpen(): boolean {
    return this.opened;
  }

  close(): void {
    this.opened = false;
  }

  async delete(): Promise<void> {
    // Simulate DB deletion (clearing in-memory state)
    this.version = 0;
    this.tables.forEach(t => t.clear());
    this.opened = false;
    return Promise.resolve();
  }

  async transaction<T>(mode: string, ...args: unknown[]): Promise<T> {
    // InMemoryLocalDB はロックなしで即時実行。
    // Dexie 互換の可変引数スタイル (mode, table1, table2, ..., scope) に対応。
    const scope = args[args.length - 1] as () => Promise<T> | T;
    return await scope();
  }

  async getItem(tableName: string, id: string): Promise<any> {
    const item = await this.table(tableName).get(id);
    if (tableName === 'cards') return item ? normalizeCard(item) : item;
    if (tableName === 'folders') return item ? normalizeFolderWithSilent(item) : item;
    return item;
  }

  async getAllItems(tableName: string): Promise<any[]> {
    const items = await this.table(tableName).toArray();
    if (tableName === 'cards') return items.map(normalizeCard);
    if (tableName === 'folders') return items.map(normalizeFolderWithSilent);
    return items;
  }

  private async enqueueSync(tableName: string, payload: unknown): Promise<void> {
    if (!SYNCABLE_TABLES.has(tableName)) return;
    const now = Date.now();
    const task: SyncQueueItem = {
      id: nanoid(),
      idempotencyKey: nanoid(),
      targetId: payload.id,
      type: 'upload',
      entity: ENTITY_MAP[tableName],
      operationType: 'update',
      payload,
      priority: 'high',
      createdAt: now,
      updatedAt: now,
      status: 'pending',
      retryCount: 0,
    };

    await this.syncQueue.put(task as any);
    if (this.syncTrigger) {
      setTimeout(() => this.syncTrigger?.(), 0);
    }
  }

  async addItem(tableName: string, item: unknown, skipSync = false): Promise<string> {
    const payload = ensureObject(item);
    const id = await this.table(tableName).add(payload);
    if (!skipSync) await this.enqueueSync(tableName, payload);
    return String(id ?? payload.id);
  }

  async updateItem(tableName: string, id: string, changes: object, skipSync = false): Promise<number> {
    const result = await this.table(tableName).update(id, changes as any);
    if (!skipSync && result > 0) {
      const fullItem = await this.table(tableName).get(id);
      if (fullItem) await this.enqueueSync(tableName, fullItem);
    }
    return result;
  }

  async deleteItem(tableName: string, id: string): Promise<void> {
    await this.table(tableName).delete(id);
  }

  async softDelete(tableName: string, id: string): Promise<number> {
    return this.updateItem(tableName, id, { isDeleted: true, deletedAt: new Date(), updatedAt: new Date() });
  }

  async restore(tableName: string, id: string): Promise<number> {
    return this.updateItem(tableName, id, { isDeleted: false, deletedAt: null, updatedAt: new Date() });
  }

  async purge(tableName: string, id: string): Promise<void> {
    await this.deleteItem(tableName, id);
  }

  async bulkUpsert(tableName: string, items: unknown[], skipSync = false): Promise<void> {
    if (!Array.isArray(items) || items.length === 0) return;
    await this.table(tableName).bulkPut(items as any[]);
    if (!skipSync) {
      for (const item of items) {
        await this.enqueueSync(tableName, item);
      }
    }
  }

  async clearTable(tableName: string): Promise<void> {
    await this.table(tableName).clear();
  }

  async getAllCards(): Promise<Card[]> {
    const cards = await this.cards.toArray();
    return cards.map(normalizeCard) as Card[];
  }

  async getAllFolders(): Promise<Folder[]> {
    const folders = await this.folders.toArray();
    return folders.map(normalizeFolderWithSilent) as Folder[];
  }

  async getLastSyncTime(userId: string): Promise<Date | null> {
    const meta = await this.syncMetadata.get(userId);
    if (!meta?.lastSyncTime) return null;
    const value = meta.lastSyncTime;
    if (value instanceof Date) return value;
    if (value && typeof value?.toDate === 'function') return value.toDate();
    return new Date(value);
  }

  async updateLastSyncTime(userId: string, syncTime: Date): Promise<void> {
    await this.syncMetadata.put({
      userId,
      deviceId: getOrCreateDeviceId(),
      deviceName: getDeviceName(),
      lastSyncTime: syncTime,
      lastHighResSync: null,
      isActive: true,
    });
  }

  async getDirtyItems(tableName: string, userId: string, lastSyncTime: Date): Promise<any[]> {
    const rows = await this.table(tableName).toArray();
    const threshold = toTimestamp(lastSyncTime);
    return rows.filter((row) => row.userId === userId && toTimestamp(row.updatedAt) >= threshold);
  }

  async clearAllData(): Promise<void> {
    await Promise.all(this.tables.map((table) => table.clear()));
  }

  async cleanupSyncHistory(): Promise<void> {
    const now = Date.now();
    const THIRTY_DAYS = 30 * 24 * 60 * 60 * 1000;
    await this.syncHistory.where('finishedAt').below(now - THIRTY_DAYS).delete();
    const all = await this.syncHistory.orderBy('finishedAt').toArray();
    if (all.length > 100) {
      const toDelete = all.slice(0, all.length - 100).map((item: unknown) => item.id);
      await this.syncHistory.bulkDelete(toDelete);
    }
  }

  async cleanupSyncErrors(): Promise<void> {
    const now = Date.now();
    const SEVEN_DAYS = 7 * 24 * 60 * 60 * 1000;
    const oldErrors = await this.syncErrors
      .where('occurredAt')
      .below(now - SEVEN_DAYS)
      .and((item: unknown) => !item.retryable)
      .toArray();
    await this.syncErrors.bulkDelete(oldErrors.map((item: unknown) => item.id));
  }

  async getDeviceMeta(userId: string): Promise<any | undefined> {
    return this.deviceMeta.where('userId').equals(userId).first();
  }

  async upsertDeviceMeta(meta: unknown): Promise<void> {
    await this.deviceMeta.put(meta);
  }

  async getSyncEnabledFolders(userId: string): Promise<any[]> {
    return this.folders.where('userId').equals(userId).and((folder: unknown) => folder.cloudSyncEnabled === true).toArray();
  }

  async getUpdatedCards(folderId: string, lastSyncTime: Date): Promise<any[]> {
    const threshold = toTimestamp(lastSyncTime);
    return this.cards
      .where('folderId')
      .equals(folderId)
      .and((card: unknown) => toTimestamp(card.updatedAt) > threshold)
      .toArray();
  }

  async upsert(tableName: string, data: unknown, skipSync = false): Promise<void> {
    await this.table(tableName).put(data);
    if (!skipSync) await this.enqueueSync(tableName, data);
  }

  setSyncTrigger(callback: () => void): void {
    this.syncTrigger = callback;
  }

  async importFromDatabase(
    _sourceDbName: string,
    _currentUserId: string,
    _onProgress?: (progress: string) => void
  ): Promise<{ cards: number; folders: number; stats: number; studyLogs: number; firstCardKeys: string[] }> {
    throw new Error('Local fallback mode: database import is unavailable.');
  }

  async extractFromFirestoreSDK(
    _sourceDbName: string,
    _currentUserId: string,
    _onProgress?: (progress: string) => void
  ): Promise<{ cards: number; folders: number; firstCardKeys: string[] }> {
    throw new Error('Local fallback mode: Firestore cache extraction is unavailable.');
  }

  async repairDataIntegrity(
    _currentUserId: string,
    _onProgress?: (msg: string) => void
  ): Promise<{ folders: number; cards: number; canonicalId: string | null; issues: unknown[] }> {
    return { folders: 0, cards: 0, canonicalId: null, issues: [] };
  }
}

import { getLocalDb } from './localDB';
import { Dexie } from 'dexie';
import { CloudSyncAdapter } from './logic/CloudSyncAdapter';
import { sanitizeForLog } from '@/utils/logSanitizer';
import { sanitizeBlobUrlsDeep, type BlobUrlFix } from '@/utils/blobUrlSanitizer';

/**
 * IndexedDB 再構築オーケストレーター
 * 
 * 責務:
 * - IndexedDB の破棄（呼び出し元で実行済み）
 * - クラウドからの再同期
 */
export class IndexedDBRebuildOrchestrator {
  private static isRebuilding = false;

  static isSupportedType(type: string): boolean {
    return type === 'card' || type === 'folder' || type === 'cardRelation' || type === 'projectMap';
  }

  private static tableFromType(type: string): string {
    return `${type}s`;
  }

  /**
   * IndexedDB を再構築
   * 
   * @param userId ユーザーID
   * @param reason 再構築理由
   * @param onProgress 進捗コールバック
   */
  static async rebuild(
    userId: string,
    reason?: string,
    onProgress?: (msg: string) => void
  ): Promise<{
    success: boolean;
    degraded: boolean;
    failures: Array<{ type: string; id: string; error: string; fixes?: BlobUrlFix[] }>;
    insertedCount: number;
  }> {
    if (this.isRebuilding) {
      console.warn('[Rebuild] Rebuild already in progress. Skipping.');
      return { success: true, degraded: false, failures: [], insertedCount: 0 };
    }

    if (!userId) {
      const msg = '[Rebuild] Missing userId. Cannot rebuild.';
      console.error(msg);
      throw new Error(msg);
    }
    
    this.isRebuilding = true;

    try {
      console.log(`[Rebuild:${userId}] Starting rebuild... Reason: ${reason || 'unknown'}`);
      onProgress?.('クラウドからデータを取得しています...');
      
      // 1. クラウドから最新データを先に取得（DB削除前にデータ確保）
      const adapter = new CloudSyncAdapter(userId);
      // 0を指定して全データを取得（フル同期）
      const { changes } = await adapter.pullDiff(0);
      
      if (changes.length === 0) {
        console.log(`[Rebuild:${userId}] No data found in cloud. Skipping destructive rebuild.`);
        onProgress?.('クラウドにデータはありませんでした。');
        return { success: true, degraded: false, failures: [], insertedCount: 0 };
      }

      onProgress?.('データベースを再構築中...');

      // 2. 既存のDB接続を完全に閉じる
      const oldDb = await getLocalDb(userId);
      if (oldDb) {
        oldDb.close();
      }
      
      // 3. インスタンスキャッシュをクリア (LocalDB側のstaticメソッド)
      // これをしないと、LocalDB.getInstance() は閉じた古いインスタンスを返し続けてしまう
      const LocalDBClass = (await import('./localDB')).LocalDB;
      LocalDBClass.clearInstance();

      // 4. 物理的に削除 (Dexie.delete)
      const dbName = oldDb?.name || (LocalDBClass as any).getDatabaseNameForUser?.(userId) || `FlashcardMasterDB_${userId}`;
      console.log(`[Rebuild] Deleting database: ${dbName}`);
      await Dexie.delete(dbName);

      // 5. 新しいインスタンスを作成
      console.log('[Rebuild] Creating new DB instance...');
      const newDb = await getLocalDb(userId);

      onProgress?.(`${changes.length} 件のデータを復元中...`);
      
      // 6. 新しいDBにデータを流し込む
      const failures: Array<{ type: string; id: string; error: string; fixes?: BlobUrlFix[] }> = [];
      let insertedCount = 0;
      await newDb.transaction('rw',
        [newDb.folders, newDb.cards, newDb.users, newDb.userSettings, newDb.userStats, newDb.syncMetadata, newDb.levelHistories, newDb.deviceMeta, (newDb as any).tags, (newDb as any).cardRelations, (newDb as any).projectMaps],
        async () => {
          console.log(`[Rebuild] Inserting ${changes.length} items to fresh DB...`);
          for (const change of changes) {
            if (!this.isSupportedType(change.type)) continue;
            const table = this.tableFromType(change.type);
            const sanitizeResult = sanitizeBlobUrlsDeep(change.data);
            if (sanitizeResult.changed) {
              console.warn('[Rebuild] sanitize_blob_url', sanitizeForLog({
                type: change.type,
                id: change.id,
                fixes: sanitizeResult.fixes,
              }));
            }

            try {
              await newDb.upsert(table as any, sanitizeResult.value, true);
              insertedCount += 1;
            } catch (error) {
              const itemFailure = {
                type: change.type,
                id: change.id ?? sanitizeResult.value?.id ?? 'unknown',
                error: error instanceof Error ? error.message : String(error),
                fixes: sanitizeResult.changed ? sanitizeResult.fixes : undefined,
              };
              failures.push(itemFailure);
              console.error('[Rebuild] rebuild_item_failed', sanitizeForLog(itemFailure));
              continue;
            }
          }
        }
      );
      if (failures.length > 0) {
        console.error('[Rebuild] rebuild_partial_failures', sanitizeForLog({
          count: failures.length,
          failures: failures.slice(0, 20),
        }));
      }
      
      // 7. メタデータサービスでCLEANマークをつける（オプションだが推奨）
      // 循環参照回避のためダイナミックインポート
      try {
        const { IndexedDBMetadataService } = await import('./IndexedDBMetadataService');
        const metaService = new IndexedDBMetadataService(newDb, userId);
        await metaService.markClean();
      } catch (e) {
        console.warn('[Rebuild] Failed to mark clean state', e);
      }

      console.log(`[Rebuild:${userId}] Rebuild complete with ${insertedCount}/${changes.length} items.`);
      onProgress?.('再構築が完了しました');
      return {
        success: true,
        degraded: failures.length > 0,
        failures,
        insertedCount,
      };
      
    } catch (error) {
      console.error(`[Rebuild:${userId}] Rebuild failed:`, error);
      onProgress?.('再構築に失敗しました。');
      throw error;
    } finally {
      this.isRebuilding = false;
    }
  }
}

import type { Notification, NotificationLevel, NotificationOptions } from '../types/notification';

/**
 * 通知サービス
 * 
 * エラーレベルに応じた通知を管理する
 * - INFO: 状態通知（自動で消える／邪魔しない）
 * - WARNING: 放置すると困る（閉じられる／軽い行動導線）
 * - ERROR: 続行不可（明確なアクション必須）
 */
class NotificationService {
  private listeners: Set<(notification: Notification) => void> = new Set();
  private notifications: Map<string, Notification> = new Map();

  /**
   * 通知リスナーを追加
   */
  subscribe(listener: (notification: Notification) => void): () => void {
    this.listeners.add(listener);
    return () => this.listeners.delete(listener);
  }

  /**
   * 通知を発行
   */
  private notify(notification: Notification): void {
    this.notifications.set(notification.id, notification);
    this.listeners.forEach(listener => listener(notification));
  }

  /**
   * INFO レベルの通知
   * 
   * 特徴:
   * - 自動で消える
   * - 邪魔しない
   * - ユーザーの操作不要
   */
  info(title: string, message: string, options?: NotificationOptions): void {
    const notification: Notification = {
      id: `info-${Date.now()}`,
      level: 'info',
      title,
      message,
      details: options?.details,
      timestamp: Date.now(),
      autoClose: options?.autoClose ?? true,
      closeable: false,
      duration: options?.duration ?? 5000, // デフォルト5秒
    };

    this.notify(notification);
  }

  /**
   * WARNING レベルの通知
   * 
   * 特徴:
   * - 閉じられる
   * - 軽い行動導線
   * - 放置すると困る
   */
  warning(title: string, message: string, options?: NotificationOptions): void {
    const notification: Notification = {
      id: `warning-${Date.now()}`,
      level: 'warning',
      title,
      message,
      details: options?.details,
      timestamp: Date.now(),
      autoClose: false,
      closeable: options?.closeable ?? true,
      actions: options?.actions,
    };

    this.notify(notification);
  }

  /**
   * ERROR レベルの通知
   * 
   * 特徴:
   * - 明確なアクション必須
   * - 続行不可
   * - 閉じられない
   */
  error(title: string, message: string, options?: NotificationOptions): void {
    const notification: Notification = {
      id: `error-${Date.now()}`,
      level: 'error',
      title,
      message,
      details: options?.details,
      timestamp: Date.now(),
      autoClose: false,
      closeable: false,
      actions: options?.actions ?? [
        {
          label: 'サポートに連絡',
          onClick: () => {
            // サポート連絡処理
            window.open('mailto:support@example.com', '_blank');
          },
          primary: true,
        },
      ],
    };

    this.notify(notification);
  }

  /**
   * 通知を削除
   */
  dismiss(id: string): void {
    this.notifications.delete(id);
    // リスナーに削除を通知（null を送る）
    this.listeners.forEach(listener => listener({ id } as any));
  }

  /**
   * 全ての通知を取得
   */
  getAll(): Notification[] {
    return Array.from(this.notifications.values());
  }
}

// シングルトンインスタンス
export const notificationService = new NotificationService();

import pLimit from 'p-limit';
import { strictValidateBeforeSave } from '@/utils/imageValidation';
import type { UploadedImage } from '@/types';
import { imageDB } from '@/services/ImageDatabaseWriter';
import * as Sentry from '@sentry/react';


/**
 * 順序保証付き並列アップロード
 */
class OrderedUploadQueue {
  private queue: Array<{ file: File; image: UploadedImage; order: number }> = [];
  private completedOrders = new Set<number>();
  
  /**
   * アップロードタスクを追加（順序番号付き）
   */
  enqueue(file: File, image: UploadedImage, order: number): void {
    this.queue.push({ file, image, order });
    console.log(`[OrderedUpload] Enqueued order ${order} (Total: ${this.queue.length})`);
  }
  
  /**
   * 並列アップロード（p-limit + 順序保証）
   */
  async processWithOrder(
    concurrency: number = 2,
    uploadFn: (file: File, image: UploadedImage) => Promise<UploadedImage>
  ): Promise<void> {
    const limit = pLimit(concurrency);
    
    const tasks = this.queue.map((item) =>
      limit(async () => {
        try {
          // 1. アップロード処理
          const updatedImage = await uploadFn(item.file, item.image);
          
          // 2. バリデーション
          strictValidateBeforeSave(updatedImage);
          
          // 3. DB 保存（順序番号を記録）
          await imageDB.saveToFirestore({ ...updatedImage, uploadOrder: item.order });
          
          // 4. 完了記録
          this.completedOrders.add(item.order);
          
          console.log(`[OrderedUpload] Completed order ${item.order}`);
        } catch (error) {
          console.error(`[OrderedUpload] Failed order ${item.order}`, error);
          
          // エラー時はコンソールに記録(Sentryは本番環境で自動的にキャプチャ)
          throw error;
        }
      })
    );
    
    await Promise.allSettled(tasks);
    
    // 順序の整合性チェック
    const expectedOrders = this.queue.map(item => item.order).sort((a, b) => a - b);
    const missingOrders = expectedOrders.filter(order => !this.completedOrders.has(order));
    
    if (missingOrders.length > 0) {
      console.error(`[OrderedUpload] Missing orders: ${missingOrders.join(', ')}`);
      
      // Sentry に報告(本番環境で自動キャプチャ)
      if (import.meta.env.PROD) {
        console.error('[OrderedUpload] Upload order integrity violation', { missingOrders });
      }
    }
  }
  
  /**
   * キューをクリア
   */
  clear(): void {
    this.queue = [];
    this.completedOrders.clear();
    console.log('[OrderedUpload] Queue cleared');
  }
  
  /**
   * 完了状況を取得
   */
  getStatus(): { total: number; completed: number; pending: number } {
    return {
      total: this.queue.length,
      completed: this.completedOrders.size,
      pending: this.queue.length - this.completedOrders.size,
    };
  }
}

/**
 * 順序保証付きアップロードキューの統一インスタンス
 */
export const orderedUploadQueue = new OrderedUploadQueue();

import { strictValidateBeforeSave } from '@/utils/imageValidation';
import type { UploadedImage } from '@/types';
import { getLocalDb, isBackingStoreOpenError } from '@/services/localDB';
import { warnOncePerSession } from '@/services/localDBRuntimeState';
import { auth } from '@/services/firebase';

interface QueueItem {
  id: string;
  image: UploadedImage;
  fileData: ArrayBuffer;
  fileName: string;
  fileType: string;
  retryCount: number;
  enqueuedAt: number;
}

/**
 * 永続化されたオフラインキュー
 */
class PersistentOfflineQueue {
  private readonly PPTX_MIME = 'application/vnd.openxmlformats-officedocument.presentationml.presentation';
  private readonly DB_NAME = 'offline_upload_queue';
  private readonly STORE_NAME = 'pending_uploads';
  private isProcessing = false;
  private idbUnavailable = false;
  private readonly memoryQueue = new Map<string, QueueItem>();

  private requestToPromise<T>(request: IDBRequest<T>): Promise<T> {
    return new Promise<T>((resolve, reject) => {
      request.onsuccess = () => resolve(request.result);
      request.onerror = () => reject(request.error);
    });
  }

  private isPdfQueueItem(item: QueueItem | { fileType: string; fileName: string }): boolean {
    return item.fileType === 'application/pdf'
      || (typeof item.fileName === 'string' && item.fileName.toLowerCase().endsWith('.pdf'));
  }

  private isPptxQueueItem(item: QueueItem | { fileType: string; fileName: string }): boolean {
    return item.fileType === this.PPTX_MIME
      || (typeof item.fileName === 'string' && item.fileName.toLowerCase().endsWith('.pptx'));
  }

  private isDocumentQueueItem(item: QueueItem | { fileType: string; fileName: string }): boolean {
    return this.isPdfQueueItem(item) || this.isPptxQueueItem(item);
  }

  private getDocumentKindLabel(item: QueueItem | { fileType: string; fileName: string }): 'PDF' | 'PPTX' | 'DOC' {
    if (this.isPdfQueueItem(item)) return 'PDF';
    if (this.isPptxQueueItem(item)) return 'PPTX';
    return 'DOC';
  }

  private isDocumentUploadReady(doc: unknown): boolean {
    if (!doc) return false;
    if (doc.uploadStatus === 'ready') return true;
    if (typeof doc.remoteUrl === 'string' && doc.remoteUrl.trim().length > 0) return true;
    if (typeof doc.downloadUrl === 'string' && doc.downloadUrl.trim().length > 0) return true;
    return false;
  }

  private async getQueueItem(id: string): Promise<QueueItem | null> {
    if (!id) return null;
    if (this.idbUnavailable) {
      return this.memoryQueue.get(id) ?? null;
    }

    try {
      const db = await this.openDB();
      const tx = db.transaction(this.STORE_NAME, 'readonly');
      const store = tx.objectStore(this.STORE_NAME);
      const item = await this.requestToPromise(store.get(id));
      return (item as QueueItem | undefined) ?? null;
    } catch (error) {
      this.activateMemoryFallback(error);
      return this.memoryQueue.get(id) ?? null;
    }
  }
  
  /**
   * キューに追加（IndexedDB に永続化）
   */
  async enqueue(image: UploadedImage, file: File): Promise<void> {
    // File を ArrayBuffer に変換して保存（tx作成前に完了させる）
    const arrayBuffer = await file.arrayBuffer();

    const payload: QueueItem = {
      id: image.id,
      image,
      fileData: arrayBuffer,
      fileName: file.name,
      fileType: file.type,
      retryCount: 0,
      enqueuedAt: Date.now(),
    };

    const existing = await this.getQueueItem(payload.id);
    if (existing) {
      console.info('[PersistentQueue] Deduplicating enqueue by document id', {
        id: payload.id,
        previousFileName: existing.fileName,
        incomingFileName: payload.fileName,
      });
    }

    if (this.idbUnavailable) {
      this.memoryQueue.set(payload.id, payload);
      console.log(`[PersistentQueue] Enqueued in memory fallback: ${file.name}`);
      return;
    }

    try {
      const db = await this.openDB();
      // ✅ tx作成〜store.putまでの間に await を挟まない
      await new Promise<void>((resolve, reject) => {
        const tx = db.transaction(this.STORE_NAME, 'readwrite');
        const store = tx.objectStore(this.STORE_NAME);
        const req = store.put(payload);

        req.onerror = () => reject(req.error);
        tx.oncomplete = () => resolve();
        tx.onerror = () => reject(tx.error ?? req.error);
        tx.onabort = () => reject(tx.error ?? req.error ?? new Error('IDB tx aborted'));
      });
    } catch (error) {
      this.activateMemoryFallback(error);
      this.memoryQueue.set(payload.id, payload);
      console.log(`[PersistentQueue] Enqueued in memory fallback after IDB error: ${file.name}`);
      return;
    }

    console.log(`[PersistentQueue] Enqueued: ${file.name}`);
  }
  
  /**
   * キューを処理（アプリ起動時に自動実行）
   */
  async processQueue(
    uploadFn: (file: File, image: UploadedImage) => Promise<UploadedImage>
  ): Promise<void> {
    if (this.isProcessing) {
      console.log('[PersistentQueue] Already processing');
      return;
    }
    
    this.isProcessing = true;
    
    try {
      const items = await this.getAllItems();
      
      console.log(`[PersistentQueue] Processing ${items.length} items`);
      
      for (const item of items) {
        try {
          if (this.isDocumentQueueItem(item)) {
            try {
              const localDb = await getLocalDb();
              const existingDoc = await localDb.documents.get(item.id);
              if (this.isDocumentUploadReady(existingDoc)) {
                console.info('[PersistentQueue] Skip queued document upload because item is already ready', {
                  docId: item.id,
                  fileName: item.fileName,
                  kind: this.getDocumentKindLabel(item),
                  uploadStatus: existingDoc?.uploadStatus ?? null,
                });
                await this.dequeue(item.id);
                continue;
              }
            } catch (guardErr) {
              console.warn('[PersistentQueue] readiness guard check failed; continuing upload attempt', guardErr);
            }
          }

          // ArrayBuffer から File を復元
          const file = new File([item.fileData], item.fileName, { type: item.fileType });
          
          // アップロード処理
          const updatedImage = await uploadFn(file, item.image);
          if (!updatedImage.remoteUrl) {
            throw new Error('[PersistentQueue] Upload finished without remoteUrl');
          }
          
          // バリデーション
          strictValidateBeforeSave(updatedImage);
          
          // DB 更新
          const { imageDB } = await import('@/services/ImageDatabaseWriter');
          const firestoreTarget = imageDB.resolveFirestoreTarget(updatedImage);
          if (imageDB.isFirestoreDiagnosticsEnabled()) {
            console.info('[PersistentQueue] Firestore image write attempt', {
              operation: 'setDoc',
              path: firestoreTarget.path,
              uid: firestoreTarget.uid,
              queueItemId: item.id,
              fileName: item.fileName,
            });
          }
          try {
            await imageDB.saveToFirestore(updatedImage);
          } catch (writeErr) {
            if (imageDB.isFirestoreDiagnosticsEnabled()) {
              console.error('[PersistentQueue] Firestore image write rejected', {
                operation: 'setDoc',
                path: firestoreTarget.path,
                uid: firestoreTarget.uid,
                queueItemId: item.id,
                fileName: item.fileName,
                error: writeErr,
              });
            } else {
              console.error('[PersistentQueue] Firestore image write rejected', {
                operation: 'setDoc',
                queueItemId: item.id,
                fileName: item.fileName,
                error: writeErr,
              });
            }
            throw writeErr;
          }

          // ドキュメント（PDF/PPTX）の場合は documents テーブルも更新（remoteUrl反映）
          const isDocumentItem = this.isDocumentQueueItem(item);
          const isAssetLikeImageItem = !isDocumentItem && item.fileType.startsWith('image/');
          if (isDocumentItem) {
            const localDb = await getLocalDb();
            const existingDoc = await localDb.documents.get(updatedImage.id);
            if (existingDoc) {
              await localDb.updateItem('documents', updatedImage.id, {
                remoteUrl: updatedImage.remoteUrl,
                downloadUrl: updatedImage.remoteUrl,
                storagePath: updatedImage.storagePath ?? existingDoc.storagePath ?? null,
                uploadStatus: 'ready',
                updatedAt: new Date(),
              });
              const refreshedDoc = await localDb.documents.get(updatedImage.id);
              console.info('[PersistentQueue] Document sync success with local source retained', {
                docId: updatedImage.id,
                kind: this.getDocumentKindLabel(item),
                localFileId: refreshedDoc?.localFileId ?? null,
                blobUrl: (refreshedDoc as any)?.blobUrl ?? refreshedDoc?.localUrl ?? null,
                remoteUrl: refreshedDoc?.remoteUrl ?? null,
                uploadStatus: refreshedDoc?.uploadStatus ?? null,
              });
            }
          }

          if (isAssetLikeImageItem) {
            const localDb = await getLocalDb();
            const existingAsset = await localDb.images.get(updatedImage.id);
            const now = new Date();
            await localDb.images.put({
              ...(existingAsset as any ?? {}),
              id: updatedImage.id,
              userId: auth.currentUser?.uid ?? (existingAsset as any)?.userId ?? '',
              mime: item.fileType || (existingAsset as any)?.mime || 'application/octet-stream',
              size: item.fileData.byteLength ?? (existingAsset as any)?.size ?? 0,
              localBlobId: (existingAsset as any)?.localBlobId ?? updatedImage.localFileId ?? updatedImage.id,
              localStatus: (existingAsset as any)?.localStatus ?? 'present',
              remoteKey: updatedImage.storagePath ?? (existingAsset as any)?.remoteKey ?? null,
              remoteStatus: 'ready',
              remoteUrlCache: updatedImage.remoteUrl ?? (existingAsset as any)?.remoteUrlCache ?? null,
              updatedAt: now,
              createdAt: (existingAsset as any)?.createdAt ?? now,
              retryCount: 0,
            } as any);

            const pendingAssetSyncItems = await localDb.syncQueue
              .where('targetId')
              .equals(updatedImage.id)
              .filter((q: unknown) => q.entity === 'asset')
              .toArray();
            if (pendingAssetSyncItems.length > 0) {
              await localDb.syncQueue.bulkDelete(pendingAssetSyncItems.map((q: unknown) => q.id));
            }

            if (import.meta.env.DEV) {
              console.info('[AssetSync] upload success', {
                assetId: updatedImage.id,
                remoteKey: updatedImage.storagePath ?? null,
              });
            }
          }
          
          // キューから削除
          await this.dequeue(item.id);
          
          console.log(`[PersistentQueue] Processed: ${item.fileName}`);
        } catch (error) {
          console.error(`[PersistentQueue] Failed: ${item.fileName}`, error);
          
          // リトライカウントを増やす
          await this.incrementRetryCount(item.id);
          
          // 最大3回までリトライ
          if ((item.retryCount ?? 0) + 1 >= 3) {
            console.error(`[PersistentQueue] Max retries reached: ${item.fileName}`);
            const isDocumentItem = this.isDocumentQueueItem(item);
            const isAssetLikeImageItem = !isDocumentItem && item.fileType.startsWith('image/');
            if (isDocumentItem) {
              try {
                const localDb = await getLocalDb();
                const existingDoc = await localDb.documents.get(item.id);
                if (existingDoc) {
                  if (this.isDocumentUploadReady(existingDoc)) {
                    console.info('[PersistentQueue] Skip failed-mark because document is already ready', {
                      docId: item.id,
                      kind: this.getDocumentKindLabel(item),
                      uploadStatus: existingDoc.uploadStatus ?? null,
                    });
                    await this.dequeue(item.id);
                    continue;
                  }
                  await localDb.updateItem('documents', item.id, {
                    uploadStatus: 'failed',
                    updatedAt: new Date(),
                  });
                  const failedDoc = await localDb.documents.get(item.id);
                  console.error('[PersistentQueue] Document sync failed after retries; local source kept', {
                    docId: item.id,
                    kind: this.getDocumentKindLabel(item),
                    localFileId: failedDoc?.localFileId ?? null,
                    blobUrl: (failedDoc as any)?.blobUrl ?? failedDoc?.localUrl ?? null,
                    remoteUrl: failedDoc?.remoteUrl ?? null,
                    uploadStatus: failedDoc?.uploadStatus ?? null,
                  });
                }
              } catch (docErr) {
                console.warn('[PersistentQueue] Failed to mark document upload as failed', docErr);
              }
            }
            if (isAssetLikeImageItem) {
              try {
                const localDb = await getLocalDb();
                const existingAsset = await localDb.images.get(item.id);
                const now = new Date();
                await localDb.images.put({
                  ...(existingAsset as any ?? {}),
                  id: item.id,
                  userId: auth.currentUser?.uid ?? (existingAsset as any)?.userId ?? '',
                  mime: item.fileType || (existingAsset as any)?.mime || 'application/octet-stream',
                  size: item.fileData.byteLength ?? (existingAsset as any)?.size ?? 0,
                  localBlobId: (existingAsset as any)?.localBlobId ?? item.id,
                  localStatus: (existingAsset as any)?.localStatus ?? 'present',
                  remoteKey: (existingAsset as any)?.remoteKey ?? null,
                  remoteStatus: 'failed',
                  updatedAt: now,
                  createdAt: (existingAsset as any)?.createdAt ?? now,
                  retryCount: (existingAsset as any)?.retryCount ? (existingAsset as any).retryCount + 1 : 1,
                } as any);
                if (import.meta.env.DEV) {
                  console.warn('[AssetSync] upload failed', { assetId: item.id });
                }
              } catch (assetErr) {
                console.warn('[PersistentQueue] Failed to update asset status', assetErr);
              }
            }
            await this.dequeue(item.id);
          }
        }
        
        // UI スレッド占有対策
        await new Promise(resolve => setTimeout(resolve, 0));
      }
    } finally {
      this.isProcessing = false;
    }
  }
  
  /**
   * キューの件数を取得
   */
  async getQueueCount(): Promise<number> {
    if (this.idbUnavailable) {
      return this.memoryQueue.size;
    }

    try {
      const db = await this.openDB();
      const tx = db.transaction(this.STORE_NAME, 'readonly');
      const store = tx.objectStore(this.STORE_NAME);
      return await this.requestToPromise(store.count());
    } catch (error) {
      this.activateMemoryFallback(error);
      return this.memoryQueue.size;
    }
  }
  
  private async openDB(): Promise<IDBDatabase> {
    return new Promise((resolve, reject) => {
      const request = indexedDB.open(this.DB_NAME, 1);
      
      request.onsuccess = () => resolve(request.result);
      request.onerror = () => reject(request.error);
      
      request.onupgradeneeded = (event) => {
        const db = (event.target as IDBOpenDBRequest).result;
        if (!db.objectStoreNames.contains(this.STORE_NAME)) {
          db.createObjectStore(this.STORE_NAME, { keyPath: 'id' });
        }
      };
    });
  }

  private activateMemoryFallback(error: unknown): void {
    if (this.idbUnavailable) return;
    this.idbUnavailable = true;

    const reason = isBackingStoreOpenError(error)
      ? '[PersistentQueue] IndexedDB backing store error detected. Switched to in-memory queue for this session (cleared on reload).'
      : '[PersistentQueue] IndexedDB unavailable. Switched to in-memory queue for this session (cleared on reload).';

    warnOncePerSession('persistent-queue:idb-fallback', reason, error);
  }

  private async getAllItems(): Promise<QueueItem[]> {
    if (this.idbUnavailable) {
      return Array.from(this.memoryQueue.values());
    }

    try {
      const db = await this.openDB();
      const tx = db.transaction(this.STORE_NAME, 'readonly');
      const store = tx.objectStore(this.STORE_NAME);
      const items = await this.requestToPromise(store.getAll());
      return items as QueueItem[];
    } catch (error) {
      this.activateMemoryFallback(error);
      return Array.from(this.memoryQueue.values());
    }
  }
  
  private async dequeue(id: string): Promise<void> {
    if (this.idbUnavailable) {
      this.memoryQueue.delete(id);
      return;
    }

    try {
      const db = await this.openDB();
      const tx = db.transaction(this.STORE_NAME, 'readwrite');
      const store = tx.objectStore(this.STORE_NAME);
      await this.requestToPromise(store.delete(id));
    } catch (error) {
      this.activateMemoryFallback(error);
      this.memoryQueue.delete(id);
    }
  }
  
  private async incrementRetryCount(id: string): Promise<void> {
    if (this.idbUnavailable) {
      const item = this.memoryQueue.get(id);
      if (item) {
        item.retryCount = (item.retryCount || 0) + 1;
        this.memoryQueue.set(id, item);
      }
      return;
    }

    try {
      const db = await this.openDB();
      const tx = db.transaction(this.STORE_NAME, 'readwrite');
      const store = tx.objectStore(this.STORE_NAME);
      const item = await this.requestToPromise(store.get(id));
      
      if (item) {
        item.retryCount = (item.retryCount || 0) + 1;
        await this.requestToPromise(store.put(item));
      }
    } catch (error) {
      this.activateMemoryFallback(error);
      const item = this.memoryQueue.get(id);
      if (item) {
        item.retryCount = (item.retryCount || 0) + 1;
        this.memoryQueue.set(id, item);
      }
    }
  }
}

