import { storage, firestoreDb as db } from './firebase';
import { ref, uploadBytes, getDownloadURL } from 'firebase/storage';
import { doc, updateDoc, arrayUnion } from 'firebase/firestore';
import { getLocalDb, type LocalDBLike } from './localDB';
import type { UploadedImage } from '../types';
import { createStorageUrl } from '../types/branded';

const MAX_QUOTA = 500 * 1024 * 1024; // 500MB
const MAX_RETRIES = 5;

export class ImageSyncService {
  private localDB: LocalDBLike;

  constructor(userId: string, localDB: LocalDBLike) {
    this.localDB = localDB;
  }

  private async getStorageUsage(): Promise<number> {
    const stats = await this.localDB.userStats.get('current') || await this.localDB.userStats.toCollection().first();
    return stats?.totalStorageUsedBytes || 0;
  }

  private async checkQuota(fileSize: number): Promise<boolean> {
    const currentUsage = await this.getStorageUsage();
    return currentUsage + fileSize <= MAX_QUOTA;
  }

  private sleep(ms: number) {
    return new Promise(resolve => setTimeout(resolve, ms));
  }

  private async calculateChecksum(blob: Blob): Promise<string> {
    const arrayBuffer = await blob.arrayBuffer();
    const hashBuffer = await crypto.subtle.digest('SHA-256', arrayBuffer);
    const hashArray = Array.from(new Uint8Array(hashBuffer));
    return hashArray.map(b => b.toString(16).padStart(2, '0')).join('');
  }

  /**
   * サムネイルを生成する（Canvasを使用）
   */
  async generateThumbnail(blob: Blob, maxWidth = 300, maxHeight = 300): Promise<Blob> {
    return new Promise((resolve, reject) => {
      const img = new Image();
      img.onload = () => {
        let width = img.width;
        let height = img.height;

        if (width > maxWidth || height > maxHeight) {
          const ratio = Math.min(maxWidth / width, maxHeight / height);
          width *= ratio;
          height *= ratio;
        }

        const canvas = document.createElement('canvas');
        canvas.width = width;
        canvas.height = height;
        const ctx = canvas.getContext('2d');
        if (!ctx) {
          reject(new Error('Failed to get canvas context'));
          return;
        }

        ctx.drawImage(img, 0, 0, width, height);
        canvas.toBlob((thumbnailBlob) => {
          if (thumbnailBlob) {
            resolve(thumbnailBlob);
          } else {
            reject(new Error('Failed to create thumbnail blob'));
          }
        }, 'image/jpeg', 0.7);
      };
      img.onerror = () => reject(new Error('Failed to load image'));
      img.src = URL.createObjectURL(blob);
    });
  }

  /**
   * ローカルにのみ存在する（remoteUrlがない）画像を検出し、Storageにアップロードする
   */
  async syncLocalImages(userId: string, onProgress?: (msg: string) => void): Promise<void> {
    console.log('[ImageSync] Starting image sync check...');
    onProgress?.('画像同期の準備中...');
    const cards = await this.localDB.cards.toArray();
    
    for (const card of cards) {
      const updatedQuestionImages = await this.processImageArray(userId, card.id, 'cards', 'questionImages', card.questionImages, onProgress);
      const updatedAnswerImages = await this.processImageArray(userId, card.id, 'cards', 'answerImages', card.answerImages, onProgress);

      if (updatedQuestionImages || updatedAnswerImages) {
        await this.localDB.cards.update(card.id, {
          questionImages: updatedQuestionImages || card.questionImages,
          answerImages: updatedAnswerImages || card.answerImages,
          updatedAt: new Date()
        });
      }
    }
  }

  private async processImageArray(
    userId: string, 
    entityId: string, 
    table: string, 
    fieldName: string, 
    images: UploadedImage[],
    onProgress?: (msg: string) => void
  ): Promise<UploadedImage[] | null> {
    if (!images || images.length === 0) return null;
    let changed = false;
    const newImages = [...images];

    for (let i = 0; i < newImages.length; i++) {
      const image = newImages[i];
      // localUrlがあり、remoteUrlがない場合
      if (image.localUrl && !image.remoteUrl) {
        // すでに完了しているか、直近で失敗しすぎていないか確認
        if (image.uploadState === 'completed') continue;
        
        try {
          onProgress?.(`アップロード中 (${i + 1}/${newImages.length}): ${image.id.substring(0, 8)}...`);
          const syncedImage = await this.uploadImageToStorage(userId, image);
          newImages[i] = syncedImage;
          changed = true;
          console.log(`[ImageSync] Successfully uploaded image ${image.id}`);
        } catch (error) {
          console.error(`[ImageSync] Failed to upload image ${image.id}:`, error);
          newImages[i] = { ...image, uploadState: 'failed', lastAttempt: new Date() };
          changed = true;
        }
      }
    }

    return changed ? newImages : null;
  }

  private async uploadImageToStorage(userId: string, image: UploadedImage): Promise<UploadedImage> {
    if (!image.localUrl) throw new Error('Local URL missing');

    const response = await fetch(image.localUrl);
    const blob = await response.blob();
    
    // 1. Quota Check
    const thumbnailBlob = await this.generateThumbnail(blob);
    const totalSize = blob.size + thumbnailBlob.size;
    
    // Checksum
    const checksum = await this.calculateChecksum(blob);
    
    // 2. Check if already uploaded (Resume / Deduplication)
    // 実装プランに基づき、同一チェックサムの画像がクラウドにあれば再利用可能
    const highResPath = `users/${userId}/images/${checksum}_full`;
    const highResRef = ref(storage, highResPath);
    
    try {
      const existingUrl = await getDownloadURL(highResRef);
      console.log(`[ImageSync] Image with checksum ${checksum} already exists. Skipping upload.`);
      
      const thumbPath = `users/${userId}/images/${checksum}_thumb`;
      const thumbUrl = await getDownloadURL(ref(storage, thumbPath));
      
      return {
        ...image,
        remoteUrl: createStorageUrl(existingUrl),
        thumbnailUrl: createStorageUrl(thumbUrl),
        remoteId: image.id,
        storagePath: highResPath,
        status: 'ready',
        uploadState: 'completed',
        sizeBytes: blob.size,
        checksum: checksum,
        lastAttempt: new Date()
      };
    } catch (e) {
      // Not found, proceed with upload
    }
    
    if (!(await this.checkQuota(totalSize))) {
      throw new Error('Storage quota exceeded (Max 500MB)');
    }

    let lastError: unknown = null;
    for (let attempt = 0; attempt < MAX_RETRIES; attempt++) {
      try {
        // Update state to inProgress
        const inProgressImage = { 
          ...image, 
          uploadState: 'inProgress' as const, 
          lastAttempt: new Date(),
          checksum: checksum 
        };
        
        // 1. 高解像度版のアップロード
        const highResPath = `users/${userId}/images/${image.id}_full`;
        const highResRef = ref(storage, highResPath);
        await uploadBytes(highResRef, blob);
        const highResUrl = await getDownloadURL(highResRef);

        // 2. サムネイルのアップロード
        const thumbnailPath = `users/${userId}/images/${image.id}_thumb`;
        const thumbnailRef = ref(storage, thumbnailPath);
        await uploadBytes(thumbnailRef, thumbnailBlob);
        const thumbnailUrl = await getDownloadURL(thumbnailRef);

        // Update UserStats usage
        await this.updateStorageUsage(blob.size, thumbnailBlob.size);

        return {
          ...image,
          remoteUrl: createStorageUrl(highResUrl),
          thumbnailUrl: createStorageUrl(thumbnailUrl),
          remoteId: image.id,
          storagePath: highResPath,
          status: 'ready',
          uploadState: 'completed',
          sizeBytes: blob.size,
          checksum: checksum,
          lastAttempt: new Date()
        };
      } catch (error) {
        lastError = error;
        console.warn(`[ImageSync] Upload attempt ${attempt + 1} failed for ${image.id}:`, error);
        if (attempt < MAX_RETRIES - 1) {
          await this.sleep(Math.pow(2, attempt) * 1000); // Exponential backoff
        }
      }
    }

    throw lastError || new Error('Upload failed after max retries');
  }

  private async updateStorageUsage(highResSize: number, thumbnailSize: number): Promise<void> {
    const statsTable = this.localDB.userStats;
    const stats = await statsTable.get('current') || await statsTable.toCollection().first();
    
    if (stats) {
      await statsTable.update(stats.id, {
        totalHighResBytes: (stats.totalHighResBytes || 0) + highResSize,
        totalThumbnailBytes: (stats.totalThumbnailBytes || 0) + thumbnailSize,
        totalStorageUsedBytes: (stats.totalStorageUsedBytes || 0) + highResSize + thumbnailSize,
        updatedAt: new Date()
      });
    }
  }

  /**
   * [DEPRECATED/REMOVED]
   * Previously used to download images to creating local blobs.
   * Removed to prevent "Not allowed to load local resource" errors and blob leaks.
   * We now rely on standard browser caching for remote URLs.
   */
  async downloadHighResImage(image: UploadedImage): Promise<string | null> {
    return null;
  }
}

import type { ICloudSyncAdapter } from '../interfaces/ISyncService';
import { firestoreDb } from '../firebase';
import {
  collection,
  query,
  where,
  orderBy,
  limit,
  getDocs,
  writeBatch,
  doc,
  getDoc,
  Timestamp,
} from 'firebase/firestore';
import * as Firestore from 'firebase/firestore';
import { sanitizeBlobUrlsDeep } from '@/utils/blobUrlSanitizer';
import { sanitizeForLog } from '@/utils/logSanitizer';

/**
 * undefined は Firestore に投げた瞬間に爆発するので、深い階層まで除去する。
 * ※ 配列内の undefined も消す（Firestore 的にアウト）
 * ※ Date / Timestamp はそのまま
 */
function deepStripUndefined(input: unknown): unknown {
  if (input === undefined) return undefined;
  if (input === null) return null;

  if (input instanceof Timestamp) return input;
  if (input instanceof Date) return input;

  if (Array.isArray(input)) {
    return input.map(deepStripUndefined).filter((v) => v !== undefined);
  }

  if (typeof input === 'object') {
    const out: unknown = {};
    for (const [k, v] of Object.entries(input)) {
      const cleaned = deepStripUndefined(v);
      if (cleaned !== undefined) out[k] = cleaned;
    }
    return out;
  }

  return input;
}

/**
 * serverTimestamp が使える環境なら使う。無理ならクライアント時刻で妥協。
 * （大規模運用なら最終的には serverTimestamp に統一したいが、まず死なないのが最優先）
 */
function cloudUpdatedAt(): unknown {
  const fn = (Firestore as any).serverTimestamp;
  if (typeof fn === 'function') return fn();
  return Timestamp.now();
}

const COLLECTION_BY_TYPE: Record<string, string> = {
  card: 'cards',
  folder: 'folders',
  userSetting: 'userSettings',
};

/**
 * Firestore writeBatch は「1リクエストあたり 10MiB」制限がある。
 * 大きい変更が混ざると commit が普通に死ぬので、サイズでチャンクして複数回 commit する。
 * （余裕を見て 7.5MiB 目安）
 */
const MAX_BATCH_BYTES = Math.floor(7.5 * 1024 * 1024);
/**
 * Firestore batch の最大書き込み数は 500。余裕を見て 450。
 */
const MAX_BATCH_OPS = 450;
/**
 * pullDiff のページサイズ（無限 getDocs で死なないように）
 */
const PAGE_SIZE = 500;

const _encoder = new TextEncoder();

/** JSON stringify の byte 数で概算（正確じゃないが爆死回避には十分） */
function estimateBytes(value: unknown): number {
  try {
    return _encoder.encode(JSON.stringify(value)).length;
  } catch {
    // stringify 不能 = だいたい危険なので大きめに見積もる
    return 1024 * 1024;
  }
}

function chunkChangesBySize(changes: unknown[]): unknown[][] {
  const chunks: unknown[][] = [];
  let current: unknown[] = [];
  let bytes = 0;

  for (const ch of changes) {
    // data だけじゃなく type/id も少し上乗せ
    const docBytes = estimateBytes(ch?.data ?? {});
    const extra = docBytes + 512;

    const wouldExceedBytes = current.length > 0 && bytes + extra > MAX_BATCH_BYTES;
    const wouldExceedOps = current.length > 0 && current.length + 1 > MAX_BATCH_OPS;

    if (wouldExceedBytes || wouldExceedOps) {
      chunks.push(current);
      current = [];
      bytes = 0;
    }

    current.push(ch);
    bytes += extra;
  }

  if (current.length > 0) chunks.push(current);
  return chunks;
}

export class CloudSyncAdapter implements ICloudSyncAdapter {
  private userId: string;

  constructor(userId: string) {
    this.userId = userId;
  }

  private sanitizeForCloud(type: string, data: unknown): unknown {
    if (!data) return data;

    // ✅ 全エンティティ共通: undefined を深く除去
    const cleaned = deepStripUndefined(data);

    // ここでローカル専用フィールドを落としたいなら type ごとに増やす
    // （今の 'document' 判定は多分使われてないので、必要になったら追加でOK）
    return cleaned;
  }

  private sanitizeFromCloud(type: string, data: unknown): unknown {
    if (!data) return data;
    const stripped = deepStripUndefined(data);
    const sanitized = sanitizeBlobUrlsDeep(stripped);
    if (sanitized.changed) {
      console.warn(
        '[CloudSyncAdapter] sanitize_blob_url_from_cloud',
        sanitizeForLog({
          type,
          id: data?.id,
          fixes: sanitized.fixes,
        })
      );
    }
    return sanitized.value;
  }

  async pullDiff(since: number): Promise<{ changes: unknown[]; serverTime: number }> {
    console.log('🔄 [CloudSyncAdapter] pullDiff START', { since, userId: this.userId });
    const changes: unknown[] = [];

    if (!firestoreDb) {
      console.warn('⚠️ [CloudSyncAdapter] firestoreDb is not initialized. Skipping pullDiff.');
      return { changes: [], serverTime: Date.now() };
    }

    try {
      const sinceTimestamp = Timestamp.fromMillis(since);
      const startAfterFn = (Firestore as any).startAfter as undefined | ((snapshot: unknown) => any);

      // cards
      {
        const ref = collection(firestoreDb, `users/${this.userId}/cards`);

        let lastDoc: unknown = null;
        let total = 0;

        while (true) {
          const constraints: unknown[] = [
            where('updatedAt', '>', sinceTimestamp),
            orderBy('updatedAt', 'asc'),
            limit(PAGE_SIZE),
          ];

          // typings に startAfter が無い環境でも動くよう any 経由で呼ぶ
          if (startAfterFn && lastDoc) constraints.splice(2, 0, startAfterFn(lastDoc));

          const qy = query(ref, ...constraints);
          const snap = await getDocs(qy);
          total += snap.size;

          snap.forEach((d) => {
            changes.push({ type: 'card', id: d.id, data: this.sanitizeFromCloud('card', d.data()) });
          });

          // startAfter が無い環境では1ページで止める（現状より悪化させない）
          if (!startAfterFn || snap.empty || snap.size < PAGE_SIZE) break;
          lastDoc = snap.docs[snap.docs.length - 1] ?? null;
        }

        console.log(`[CloudSyncAdapter] Remote cards found: ${total}`);
      }

      // folders
      {
        const ref = collection(firestoreDb, `users/${this.userId}/folders`);

        let lastDoc: unknown = null;
        let total = 0;

        while (true) {
          const constraints: unknown[] = [
            where('updatedAt', '>', sinceTimestamp),
            orderBy('updatedAt', 'asc'),
            limit(PAGE_SIZE),
          ];

          if (startAfterFn && lastDoc) constraints.splice(2, 0, startAfterFn(lastDoc));

          const qy = query(ref, ...constraints);
          const snap = await getDocs(qy);
          total += snap.size;

          snap.forEach((d) => {
            changes.push({ type: 'folder', id: d.id, data: this.sanitizeFromCloud('folder', d.data()) });
          });

          if (!startAfterFn || snap.empty || snap.size < PAGE_SIZE) break;
          lastDoc = snap.docs[snap.docs.length - 1] ?? null;
        }

        console.log(`[CloudSyncAdapter] Remote folders found: ${total}`);
      }

      // userSettings (top-level document)
      {
        const settingsRef = doc(firestoreDb, 'userSettings', this.userId);
        const snap = await getDoc(settingsRef);
        if (snap.exists()) {
          const data: unknown = this.sanitizeFromCloud('userSetting', snap.data());
          const updatedAt =
            data?.updatedAt?.toMillis?.() ??
            data?.updatedAt?.getTime?.() ??
            (data?.updatedAt instanceof Date ? data.updatedAt.getTime() : 0);
          if (!since || updatedAt > since) {
            changes.push({ type: 'userSetting', id: snap.id, data });
          }
        }
      }

      console.log(`🔄 [CloudSyncAdapter] pullDiff SUCCESS. Total changes: ${changes.length}`);
      return { changes, serverTime: Date.now() };
    } catch (error) {
      console.error('❌ [CloudSyncAdapter] pullDiff ERROR:', error);
      throw error;
    }
  }

  async pushBatch(changes: unknown[]): Promise<{ successIds: string[]; failedIds: string[]; error?: unknown }> {
    console.log(`📤 [CloudSyncAdapter] pushBatch START. Count: ${changes.length}`);
    const successIds: string[] = [];
    const failedIds: string[] = [];

    try {
      if (!firestoreDb) {
        console.error('❌ [CloudSyncAdapter] firestoreDb is null during pushBatch');
        return {
          successIds: [],
          failedIds: changes.map((c) => c.id),
          error: new Error('Firestore not initialized'),
        };
      }

      const chunks = chunkChangesBySize(changes);
      let firstError: unknown = undefined;

      for (const chunk of chunks) {
        const batch = writeBatch(firestoreDb);
        const chunkIds: string[] = [];

        for (const change of chunk) {
          const { type, id, data } = change;
          const col = COLLECTION_BY_TYPE[type] ?? `${type}s`; // 保険
          console.log(`   - Adding to batch: ${col}/${id}`);

          const docRef =
            type === 'userSetting'
              ? doc(firestoreDb, 'userSettings', id || this.userId)
              : doc(firestoreDb, `users/${this.userId}/${col}`, id);

          const sanitized = this.sanitizeForCloud(type, data);

          // sanitized が null とか来たら普通に事故るので最低限の防御
          if (!sanitized || typeof sanitized !== 'object') {
            throw new Error(`Invalid payload for ${type}/${id}: expected object`);
          }

          batch.set(
            docRef,
            {
              ...sanitized,
              updatedAt: cloudUpdatedAt(),
            },
            { merge: true }
          );

          chunkIds.push(id);
        }

        try {
          console.log(`   - Committing batch... (ops=${chunkIds.length})`);
          await batch.commit();
          successIds.push(...chunkIds);
        } catch (error) {
          console.error('❌ [CloudSyncAdapter] pushBatch chunk commit ERROR:', error);
          failedIds.push(...chunkIds);
          if (!firstError) firstError = error;
          // 次のチャンクへ（成功分は残す）
        }
      }

      if (failedIds.length > 0) {
        return { successIds, failedIds, error: firstError };
      }

      console.log('📤 [CloudSyncAdapter] pushBatch SUCCESS');
      return { successIds, failedIds };
    } catch (error) {
      console.error('❌ [CloudSyncAdapter] pushBatch ERROR:', error);
      return {
        successIds: [],
        failedIds: changes.map((c) => c.id),
        error,
      };
    }
  }

  async pullFull(entityIds: string[]): Promise<any[]> {
    const results: unknown[] = [];

    for (const id of entityIds) {
      if (!firestoreDb) throw new Error('Firebase Firestore is not initialized.');

      // card
      {
        const snap = await getDocs(query(collection(firestoreDb, `users/${this.userId}/cards`), where('id', '==', id)));
        if (!snap.empty) {
          results.push({ type: 'card', id, data: this.sanitizeFromCloud('card', snap.docs[0].data()) });
          continue;
        }
      }

      // folder
      {
        const snap = await getDocs(
          query(collection(firestoreDb, `users/${this.userId}/folders`), where('id', '==', id))
        );
        if (!snap.empty) {
          results.push({ type: 'folder', id, data: this.sanitizeFromCloud('folder', snap.docs[0].data()) });
          continue;
        }
      }

      // userSetting
      {
        const snap = await getDoc(doc(firestoreDb, 'userSettings', this.userId));
        if (snap.exists()) {
          results.push({
            type: 'userSetting',
            id: this.userId,
            data: this.sanitizeFromCloud('userSetting', snap.data()),
          });
        }
      }
    }

    return results;
  }
}

import type { INetworkMonitor, BatchConstraint } from '../interfaces/ISyncService';
import type { NetworkStatus, SyncContextSource } from '../../types/telemetry';

/**
 * NetworkMonitor: ネットワーク状態を監視し、実測値ベースで健全性を判断
 * 状態遷移にヒステリシス（履歴効果）を持たせ、頻繁な揺れを防ぐ
 */
export class NetworkMonitor implements INetworkMonitor {
  private _status: NetworkStatus = 'good';
  private consecutiveSuccesses = 0;
  private consecutiveFailures = 0;
  private recentDurations: number[] = [];
  private listeners: Array<(status: NetworkStatus) => void> = [];

  private readonly DURATION_WINDOW = 5; // 直近5回の平均を取る
  
  // 状態遷移の閾値
  private readonly THRESHOLDS = {
    EXCELLENT_SUCCESS_COUNT: 5,
    GOOD_SUCCESS_COUNT: 3,
    POOR_ERROR_RATE: 0.1,
    RTT_SLOW: 2000,
    RTT_FAST: 100
  };
  
  private handleOnline = () => {
    console.log('[NetworkMonitor] Network is online');
    this.updateStatus();
    // 復帰時に即座にgoodに戻す試み（updateStatus内でのロジックに依存）
    if (this._status === 'offline') {
        this._status = 'poor'; // リセット
        this.notifyListeners();
    }
  };

  private handleOffline = () => {
    console.log('[NetworkMonitor] Network is offline');
    this._status = 'offline';
    this.notifyListeners();
  };

  constructor() {
    if (typeof window !== 'undefined') {
        window.addEventListener('online', this.handleOnline);
        window.addEventListener('offline', this.handleOffline);
    }
  }

  destroy() {
    if (typeof window !== 'undefined') {
        window.removeEventListener('online', this.handleOnline);
        window.removeEventListener('offline', this.handleOffline);
    }
  }

  get status(): NetworkStatus {
    return this._status;
  }

  /**
   * バッチ制約を環境コンテキストに応じて返す
   */
  getBatchConstraint(context: SyncContextSource): BatchConstraint {
    // ユーザー主導の同期は最優先
    if (context === 'user_initiated') {
      return {
        maxSize: 100,
        concurrency: 3,
        timeoutMs: 30000
      };
    }

    // ネットワーク状態に応じた制約
    const baseConstraint = this.getBaseConstraintByNetwork();
    
    // バックグラウンドは控えめに
    if (context === 'background') {
      return {
        maxSize: Math.min(baseConstraint.maxSize, 20),
        concurrency: 1,
        timeoutMs: 10000
      };
    }

    return baseConstraint;
  }

  private getBaseConstraintByNetwork(): BatchConstraint {
    const avgDuration = this.getAverageDuration();
    
    switch (this._status) {
      case 'excellent':
        return { maxSize: 50, concurrency: 2, timeoutMs: 20000 };
      case 'good':
        return { maxSize: 30, concurrency: 1, timeoutMs: 15000 };
      case 'poor':
        return { maxSize: 10, concurrency: 1, timeoutMs: 10000 };
      case 'offline':
        return { maxSize: 0, concurrency: 0, timeoutMs: 0 };
    }
  }

  /**
   * 同期結果を報告し、状態遷移を判定
   */
  reportResult(success: boolean, durationMs: number): void {
    // 持続時間の記録
    this.recentDurations.push(durationMs);
    if (this.recentDurations.length > this.DURATION_WINDOW) {
      this.recentDurations.shift();
    }

    // 連続成功/失敗のカウント
    if (success) {
      this.consecutiveSuccesses++;
      this.consecutiveFailures = 0;
    } else {
      this.consecutiveFailures++;
      this.consecutiveSuccesses = 0;
    }

    // 状態遷移の判定
    this.updateStatus();
  }

  private updateStatus(): void {
    const avgDuration = this.getAverageDuration();
    const oldStatus = this._status;

    // オフライン判定（即座に降格）
    if (!navigator.onLine) {
      this._status = 'offline';
    }
    // Poor判定（エラー率または極端な遅延で即座に降格）
    else if (this.consecutiveFailures >= 2 || avgDuration > this.THRESHOLDS.RTT_SLOW) {
      this._status = 'poor';
    }
    // Poor -> Good への昇格（慎重に、連続成功が必要）
    else if (this._status === 'poor' && this.consecutiveSuccesses >= this.THRESHOLDS.GOOD_SUCCESS_COUNT) {
      this._status = 'good';
    }
    // Good -> Excellent への昇格（さらに慎重に）
    else if (
      this._status === 'good' && 
      this.consecutiveSuccesses >= this.THRESHOLDS.EXCELLENT_SUCCESS_COUNT &&
      avgDuration < this.THRESHOLDS.RTT_FAST
    ) {
      this._status = 'excellent';
    }
    // Offline -> Poor への復帰
    else if (this._status === 'offline' && navigator.onLine) {
      this._status = 'poor'; // 復帰直後は慎重にpoorから開始
    }

    // 状態変化があればリスナーに通知
    if (oldStatus !== this._status) {
      console.log(`[NetworkMonitor] Status changed: ${oldStatus} -> ${this._status}`);
      this.notifyListeners();
    }
  }

  private getAverageDuration(): number {
    if (this.recentDurations.length === 0) return 100; // デフォルト値
    return this.recentDurations.reduce((a, b) => a + b, 0) / this.recentDurations.length;
  }

  /**
   * 状態変化のリスナー登録
   */
  subscribe(callback: (status: NetworkStatus) => void): () => void {
    this.listeners.push(callback);
    return () => {
      this.listeners = this.listeners.filter(l => l !== callback);
    };
  }

  private notifyListeners(): void {
    this.listeners.forEach(listener => listener(this._status));
  }
}

import { firestoreDb } from '../firebase';
import { collection, addDoc, serverTimestamp, Timestamp, onSnapshot, doc, query, where, updateDoc } from 'firebase/firestore';
import type { SecurityEventType, SecurityLog, SecurityMetadata } from '../../types/telemetry';

/**
 * リスク検知ルールの定義
 * クライアントサイドでの検知ポリシー
 */
interface DetectionRule {
  type: SecurityEventType;
  riskScore: number; // イベントごとの加算スコア
  alwaysTrigger?: boolean; // 閾値なしで即座に加算するか
  timeWindowMs?: number; // 監視窓（ミリ秒）
  countThreshold?: number; // 閾値（回数）
}

/**
 * 異常検知ルールとRiskScore設計に基づく定義
 * @see docs/データベース/異常検知ルールとRiskScore設計.md
 */
const DETECTION_RULES: DetectionRule[] = [
  // 認証異常
  { type: 'LOGIN_FAILED', riskScore: 5, timeWindowMs: 5 * 60 * 1000, countThreshold: 1 }, 
  { type: 'SYNC_AUTH_ERROR', riskScore: 10, alwaysTrigger: true },
  
  // 端末異常
  { type: 'ACCESS_DENIED_REVOKED', riskScore: 30, alwaysTrigger: true },
  
  // 重要操作失敗
  { type: 'SENSITIVE_OP_REVOKED', riskScore: 20, alwaysTrigger: true },
  
  // 管理操作
  { type: 'ADMIN_DEVICE_REVOKE', riskScore: 10, alwaysTrigger: true },
  { type: 'ADMIN_ACCOUNT_LOCK', riskScore: 50, alwaysTrigger: true },
  
  // 技術的異常（以前のルールも保持）
  { type: 'LOCK_CONTENTION_EXCESS', riskScore: 7, timeWindowMs: 5 * 60 * 1000, countThreshold: 10 },
  { type: 'SYNC_CONFLICT_EXCESS', riskScore: 3, timeWindowMs: 5 * 60 * 1000, countThreshold: 10 },
];

/**
 * セキュリティ状態の定義
 */
export interface SecurityState {
  isLocked: boolean;
  requires2FA: boolean;
  alerts: unknown[];
}

/**
 * SecurityMonitor: セキュリティイベントの監視と異常検知を行うクラス
 */
export class SecurityMonitor {
  private userId: string;
  private deviceId: string;
  private eventHistory: { type: SecurityEventType; timestamp: number }[] = [];
  private currentRiskScore: number = 0;
  private lastEvaluationTime: number = Date.now();
  private internalState: SecurityState = {
    isLocked: false,
    requires2FA: false,
    alerts: []
  };

  constructor(userId: string, deviceId: string) {
    this.userId = userId;
    this.deviceId = deviceId;
    this.loadState();
  }

  /**
   * イベントを記録し、異常検知を実行する
   */
  async logEvent(type: SecurityEventType, metadata: SecurityMetadata = {}): Promise<void> {
    const now = Date.now();
    this.eventHistory.push({ type, timestamp: now });
    
    // 履歴のクリーンアップ (古いイベントを削除)
    // 最大の時間窓を持つルールに合わせる (ここでは10分程度あれば十分)
    const maxWindow = 10 * 60 * 1000;
    this.eventHistory = this.eventHistory.filter(e => e.timestamp > now - maxWindow);

    // ログをFirestoreへ送信
    await this.sendSecurityLog(type, metadata);

    // ルール評価
    this.evaluateRules(type);
    
    // 永続化
    this.saveState();
  }

  /**
   * 異常検知ルールの評価
   */
  private evaluateRules(triggerType: SecurityEventType): void {
    const now = Date.now();
    let scoreAdded = 0;

    for (const rule of DETECTION_RULES) {
      if (rule.type !== triggerType) continue;

      let shouldTrigger = false;

      if (rule.alwaysTrigger) {
        shouldTrigger = true;
      } else if (rule.timeWindowMs && rule.countThreshold) {
        const recentCount = this.eventHistory.filter(
          e => e.type === rule.type && e.timestamp > now - rule.timeWindowMs!
        ).length;
        // 今回のイベントで閾値に達した、あるいは超えている場合に加算（多重加算防止は簡易）
        if (recentCount >= rule.countThreshold) {
            shouldTrigger = true;
        }
      }

      if (shouldTrigger) {
        console.warn(`[Security] Risk score added: +${rule.riskScore} by ${rule.type}`);
        this.currentRiskScore += rule.riskScore;
        scoreAdded += rule.riskScore;
      }
    }
    
    // 減衰処理（自然復旧）
    this.applyDecay(now);
    
    // 上限キャップ (0-100)
    this.currentRiskScore = Math.min(100, Math.max(0, this.currentRiskScore));
  }

  /**
   * リスクスコアの減衰処理
   * 1時間ごとの減算処理 (decayPerHour = 3)
   */
  private applyDecay(now: number): void {
    const hoursElapsed = (now - this.lastEvaluationTime) / (1000 * 60 * 60);
    if (hoursElapsed > 0) {
      const decay = Math.floor(hoursElapsed * 3); // 1時間で3減少
      if (decay > 0) {
        this.currentRiskScore = Math.max(0, this.currentRiskScore - decay);
        this.lastEvaluationTime = now;
      }
    }
  }

  /**
   * Firestoreへセキュリティログを送信
   */
  private async sendSecurityLog(type: SecurityEventType, metadata: SecurityMetadata): Promise<void> {
    try {
      if (!firestoreDb) {
        console.warn('[Security] firestoreDb is undefined. Skipping security log.');
        return;
      }
      const logData: Omit<SecurityLog, 'logId'> = {
        userId: this.userId,
        deviceId: this.deviceId,
        eventType: type,
        severity: this.getSeverity(type),
        source: 'client',
        isUserVisible: this.isUserVisible(type),
        description: this.getDescription(type),
        metadata,
        occurredAt: serverTimestamp()
      };
      
      await addDoc(collection(firestoreDb, `users/${this.userId}/securityLogs`), logData);
    } catch (error) {
      console.error('[Security] Failed to send log:', error);
      // 送信失敗自体もリスクだが、無限ループ防止のためここでは握りつぶす
    }
  }

  /**
   * イベントタイプから重要度を判定
   */
  private getSeverity(type: SecurityEventType): 'info' | 'warning' | 'critical' {
    switch (type) {
      case 'ACCESS_DENIED_REVOKED':
      case 'LOCK_CONTENTION_EXCESS':
      case 'ADMIN_ACCOUNT_LOCK':
        return 'critical';
      case 'DEVICE_REVOKED':
      case 'SYNC_AUTH_ERROR':
      case 'SYNC_CONFLICT_EXCESS':
      case 'ADMIN_DEVICE_REVOKE':
      case 'SENSITIVE_OP_REVOKED':
        return 'warning';
      default:
        return 'info';
    }
  }

    /**
   * ユーザーに表示すべきかどうか
   */
    private isUserVisible(type: SecurityEventType): boolean {
        // 基本的に内部的な異常検知はユーザーに見せないが、
        // アカウントロックや新しいデバイス登録などは見せる
        switch(type) {
            case 'DEVICE_NEW_REGISTER':
            case 'LOGIN_SUCCESS':
            case 'DEVICE_REVOKED':
            case 'ADMIN_ACCOUNT_LOCK':
                return true;
            default:
                return false;
        }
    }

  /**
   * デフォルトの説明文
   */
  private getDescription(type: SecurityEventType): string {
    // 簡易的なマッピング。多言語対応が必要な場合は別途翻訳リソースを使う。
    const descMap: Record<SecurityEventType, string> = {
      'LOGIN_SUCCESS': 'ログインに成功しました',
      'LOGIN_FAILED': 'ログインに失敗しました',
      'DEVICE_REVOKED': 'デバイス登録が解除されました',
      'ACCESS_DENIED_REVOKED': '無効化されたデバイスからのアクセスを拒否しました',
      'SYNC_AUTH_ERROR': '同期の認証エラーが発生しました',
      'SENSITIVE_OP_REVOKED': '権限のない重要な操作が拒否されました',
      'DEVICE_NEW_REGISTER': '新しいデバイスが登録されました',
      'LOCK_CONTENTION_EXCESS': '同期ロックの頻繁な競合（奪取ループ）を検知しました',
      'SYNC_CONFLICT_EXCESS': 'データ競合が異常に多発しています',
      'ADMIN_DEVICE_REVOKE': '管理者によりデバイスが解除されました',
      'ADMIN_ACCOUNT_LOCK': '管理者によりアカウントがロックされました',
      'ADMIN_LOG_EXPORT': '監査ログが出力されました'
    };
    return descMap[type] || 'セキュリティイベントが発生しました';
  }

  /**
   * 現在のセキュリティ状態（SafeModeかどうか等）を取得
   */
  getSecurityStatus(): { isSafeMode: boolean; riskScore: number } {
    // リスクスコア 10以上で SafeMode
    return {
      isSafeMode: this.currentRiskScore >= 10,
      riskScore: this.currentRiskScore
    };
  }

  private unsubscribeMetadata: (() => void) | null = null;
  private unsubscribeNotifications: (() => void) | null = null;

  /**
   * リアルタイム監視を開始する
   * - ユーザーメタデータ (ロック状態, 2FA)
   * - セキュリティ通知
   */
  startMonitoring(onStateChange: (state: SecurityState) => void): void {
    if (!firestoreDb) {
      console.error('[Security] firestoreDb is undefined. Cannot start monitoring.');
      return;
    }
    // 1. メタデータ監視
    this.unsubscribeMetadata = onSnapshot(doc(firestoreDb, `users/${this.userId}`), (snapshot) => {
      if (snapshot.exists()) {
        const data = snapshot.data();
        this.internalState.isLocked = data.isAccountLocked === true;
        this.internalState.requires2FA = data.requires2FA === true;
        
        onStateChange({ ...this.internalState });
      }
    }, (error) => {
      console.error('[Security] Metadata monitoring failed:', error);
    });

    // 2. 通知監視 (SecurityAlertの未読)
    const q = query(
      collection(firestoreDb, `users/${this.userId}/notifications`),
      where('type', '==', 'SECURITY_ALERT'),
      where('read', '==', false)
    );

    this.unsubscribeNotifications = onSnapshot(q, (snapshot) => {
      this.internalState.alerts = snapshot.docs.map(doc => ({
        id: doc.id,
        ...doc.data()
      }));
      
      onStateChange({ ...this.internalState });
    }, (error) => {
      // Permisson errors are expected if rules are not set up. Suppress to avoid spam.
      if (error.code !== 'permission-denied') {
        console.warn('[Security] Notification monitoring failed (non-permission error):', error);
      }
    });
  }

  /**
   * 通知を既読にする
   */
  async dismissAlert(alertId: string): Promise<void> {
    try {
      if (!firestoreDb) throw new Error('Firebase Firestore is not initialized.');
      const alertRef = doc(firestoreDb, `users/${this.userId}/notifications`, alertId);
      await updateDoc(alertRef, { read: true });
    } catch (error) {
      console.error('[Security] Failed to dismiss alert:', error);
    }
  }

  /**
   * 監視を停止する
   */
  stopMonitoring(): void {
    if (this.unsubscribeMetadata) {
      this.unsubscribeMetadata();
      this.unsubscribeMetadata = null;
    }
    if (this.unsubscribeNotifications) {
      this.unsubscribeNotifications();
      this.unsubscribeNotifications = null;
    }
  }

  /**
   * 状態の保存 (localStorage)
   */
  private saveState(): void {
    localStorage.setItem(`security_score_${this.userId}`, this.currentRiskScore.toString());
    localStorage.setItem(`security_last_eval_${this.userId}`, this.lastEvaluationTime.toString());
  }

  /**
   * 状態の読み込み
   */
  private loadState(): void {
    const score = localStorage.getItem(`security_score_${this.userId}`);
    const time = localStorage.getItem(`security_last_eval_${this.userId}`);
    if (score) this.currentRiskScore = parseInt(score, 10);
    if (time) this.lastEvaluationTime = parseInt(time, 10);
  }
}

import { getLocalDb } from './localDB';
import type { SyncQueueItem } from '../types/sync';
import { getFunctions, httpsCallable } from 'firebase/functions';

export type QueuePriority = 'critical' | 'high' | 'medium' | 'low';
export type OperationType = 'create' | 'update' | 'delete';

// 'completed' | 'failed' are reserved for future audit logs.
// Current Policy: Delete on Success, Revert to Pending/DLQ on Failure.
export type QueueStatus = 'pending' | 'processing' | 'completed' | 'failed';

type SynthesisResult = OperationType | 'discard' | 'error';

/**
 * Operation Synthesis Matrix
 * Defines how to combine a new operation with an existing pending operation.
 * 
 * Assumption: 'data' is a complete snapshot replacement. No deep merging.
 */
const OPERATION_MATRIX: Record<OperationType, Record<OperationType, SynthesisResult>> = {
    create: {
        create: 'error',   // Duplicate create
        update: 'create',  // Update on top of create -> effectively create with new data
        delete: 'discard'  // Create then delete -> cancel out
    },
    update: {
        create: 'error',   // Create on top of update -> invalid
        update: 'update',  // Update on top of update -> merge to single update (latest data)
        delete: 'delete'   // Update then delete -> delete
    },
    delete: {
        create: 'update',  // Delete then create -> effective restore (update)
        update: 'error',   // Update on top of delete
        delete: 'delete'   // Redundant delete
    }
};

export class OperationQueueService {
  // Concurrency & Batch Settings
  private readonly MAX_CONCURRENCY = 5; 
  private readonly BATCH_LIMIT = 20;

  // Retry Settings
  private readonly MAX_RETRIES = 5;
  private readonly BASE_DELAY_MS = 1000;
  private readonly MAX_DELAY_MS = 30000;
  private readonly JITTER_FACTOR = 0.1; // +/- 10%
  private readonly STALE_TIMEOUT_MS = 5 * 60 * 1000; // 5 minutes (Orphan detection)

  constructor() {}

  /**
   * Enqueues a change operation with compression logic.
   * If a pending operation exists for the same target, it attempts to compress them.
   */
  async enqueueChange(
    entity: 'card' | 'folder' | 'asset',
    targetId: string, 
    operationType: OperationType, 
    data: unknown, 
    priority: QueuePriority = 'medium'
  ): Promise<void> {
    const db = await getLocalDb();
    await db.transaction('rw', ['syncQueue'], async () => {
        // 1. Find existing Pending item
        // Items in 'processing' status are EXCLUDED from compression to preserve execution integrity.
        // We use the composite index [targetId+status] implicitly via where clause.
        const existingItem = await db.syncQueue
            .where({ targetId: targetId })
            .filter(item => item.status === 'pending')
            .first();

        if (existingItem) {
            // 2. Apply Synthesis Matrix
            const existingOp = existingItem.operationType as OperationType;
            const resultOp = OPERATION_MATRIX[existingOp][operationType];

            // 2-a. Discard (e.g. Create + Delete)
            if (resultOp === 'discard') {
                await db.syncQueue.delete(existingItem.id);
                console.log(`[Queue] Discarded operation for ${targetId} (${existingOp}+${operationType})`);
                return;
            }

            // 2-b. Error / Fallback (e.g. Invalid sequence)
            if (resultOp === 'error') {
                console.warn(`[Queue] Invalid sequence: ${existingOp} -> ${operationType}. Forcing new enqueue.`);
                // Force add as a new item (no compression)
                await this.addItem(entity, targetId, operationType, data, priority);
                return;
            }

            // 2-c. Update (Compression)
            // Preserve IdempotencyKey, Replace Payload, Merge Priority
            await db.syncQueue.update(existingItem.id, {
                operationType: resultOp as OperationType,
                payload: data, // Snapshot Replacement
                priority: this.resolvePriority(existingItem.priority, priority),
                entity: entity, // Ensure entity is correct (should match)
                updatedAt: Date.now(),
                retryCount: 0,
                lastError: undefined,
                nextRetryAt: undefined
            });
            console.log(`[Queue] Compressed: ${existingOp} + ${operationType} -> ${resultOp}`);

        } else {
            // 3. New Item
            await this.addItem(entity, targetId, operationType, data, priority);
        }
    });

    // Trigger processing
    this.triggerProcess();
  }

  // Helper to add new item
  private async addItem(
      entity: 'card' | 'folder' | 'asset', 
      targetId: string, 
      op: OperationType, 
      data: unknown, 
      priority: QueuePriority
  ) {
      const newItem: SyncQueueItem = {
          id: crypto.randomUUID(),
          idempotencyKey: crypto.randomUUID(), // Generated once per operation stream
          targetId,
          entity,
          operationType: op,
          action: op, // Legacy compatibility
          type: 'upload',
          payload: data,
          priority,
          status: 'pending',
          createdAt: Date.now(),
          updatedAt: Date.now(),
          retryCount: 0
      };
      const db = await getLocalDb();
      await db.syncQueue.add(newItem);
  }

  /**
   * Processes the queue with concurrency control and priority handling.
   * Safe to call concurrently (Re-entrant safe).
   */
  async processQueue(): Promise<void> {
    const db = await getLocalDb();
    // 0. Cleanup Stale Items (Self-Healing)
    await this.cleanupStaleProcessing();

    // 1. Global Concurrency Check
    const processingCount = await db.syncQueue
        .where('status').equals('processing')
        .count();
        
    if (processingCount >= this.MAX_CONCURRENCY) return;
    
    const capacity = this.MAX_CONCURRENCY - processingCount;
    const fetchLimit = Math.min(capacity, this.BATCH_LIMIT);
    const now = Date.now();

    // 2. Cascading Priority Fetch
    // We try to fill the 'fetchLimit' starting from High priority
    let candidates: SyncQueueItem[] = [];
    
    // Helper to fetch
    const fetchByPriority = async (p: QueuePriority, limit: number) => {
        if (limit <= 0) return [];
        return await db.syncQueue
            .where('[status+priority]')
            .equals(['pending', p])
            .filter(item => !item.nextRetryAt || item.nextRetryAt <= now)
            .limit(limit)
            .sortBy('createdAt');
    };

    // a. High
    const highs = await fetchByPriority('high', fetchLimit);
    candidates = [...candidates, ...highs];
    
    // b. Medium (Normal)
    const mediums = await fetchByPriority('medium', fetchLimit - candidates.length);
    candidates = [...candidates, ...mediums];
    
    // c. Low (Background)
    const lows = await fetchByPriority('low', fetchLimit - candidates.length);
    candidates = [...candidates, ...lows];

    if (candidates.length === 0) return;

    // 3. Lock & Execute
    // Process items in parallel (limited by the fact we just fetched limited batch)
    await Promise.all(candidates.map(async (item) => {
        // 3-a. Transactional Lock (CAS)
        const lockedItem = await db.transaction<SyncQueueItem | null | undefined>('rw', ['syncQueue'], async () => {
             const current = await db.syncQueue.get(item.id);
             if (!current || current.status !== 'pending') return null;
             
              // Update to processing
              await db.syncQueue.update(item.id, { 
                  status: 'processing',
                  processingStartedAt: Date.now()
              });
             return current;
        });

        if (!lockedItem) return; // Lost race or already processed

        // 3-b. Execution
        try {
            await this.performSyncOperation(lockedItem);
            
            // Success: Delete Immediately (Delete on Success)
            await db.syncQueue.delete(lockedItem.id);
            
        } catch (error) {
            await this.handleFailure(lockedItem, error);
        }
    }));
    
    // Continue processing if queue might not be empty and we had full batch
    if (candidates.length === fetchLimit) {
        setTimeout(() => this.processQueue(), 0);
    }
  }

  private resolvePriority(p1: QueuePriority, p2: QueuePriority): QueuePriority {
    const scores = { critical: 4, high: 3, medium: 2, low: 1 };
    return scores[p1] >= scores[p2] ? p1 : p2;
  }

  /**
   * Failure Handling with Backoff & DLQ
   */
  private async handleFailure(item: SyncQueueItem, error: unknown): Promise<void> {
      const newRetryCount = (item.retryCount || 0) + 1;

      if (newRetryCount > this.MAX_RETRIES) {
          // A. Max Retry Exceeded -> Move to DLQ
          await this.moveToDLQ(item, error);
          return;
      }
      
      // B. Backoff Calculation
      const baseDelay = this.BASE_DELAY_MS * Math.pow(2, newRetryCount - 1);
      const cappedDelay = Math.min(baseDelay, this.MAX_DELAY_MS);
      
      // Full Jitter
      const jitter = cappedDelay * (this.JITTER_FACTOR * (Math.random() * 2 - 1));
      const nextDelay = Math.max(0, cappedDelay + jitter);

        const db = await getLocalDb();
        // Revert to pending with delay
        await db.syncQueue.update(item.id, {
            status: 'pending', 
            retryCount: newRetryCount,
            lastError: String(error),
            nextRetryAt: Date.now() + nextDelay
        });
  }

  /**
   * Dead Letter Queue Logic
   * In Phase 1, we just delete from queue and log error.
   * Future: Move to dedicated DLQ table.
   */
  private async moveToDLQ(item: SyncQueueItem, error: unknown): Promise<void> {
      console.error(`[Queue] Item ${item.id} moved to DLQ after ${this.MAX_RETRIES} retries.`, error, item);
      
      // In a real implementation: localDb.dlq.add({ ...item, error: ... })
      // For now, we perform "manual recovery" by just deleting it from active queue 
      // but ideally we should keep it somewhere.
      // We will create a skeleton for 'syncErrors' table usage if defined, or just log hard.
      // Luckily we have 'syncErrors' table in localDB from previous versions!
      
      const db = await getLocalDb();
      try {
        await db.syncErrors.add({
            id: crypto.randomUUID(),
            occurredAt: Date.now(),
            phase: 'queue_dlq',
            retryCount: 0,
            retryable: false,
            message: String(error),
            metadata: {
                originalItemId: item.id,
                targetId: item.targetId,
                operationType: item.operationType,
                payload: item.payload
            }
        });
      } catch (e) {
        console.error('Failed to save to DLQ/SyncErrors', e);
      }

      await db.syncQueue.delete(item.id);
  }
  
  private async performSyncOperation(item: SyncQueueItem): Promise<void> {
      // Mock Implementation for Phase 1
      // In Phase 2/3, this calls Cloud Functions
      console.log(`[Queue] Executing ${item.operationType} on ${item.entity}:${item.targetId}`, item.idempotencyKey);
      
      // Simulating network delay
      await new Promise(resolve => setTimeout(resolve, 500));
      
      // Throw random error for testing retry if needed
      // if (Math.random() < 0.3) throw new Error("Random Network Error");
  }
  
  public triggerProcess(): void {
      // Trigger async processing without awaiting
      // Debouncing could be added here if needed
      setTimeout(() => this.processQueue(), 100);
  }

  /**
   * Identifies items stuck in 'processing' state for too long (due to crash/timeout)
   * and reverts them to 'pending' to allow retry.
   */
  private async cleanupStaleProcessing(): Promise<void> {
      const now = Date.now();
      const staleThreshold = now - this.STALE_TIMEOUT_MS;

      const db = await getLocalDb();
      // Scanning all 'processing' items
      // Since max concurrency is low (5), this scan is cheap.
      try {
          const staleItems = await db.syncQueue
              .where('status').equals('processing')
              .filter(item => {
                  // If processingStartedAt is missing, treat as stale immediately (legacy/bug)
                  // or give it a grace period if we prefer. But assuming new code, it should be set.
                  const startedAt = item.processingStartedAt || 0;
                  return startedAt < staleThreshold;
              })
              .toArray();

          if (staleItems.length > 0) {
              console.warn(`[Queue] Found ${staleItems.length} stale processing items. Recovering...`);
              
              await db.transaction('rw', ['syncQueue'], async () => {
                  for (const item of staleItems) {
                       await db.syncQueue.update(item.id, {
                           status: 'pending',
                           // processingStartedAt: undefined, // Optional cleanup
                           retryCount: (item.retryCount || 0) + 1,
                           lastError: 'Stale Processing Recovery',
                           nextRetryAt: now // Retry immediately
                       });
                  }
              });
          }
      } catch (error) {
          console.error('[Queue] Failed to cleanup stale items:', error);
      }
  }
}

