// Operation Queue の既存システムへの統合ヘルパー
// LocalDB との連携を強化

import { operationQueue } from './operationQueue';
import { getLocalDb } from './localDB';
import type { Card, Folder } from '../types';

/**
 * Operation Queue 統合サービス
 * 既存のLocalDB操作をOperation Queueに橋渡し
 */
export class QueueIntegrationService {
  private userId: string;

  constructor(userId: string) {
    this.userId = userId;
  }

  /**
   * カード作成（Queue統合版）
   */
  async createCard(cardData: Partial<Card>): Promise<Card> {
    const db = await getLocalDb(this.userId);
    // 1. ローカルDBに即座に反映（楽観的更新）
    // addItem returns the ID string
    const id = await db.addItem('cards', cardData as Card);
    const localCard = await db.cards.get(id);

    if (!localCard) {
      throw new Error('Failed to create local card');
    }

    // 2. Operation Queueに追加（バックグラウンド同期）
    await operationQueue.enqueueChange(
      'card',
      localCard.id,
      'create',
      localCard,
      'medium'
    );

    return localCard;
  }

  /**
   * カード更新（Queue統合版）
   */
  async updateCard(cardId: string, updates: Partial<Card>): Promise<void> {
    const db = await getLocalDb(this.userId);
    // 1. ローカルDBに即座に反映
    await db.updateItem('cards', cardId, updates);

    // 2. Operation Queueに追加
    const updated = await db.cards.get(cardId);
    if (updated) {
      await operationQueue.enqueueChange(
        'card',
        cardId,
        'update',
        updated,
        'medium'
      );
    }
  }

  /**
   * カード削除（Queue統合版）
   */
  async deleteCard(cardId: string): Promise<void> {
    const db = await getLocalDb(this.userId);
    // 1. ローカルDBに即座に反映
    await db.softDelete('cards', cardId);

    // 2. Operation Queueに追加
    await operationQueue.enqueueChange(
      'card',
      cardId,
      'delete',
      { id: cardId, isDeleted: true },
      'medium'
    );
  }

  /**
   * キュー処理実行
   * オンライン復帰時やバックグラウンドで定期的に呼び出す
   */
  async processQueue(): Promise<void> {
    await operationQueue.processQueue();
  }
}

/**
 * グローバルインスタンス管理
 */
let _instance: QueueIntegrationService | null = null;
let _currentUserId: string | null = null;

export function getQueueIntegration(userId: string): QueueIntegrationService {
  if (!_instance || _currentUserId !== userId) {
    _instance = new QueueIntegrationService(userId);
    _currentUserId = userId;
  }
  return _instance;
}

import { Timestamp } from 'firebase/firestore';
import type { SubjectiveScore } from '@/utils/reviewUtils';

export type ReviewAlgorithmInput = {
  card: {
    memoryStability?: number | null;
    currentLevel?: number | null;
    level?: number | null;
    nextReviewDate?: Date | Timestamp | null;
    lastReviewAt?: Date | Timestamp | null;
    recoveryRemaining?: number | null;
    reviewCount?: number | null; // Added

    // ✅ Added: difficulty (0..1). Higher = more error-prone / harder for this user.
    difficulty?: number | null;
  };
  subjectiveScore: SubjectiveScore;
  now?: Date;
};

export type ReviewAlgorithmResult = {
  memoryStability: number;
  nextReviewDate: Date;
  lastReviewAt: Date;
  lastSubjectiveScore: SubjectiveScore;
  recoveryRemaining: number;
  intervalDays: number;
  delayDays: number;
  reviewCount: number; // Added

  // ✅ Added
  difficulty: number;
};

// Constants
const MIN_STABILITY = 0.01;  // Prevent division by zero
const MAX_STABILITY = 1.0;
const MAX_INTERVAL_DAYS = 90;

// ✅ Difficulty constants (pragmatic defaults)
const MIN_DIFFICULTY = 0.0;
const MAX_DIFFICULTY = 1.0;

// EMA smoothing factor (smaller = more stable, larger = more reactive)
const DIFFICULTY_ALPHA = 0.10;

// Interval brake strength (0.0..1.0). Example: 0.30 => max 30% shorter at difficulty=1
const DIFFICULTY_INTERVAL_BRAKE = 0.30;

// Helper: Convert Firestore Timestamp or Date to Date
const toDate = (value?: Date | Timestamp | null): Date | null => {
  if (!value) return null;
  if (value instanceof Date) return value;
  if (typeof (value as any)?.toDate === 'function') return (value as any).toDate();
  if (typeof value === 'object') {
    const seconds =
      typeof (value as any)?.seconds === 'number'
        ? (value as any).seconds
        : typeof (value as any)?._seconds === 'number'
          ? (value as any)._seconds
          : null;
    const nanoseconds =
      typeof (value as any)?.nanoseconds === 'number'
        ? (value as any).nanoseconds
        : typeof (value as any)?._nanoseconds === 'number'
          ? (value as any)._nanoseconds
          : 0;
    if (seconds !== null) {
      const ms = seconds * 1000 + Math.floor(nanoseconds / 1e6);
      const d = new Date(ms);
      return Number.isNaN(d.getTime()) ? null : d;
    }
  }
  const parsed = new Date(value as any);
  return Number.isNaN(parsed.getTime()) ? null : parsed;
};

// Helper: Calculate day difference
const diffDays = (a: Date, b: Date): number => {
  const msA = new Date(a).setHours(0, 0, 0, 0);
  const msB = new Date(b).setHours(0, 0, 0, 0);
  return Math.floor((msA - msB) / (1000 * 60 * 60 * 24));
};

// Clamp stability to valid range (0, 1]
const clampStability = (s: number): number => {
  return Math.max(MIN_STABILITY, Math.min(MAX_STABILITY, s));
};

// ✅ Clamp to [0,1]
const clamp01 = (x: number): number => {
  return Math.max(0, Math.min(1, x));
};

// ✅ Clamp difficulty to [0,1]
const clampDifficulty = (d: number): number => {
  return Math.max(MIN_DIFFICULTY, Math.min(MAX_DIFFICULTY, d));
};

// Normalize legacy level (0-5) to new stability (0-1)
const legacyLevelToStability = (level: number): number => {
  // Map levels 0-5 to stability 0.1-0.9
  const normalized = 0.1 + (Math.min(5, Math.max(0, level)) / 5) * 0.8;
  return clampStability(normalized);
};

// Get initial stability for a card
export const getInitialStability = (
  memoryStability?: number | null,
  legacyLevel?: number | null
): number => {
  // If we have a valid 0-1 stability, use it directly
  if (typeof memoryStability === 'number' && Number.isFinite(memoryStability)) {
    if (memoryStability > 0 && memoryStability <= 1) {
      return clampStability(memoryStability);
    }
    // Legacy format (5-100 days): convert to 0-1 range
    if (memoryStability > 1 && memoryStability <= 100) {
      return clampStability((memoryStability - 5) / 95);
    }
  }

  // Fall back to legacy level if available
  if (typeof legacyLevel === 'number' && Number.isFinite(legacyLevel)) {
    return legacyLevelToStability(legacyLevel);
  }

  // Default: 30% stability for new cards
  return 0.30;
};

// ✅ Initial difficulty (0..1)
// “測る”んじゃなくて、カードの挙動から“推定する”ための初期値。
// 既存値があればそれを採用。なければ stability から雑に推定（新規でも極端にならないように弱める）。
export const getInitialDifficulty = (
  difficulty?: number | null,
  stability?: number | null
): number => {
  if (typeof difficulty === 'number' && Number.isFinite(difficulty)) {
    return clampDifficulty(difficulty);
  }

  // Derive a conservative default from stability if available:
  // Higher stability => lower difficulty, but dampened so new cards aren't instantly "hardest".
  if (typeof stability === 'number' && Number.isFinite(stability)) {
    const derived = (1 - clamp01(stability)) * 0.6; // 0..0.6 range
    return clampDifficulty(derived);
  }

  // Neutral-ish default
  return 0.35;
};

/**
 * Calculate next review interval based on stability
 * Formula: D = 1 + 100 × S^2.5
 */
const calculateIntervalDays = (stability: number): number => {
  const days = 1 + 100 * Math.pow(stability, 2.5);
  return Math.max(1, Math.min(MAX_INTERVAL_DAYS, Math.round(days)));
};

/**
 * Update stability based on subjective score
 *
 * Score 0 (忘れた): S' = S × 0.5
 * Score 1 (あいまい): S' = S × 0.8
 * Score 2 (OK): S' = S + (1-S) × 0.1
 * Score 3 (余裕): S' = S + (1-S) × 0.25
 */
const updateStability = (currentStability: number, score: SubjectiveScore): number => {
  let newStability: number;

  switch (score) {
    case 0: // 忘れた - 50% decrease (Factor 0.5)
      newStability = currentStability * 0.5;
      break;
    case 1: // あいまい - 20% decrease
      newStability = currentStability * 0.8;
      break;
    case 2: // 覚えた - 10% of remaining growth
      newStability = currentStability + (1 - currentStability) * 0.1;
      break;
    case 3: // 余裕 - 25% of remaining growth
      newStability = currentStability + (1 - currentStability) * 0.25;
      break;
    default:
      newStability = currentStability;
  }

  return clampStability(newStability);
};

// ✅ Subjective score -> "fail-ish" (0..1)
// This is NOT truth, just a pragmatic signal.
// 0 (Forgot) : 1.0
// 1 (Hard)   : 0.6
// 2 (Good)   : 0.2
// 3 (Easy)   : 0.0
const scoreToFailish = (score: SubjectiveScore): number => {
  switch (score) {
    case 0: return 1.0;
    case 1: return 0.6;
    case 2: return 0.2;
    case 3: return 0.0;
    default: return 0.2;
  }
};

// ✅ Update difficulty via EMA:
// d' = d*(1-α) + failish*α
const updateDifficulty = (currentDifficulty: number, score: SubjectiveScore): number => {
  const failish = scoreToFailish(score);
  const next = currentDifficulty * (1 - DIFFICULTY_ALPHA) + failish * DIFFICULTY_ALPHA;
  return clampDifficulty(next);
};

// ✅ Apply difficulty as a mild interval brake (safe and explainable internally)
const applyDifficultyBrakeToInterval = (baseIntervalDays: number, difficulty: number): number => {
  const factor = 1 - DIFFICULTY_INTERVAL_BRAKE * clampDifficulty(difficulty); // [1-k, 1]
  const adjusted = Math.round(baseIntervalDays * factor);
  return Math.max(1, Math.min(MAX_INTERVAL_DAYS, adjusted));
};

/**
 * Main review algorithm
 */
export const computeNextReview = ({
  card,
  subjectiveScore,
  now = new Date(),
  delayBonusEnabled = false
}: ReviewAlgorithmInput & { delayBonusEnabled?: boolean }): ReviewAlgorithmResult => {
  const c: unknown = card as any;
  // Get current stability (with legacy conversion)
  const legacyLevel = (card.currentLevel ?? c.current_level ?? card.level ?? c.level ?? null) as any;
  const currentStability = getInitialStability((card.memoryStability ?? c.memory_stability ?? null) as any, legacyLevel);

  // ✅ Get current difficulty
  const currentDifficulty = getInitialDifficulty((card.difficulty ?? c.difficulty ?? null) as any, currentStability);

  // Calculate delay (days overdue)
  const plannedDate = toDate((card.nextReviewDate ?? c.next_review_date ?? null) as any);
  const diff = plannedDate ? diffDays(now, plannedDate) : 0;
  const delayDays = Math.max(0, diff);

  // Update stability based on review result
  let newStability = updateStability(currentStability, subjectiveScore);

  // Delay Bonus Logic
  if (delayBonusEnabled && delayDays > 0) {
    // Formula: S' = S' * (1 + log2(1 + D))
    const bonusFactor = 1 + Math.log2(1 + delayDays);
    newStability = clampStability(newStability * bonusFactor);
  }

  // ✅ Update difficulty AFTER seeing the result (and independent from delay to avoid "busy life" pollution)
  const newDifficulty = updateDifficulty(currentDifficulty, subjectiveScore);

  // Recovery Mode Removed (kept for schema compatibility)
  const recoveryRemaining = 0;

  // Calculate next interval (stability base)
  const baseIntervalDays = calculateIntervalDays(newStability);

  // ✅ Apply difficulty brake (mild encourage for “problem cards”)
  const intervalDays = applyDifficultyBrakeToInterval(baseIntervalDays, newDifficulty);

  // Calculate next review date
  const nextReviewDate = new Date(now);
  nextReviewDate.setDate(nextReviewDate.getDate() + intervalDays);
  nextReviewDate.setHours(0, 0, 0, 0);

  // Increment review count
  const currentReviewCount = (card.reviewCount ?? c.review_count ?? 0) as any;
  const reviewCount = currentReviewCount + 1;

  return {
    memoryStability: newStability,
    nextReviewDate,
    lastReviewAt: now,
    lastSubjectiveScore: subjectiveScore,
    recoveryRemaining,
    intervalDays,
    delayDays,
    reviewCount,

    // ✅ Return difficulty so caller can persist it
    difficulty: newDifficulty,
  };
};

/**
 * Calculate recall probability based on time elapsed
 * Formula: R(t) = e^(-t/S)
 *
 * @param stability Current stability (0-1)
 * @param daysSinceReview Days since last review
 * @returns Recall probability (0-1)
 */
export const calculateRecallProbability = (stability: number, daysSinceReview: number): number => {
  if (stability <= 0) return 0;
  if (daysSinceReview <= 0) return 1;

  // Scale stability for the exponential formula
  const scaledStability = stability * 100;
  return Math.exp(-daysSinceReview / scaledStability);
};

// ============================================================================
// Multiple Choice Integration (4択モード統合)
// ============================================================================

/**
 * 4択モードでの確信度（正解時のみ取得）
 */
export type MultipleChoiceConfidence = 'high' | 'mid' | 'luck';

/**
 * 4択モードの復習メタデータ
 */
export type MultipleChoiceReviewMeta = {
  /** 選択した答えが正解かどうか */
  isCorrect: boolean;
  
  /** 「分からない」を選択したか（明示的なギブアップ） */
  isUnknown?: boolean;
  
  /** 正解時の確信度（未入力時は自動的に 'mid' 扱い） */
  confidence?: MultipleChoiceConfidence;
  
  /** 選択肢表示後から回答までの時間（ミリ秒） */
  choiceTimeMs?: number;
};

/**
 * 4択結果を SubjectiveScore に変換する
 * 
 * 変換ルール:
 * - isUnknown === true → 0
 * - isCorrect === false → 0
 * - isCorrect === true:
 *   - confidence === 'high' → 3
 *   - confidence === 'mid' or undefined → 2
 *   - confidence === 'luck' → 1
 * 
 * 反応時間による弱い制限:
 * - choiceTimeMs > 9000ms → score を最大 1 に制限
 * - choiceTimeMs > 6000ms → score を最大 2 に制限
 * 
 * @param meta 4択モードの復習メタデータ
 * @returns SubjectiveScore (0..3)
 */
export const convertMultipleChoiceToSubjectiveScore = (
  meta: MultipleChoiceReviewMeta
): SubjectiveScore => {
  // 分からないを選択 or 不正解 → 0
  if (meta.isUnknown === true || meta.isCorrect === false) {
    return 0;
  }

  // 正解時: 確信度から base score を決定
  const confidence = meta.confidence ?? 'mid'; // 未入力時は自動的に 'mid'
  let score: SubjectiveScore;

  switch (confidence) {
    case 'high':
      score = 3;
      break;
    case 'mid':
      score = 2;
      break;
    case 'luck':
      score = 1;
      break;
    default:
      score = 2; // fallback
  }

  // 反応時間による弱い制限（オプショナル）
  if (typeof meta.choiceTimeMs === 'number' && meta.choiceTimeMs > 0) {
    if (meta.choiceTimeMs > 9000) {
      // 9秒超: 最大 1 に制限（時間かかりすぎ）
      score = Math.min(score, 1) as SubjectiveScore;
    } else if (meta.choiceTimeMs > 6000) {
      // 6秒超: 最大 2 に制限（やや時間かかった）
      score = Math.min(score, 2) as SubjectiveScore;
    }
  }

  return score;
};

import { firestoreDb } from './firebase';
import type { LocalDBLike } from './localDB';
import type { ICloudProvider } from './cloudProvider';
import { FirebaseCloudProvider } from './cloudProvider';
import { ImageSyncService } from './imageSyncService';
import { getOrCreateDeviceId, getDeviceName } from '../utils/device';
import { collection, getDocs, query, where, writeBatch, Timestamp, doc, getDoc, setDoc, limit, orderBy } from 'firebase/firestore';
import { ref as storageRef, uploadBytesResumable, getDownloadURL } from 'firebase/storage';
import type { Folder, Card, User, UserSettings, UserStats } from '../types';
import type { SyncError, SyncHistory, SyncSettings, SyncConflict, SyncQueueItem, DiffResult, SyncResult } from '../types/sync';
import { DEFAULT_SYNC_SETTINGS } from '../types/sync';
import { sanitizeProfileImage } from '@/utils/profileImageSanitizer';
import { sanitizeForLog } from '@/utils/logSanitizer';
import { storage } from './firebase';
import { getImageBlob } from './imageFileStore';

type SyncableCollection = 'users' | 'userSettings' | 'folders' | 'cards' | 'userStats';

const normalizeFolderForSync = (folder: unknown) => {
  if (!folder) return folder;
  const isSilent = folder.isSilent ?? folder.is_silent ?? folder.silent;
  const normalized = { ...folder };
  if (isSilent !== undefined) {
    normalized.isSilent = isSilent;
  }
  delete normalized.is_silent;
  delete normalized.silent;
  return normalized;
};

/**
 * FirestoreとローカルDB (Dexie) 間の差分同期を管理するサービスクラス。
 * ローカルファースト設計: すべての読み取りはローカルから、クラウドは差分同期のみ
 * 
 * 高度化機能:
 * - エラーライフサイクル管理（retryCount、3回失敗でretryable=false）
 * - 同期履歴記録（30日 or 100件保持）
 * - ユーザー設定駆動型同期（間隔、WiFi限定など）
 * - オフラインキュー（FIFO）
 * - 競合検出とフィールド単位自動マージ
 */
export class SyncService {
  private userId: string;
  private localDB: LocalDBLike;
  private cloudProvider: ICloudProvider;
  private deviceId: string;
  private imageSyncService: ImageSyncService;
  
  // Phase 1: Sync Isolation
  public static isSyncing: boolean = false;

  constructor(userId: string, localDB: LocalDBLike, cloudProvider?: ICloudProvider) {
    if (!userId) {
      throw new Error('SyncService requires a user ID.');
    }
    this.userId = userId;
    // 注入されたLocalDBインスタンスを使用
    this.localDB = localDB;
    this.cloudProvider = cloudProvider || new FirebaseCloudProvider();
    this.imageSyncService = new ImageSyncService(userId, localDB);
    this.deviceId = getOrCreateDeviceId();

    // オンライン復帰時の自動同期
    if (typeof window !== 'undefined') {
      window.addEventListener('online', () => {
        console.log('[Sync] Online detected. Triggering auto-sync.');
        this.synchronize().catch(console.error);
      });
    }
  }

  /**
   * 同期ロックを取得（分散ロック）
   */
  private async acquireSyncLock(): Promise<boolean> {
    console.log(`[Sync] acquireSyncLock: userId="${this.userId}", deviceId="${this.deviceId}"`);

    if (!this.userId || !this.deviceId) {
        console.error('[Sync] Cannot acquire lock: Invalid userId or deviceId.');
        return false;
    }

    // Use multi-argument doc() for safer path construction
    const lockDoc = doc(firestoreDb, 'sync_locks', this.userId);
    const now = Date.now();
    const lockDuration = 5 * 60 * 1000; // 5分


    let attempts = 0;
    const maxAttempts = 3;
    const baseDelay = 1000; // 1秒

    while (attempts < maxAttempts) {
      try {
        const snapshot = await getDoc(lockDoc);
        if (snapshot.exists()) {
          const data = snapshot.data();
          if (data.deviceId !== this.deviceId && now < data.expiresAt) {
            console.warn(`[Sync] Lock held by another device: ${data.deviceId}. Attempt ${attempts + 1}/${maxAttempts}`);
            attempts++;
            if (attempts < maxAttempts) {
              // 指数バックオフ + Adaptive Jitter
              // 試行回数に応じてベースのJitter幅も調整
              const backoff = baseDelay * Math.pow(2, attempts - 1);
              const adaptiveJitter = Math.random() * backoff * (1 + attempts * 0.1); 
              const delay = backoff + adaptiveJitter;
              
              console.log(`[Sync] Retrying lock in ${Math.round(delay)}ms...`);
              await new Promise(resolve => setTimeout(resolve, delay));
              continue;
            }
            return false;
          }

          // 【正常遷移: Lock Expire → Forced Release】
          // 期限切れのロックは「ゴースト」として扱い、警告なしで上書き取得する
          if (data.deviceId !== this.deviceId && now >= data.expiresAt) {
            console.log(`[Sync] Expired lock found from device ${data.deviceId}. Performing forced release (Designated transition).`);
          }
        }

        await setDoc(lockDoc, {
          deviceId: this.deviceId,
          acquiredAt: now,
          expiresAt: now + lockDuration
        });
        return true;
      } catch (error) {
        console.error('[Sync] Failed to acquire lock:', error);
        attempts++;
        if (attempts < maxAttempts) {
          const delay = Math.floor(Math.random() * 4000) + 1000;
          await new Promise(resolve => setTimeout(resolve, delay));
          continue;
        }
        return false;
      }
    }
    return false;
  }

  private async releaseSyncLock(): Promise<void> {
    if (!this.userId) return;
    const lockDoc = doc(firestoreDb, 'sync_locks', this.userId);
    try {
      const snapshot = await getDoc(lockDoc);
      if (snapshot.exists() && snapshot.data().deviceId === this.deviceId) {
        // ロックを削除（または期限切れにする）
        await setDoc(lockDoc, { expiresAt: 0 }, { merge: true });
      }
    } catch (error) {
      console.error('[Sync] Failed to release lock:', error);
    }
  }

  /**
   * 端末を同期から解除する
   */
  async removeDevice(deviceId: string): Promise<void> {
    const deviceMetaDoc = doc(firestoreDb, `sync_metadata/${this.userId}/devices/${deviceId}`);
    await setDoc(deviceMetaDoc, { isActive: false }, { merge: true });
    console.log(`[Sync] Device ${deviceId} deactivated.`);
  }

  /**
   * 端末の表示名を更新する
   */
  async updateDeviceName(deviceId: string, newName: string): Promise<void> {
    const deviceMetaDoc = doc(firestoreDb, `sync_metadata/${this.userId}/devices/${deviceId}`);
    await setDoc(deviceMetaDoc, { deviceName: newName }, { merge: true });
    console.log(`[Sync] Device ${deviceId} renamed to ${newName}.`);
  }

  private async checkDeviceLimit(): Promise<{ ok: boolean; count: number }> {
    const devicesRef = collection(firestoreDb, `sync_metadata/${this.userId}/devices`);
    const sixtyDaysAgo = new Date(Date.now() - 60 * 24 * 60 * 60 * 1000);
    
    const q = query(
      devicesRef, 
      where('isActive', '==', true),
      where('lastSyncTime', '>', Timestamp.fromDate(sixtyDaysAgo))
    );
    const snapshot = await getDocs(q);
    return { ok: true, count: snapshot.size };
  }

  /**
   * 24時間以上活動がない非アクティブな端末を一括解除する
   */
  async cleanupInactiveDevices(): Promise<number> {
    const devicesRef = collection(firestoreDb, `sync_metadata/${this.userId}/devices`);
    const sixtyDaysAgo = new Date(Date.now() - 60 * 24 * 60 * 60 * 1000);
    
    const q = query(
      devicesRef, 
      where('isActive', '==', true),
      where('lastSyncTime', '<=', Timestamp.fromDate(sixtyDaysAgo))
    );
    
    const snapshot = await getDocs(q);
    let count = 0;
    const batch = writeBatch(firestoreDb);
    
    snapshot.docs.forEach(deviceDoc => {
      // 現在の端末は除外（念のため）
      if (deviceDoc.id !== this.deviceId) {
        batch.update(deviceDoc.ref, { isActive: false });
        count++;
      }
    });
    if (count > 0) {
      await batch.commit();
      await this.recordHistory(Date.now(), 'success', 0, 0, `Automated Cleanup: Deactivated ${count} inactive devices.`);
      console.log(`[Sync] Automated Cleanup: Deactivated ${count} inactive devices.`);
    }
    return count;
  }

  // ========================================
  // 設定管理
  // ========================================

  /**
   * 同期設定を読み込み（なければデフォルト作成）
   */
  async loadSettings(): Promise<SyncSettings> {
    let settings = await this.localDB.syncSettings.get('default');
    if (!settings) {
      settings = { ...DEFAULT_SYNC_SETTINGS };
      await this.localDB.syncSettings.put(settings);
    }
    return settings;
  }

  /**
   * 同期設定を保存
   */
  async saveSettings(settings: SyncSettings): Promise<void> {
    await this.localDB.syncSettings.put(settings);
  }

  /**
   * Best-effort WiFi判定
   * Network Information APIが未対応の場合はtrue（同期許可）を返す
   */
  private isWifiConnection(): boolean {
    const conn = (navigator as any).connection;
    if (!conn || !conn.type) return true; // 判定不能 → 許可
    return conn.type === 'wifi';
  }

  // ========================================
  // エラー管理
  // ========================================

  /**
   * エラーを記録（ライフサイクル管理）
   * 同一エラーIDが渡された場合は更新し、retryCountをインクリメント
   * 3回失敗でretryable=falseに変更
   */
  private async recordError(
    message: string,
    phase: 'upload' | 'download' | 'merge',
    stack?: string,
    existingErrorId?: string
  ): Promise<string> {
    if (existingErrorId) {
      const existing = await this.localDB.syncErrors.get(existingErrorId);
      if (existing) {
        existing.retryCount += 1;
        existing.occurredAt = Date.now();
        if (existing.retryCount >= 3) {
          existing.retryable = false;
        }
        await this.localDB.syncErrors.put(existing);
        return existing.id;
      }
    }
    
    const error: SyncError = {
      id: crypto.randomUUID(),
      occurredAt: Date.now(),
      phase,
      message,
      stack,
      retryCount: 0,
      retryable: true,
    };
    await this.localDB.syncErrors.put(error);
    return error.id;
  }

  /**
   * リトライ可能なエラーを取得
   */
  async getRetryableErrors(): Promise<SyncError[]> {
    return this.localDB.syncErrors
      .where('retryable')
      .equals(1) // Dexieではbooleanは0/1として扱われる
      .toArray();
  }

  /**
   * すべてのエラーをクリア
   */
  async clearAllErrors(): Promise<void> {
    await this.localDB.syncErrors.clear();
  }

  // ========================================
  // 履歴管理
  // ========================================

  /**
   * 同期履歴を記録
   */
  private async recordHistory(
    startedAt: number,
    result: 'success' | 'partial' | 'failed' | 'skipped_wifi',
    uploaded: number,
    downloaded: number,
    message?: string
  ): Promise<void> {
    const history: SyncHistory & { message?: string } = {
      id: crypto.randomUUID(),
      startedAt,
      finishedAt: Date.now(),
      result,
      uploaded,
      downloaded,
      message
    };
    await this.localDB.syncHistory.put(history);
  }

  /**
   * 同期履歴を取得（直近n件）
   */
  async getRecentHistory(limit: number = 30): Promise<SyncHistory[]> {
    return this.localDB.syncHistory
      .orderBy('finishedAt')
      .reverse()
      .limit(limit)
      .toArray();
  }

  // ========================================
  // オフラインキュー管理
  // ========================================

  /**
   * 変更をキューに追加（FIFO）
   * オフライン時またはpush失敗時に使用
   */
  async enqueueChange(
    entity: 'card' | 'folder' | 'asset',
    action: 'create' | 'update' | 'delete',
    payload: unknown
  ): Promise<void> {
    // キューの上限（1000件）を確認
    const count = await this.localDB.syncQueue.count();
    if (count >= 1000) {
      console.warn('[Sync] Queue limit reached. Removing oldest changes.');
      const oldest = await this.localDB.syncQueue.orderBy('createdAt').limit(count - 999).toArray();
      await this.localDB.syncQueue.bulkDelete(oldest.map(i => i.id));
    }

    const queueItem: unknown = {
      id: crypto.randomUUID(),
      entity,
      action,
      payload,
      createdAt: Date.now(),
    };
    await this.localDB.syncQueue.put(queueItem);
    console.log(`[Sync] Enqueued ${action} for ${entity}: ${payload.id}`);
  }

  /**
   * キューの件数を取得
   */
  async getQueueCount(): Promise<number> {
    return this.localDB.syncQueue.count();
  }

  /**
   * キューを順次処理
   * 各アイテムごとにtry-catch、成功したら削除、失敗したらエラー記録してキュー保持
   */
  async processQueue(): Promise<{ processed: number; failed: number }> {
    let queue = await this.localDB.syncQueue.orderBy('createdAt').toArray();
    let processed = 0;
    let failed = 0;

    // デバイスのストレージ状況に応じてキュー上限を動的に調整
    // (通常1000件、ストレージが逼迫している場合は500件に制限)
    let queueLimit = 1000;
    try {
      const storage = await navigator.storage.estimate();
      if (storage.usage && storage.quota && (storage.usage / storage.quota) > 0.8) {
        queueLimit = 500;
        console.warn(`[Sync] Storage high usage detected (${Math.round((storage.usage / storage.quota) * 100)}%). Reducing queue limit to 500.`);
      }
    } catch (e) { /* ignore */ }

    if (queue.length > queueLimit) {
      const toRemove = queue.length - queueLimit;
      console.warn(`[Sync] Queue size ${queue.length} exceeds dynamic limit ${queueLimit}. Removing ${toRemove} oldest items.`);
      const itemsToRemove = queue.slice(0, toRemove);
      for (const item of itemsToRemove) {
        await this.localDB.syncQueue.delete(item.id);
      }
      queue = queue.slice(toRemove);
    }

    for (const item of queue) {
      try {
        // すでに3回以上失敗しているアイテムは一旦スキップ（またはエラーログを吐いて破棄）
        const errors = await this.localDB.syncErrors.where('message').startsWith(`Queue processing failed`).and(e => e.message.includes(item.payload.id)).toArray();
        const totalAttempts = errors.reduce((acc, e) => acc + e.retryCount + 1, 0);

        if (totalAttempts >= 3) {
          console.error(`[Sync] Skipping queue item ${item.payload.id} after ${totalAttempts} failed attempts.`);
          // 失敗が続くアイテムはキューから削除してエラーとして記録
          await this.localDB.syncQueue.delete(item.id);
          continue;
        }

        if (item.action === 'create' || item.action === 'update') {
          if (item.entity === 'asset') {
            const payload = item.payload ?? {};
            const assetId = payload.assetId ?? item.targetId ?? item.payload?.id;
            const localBlobId = payload.localBlobId ?? assetId;
            const remoteKey = payload.remoteKey ?? `users/${this.userId}/assets/${assetId}`;
            if (!assetId || !localBlobId) {
              throw new Error('Asset queue payload is missing assetId/localBlobId');
            }
            const blob = await getImageBlob(localBlobId, { userId: this.userId });
            if (!blob) {
              await this.localDB.images.put({
                id: assetId,
                userId: this.userId,
                mime: payload.mime ?? 'application/octet-stream',
                size: payload.size ?? 0,
                localBlobId,
                localStatus: 'missing',
                remoteKey,
                remoteStatus: 'failed',
                updatedAt: new Date(),
                createdAt: new Date(),
              } as any);
              throw new Error(`Asset blob missing: ${assetId}`);
            }
            const task = uploadBytesResumable(storageRef(storage, remoteKey), blob, {
              contentType: blob.type || payload.mime || 'application/octet-stream',
            });
            await new Promise<void>((resolve, reject) => {
              task.on('state_changed', undefined, reject, () => resolve());
            });
            const remoteUrl = await getDownloadURL(task.snapshot.ref);
            const existingAsset = await this.localDB.images.get(assetId);
            await this.localDB.images.put({
              ...(existingAsset as any ?? {}),
              id: assetId,
              userId: this.userId,
              mime: blob.type || payload.mime || (existingAsset as any)?.mime || 'application/octet-stream',
              size: blob.size || payload.size || (existingAsset as any)?.size || 0,
              localBlobId,
              localStatus: 'present',
              remoteKey,
              remoteStatus: 'ready',
              remoteUrlCache: remoteUrl,
              retryCount: 0,
              updatedAt: new Date(),
              createdAt: (existingAsset as any)?.createdAt ?? new Date(),
            } as any);
            if (import.meta.env.DEV) {
              console.info('[AssetSync] syncQueue upload success', { assetId, remoteKey });
            }
          } else if (item.entity === 'card') {
            await this.cloudProvider.upsertCard(item.payload);
          } else {
            await this.cloudProvider.upsertFolder(item.payload);
          }
        } else if (item.action === 'delete') {
          if (item.entity === 'asset') {
            // 画像資産のdeleteは現状ローカルメタ更新のみ（Storage削除は将来対応）
            await this.localDB.images.update(item.payload.id ?? item.targetId, {
              remoteStatus: 'none',
              updatedAt: new Date(),
            } as any);
          } else if (item.entity === 'card') {
            await this.cloudProvider.deleteCard(item.payload.id, this.userId);
          } else {
            await this.cloudProvider.deleteFolder(item.payload.id, this.userId);
          }
        }
        
        // 成功したらキューから削除
        await this.localDB.syncQueue.delete(item.id);
        processed++;
        console.log(`[Sync] Processed queue item: ${item.action} ${item.entity} ${item.payload.id}`);
      } catch (error: unknown) {
        // 失敗したらエラー記録してキュー保持
        await this.recordError(
          `Queue processing failed: ${error.message}`,
          'upload',
          error.stack
        );
        failed++;
        console.error(`[Sync] Failed to process queue item:`, error);
      }
    }

    return { processed, failed };
  }

  // ========================================
  // 競合検出と解決
  // ========================================

  /**
   * クラウドのデータとローカルのデータをマージする（Field-level Merging）
   */
  private mergeEntity(local: unknown, remote: unknown, entityType: 'card' | 'folder'): unknown {
    if (!local) return remote;
    if (!remote) return local;

    const localUpdated = local.updatedAt instanceof Date ? local.updatedAt : local.updatedAt?.toDate?.() || new Date(0);
    const remoteUpdated = remote.updatedAt instanceof Date ? remote.updatedAt : remote.updatedAt?.toDate?.() || new Date(0);

    // 基本的には「最新の更新日時」を持つ方を優先
    if (remoteUpdated > localUpdated) {
        // 画像フィールドの特別なマージ
        const mergedImages: unknown = {};
        let imageMergedDescription = '';
        
        ['questionImages', 'answerImages'].forEach(field => {
            if (local[field] && remote[field]) {
                const combined = [...local[field], ...remote[field]];
                const unique = Array.from(new Map(combined.map(img => [img.id, img])).values());
                if (unique.length > remote[field].length) {
                    imageMergedDescription = '別の端末で画像が追加されました。両方の画像を保持します。';
                }
                mergedImages[field] = unique;
            }
        });

        const merged = { ...local, ...remote, ...mergedImages };
        
        // テキストフィールドなどで競合があるかチェック
        const isCard = entityType === 'card';
        const hasTextConflict = isCard 
            ? (local.question !== remote.question || local.answer !== remote.answer)
            : (local.name !== remote.name);

        if (hasTextConflict) {
            merged.hasSyncConflict = true;
            merged.conflictDescription = imageMergedDescription 
                ? `${imageMergedDescription} また、${isCard ? '問題文や回答' : 'フォルダ名'}の内容に競合があります。最新の編集内容を優先しましたが、確認をお勧めします。`
                : '別の端末でも編集が行われていました。最新の内容を優先しましたが、競合がある可能性があります。';
            
            // 手動解決用に詳細を conflicts テーブルに保存
            const conflictDetails: unknown = isCard ? {
                question: { local: local.question, remote: remote.question },
                answer: { local: local.answer, remote: remote.answer }
            } : {
                name: { local: local.name, remote: remote.name }
            };

            this.saveConflict(remote.id, entityType, merged, conflictDetails)
                .catch(err => console.error('[Sync] Failed to save detailed conflict:', err));
        } else if (imageMergedDescription) {
            merged.hasSyncConflict = true;
            merged.conflictDescription = imageMergedDescription;
        }
        
        return merged;
    } else if (localUpdated > remoteUpdated) {
        // ローカルが新しい場合はそのまま（次のpushで同期される）
        return local;
    }

    // 更新日時が同じ場合はマージ
    return { ...local, ...remote };
  }

  /**
   * 2-way差分検出とフィールド単位自動マージ
   * base=local（ユーザーが最後に見た状態）
   */
  private diffFields(local: unknown, remote: unknown): DiffResult {
    const base = local; // 2-way merge
    const autoMerged = { ...base };
    const conflicts: Record<string, { local: unknown; remote: unknown }> = {};

    // 共通フィールドを比較
    const allKeys = new Set([...Object.keys(local), ...Object.keys(remote)]);
    
    for (const key of allKeys) {
      // メタデータフィールドはスキップ
      if (['id', 'userId', 'deviceId', 'createdAt', 'updatedAt'].includes(key)) {
        continue;
      }

      const l = local[key];
      const r = remote[key];
      const b = base[key];

      // 値が同じ
      if (JSON.stringify(l) === JSON.stringify(r)) {
        autoMerged[key] = l;
      }
      // ローカル変更なし、リモート変更あり
      else if (JSON.stringify(l) === JSON.stringify(b)) {
        autoMerged[key] = r;
      }
      // リモート変更なし、ローカル変更あり
      else if (JSON.stringify(r) === JSON.stringify(b)) {
        autoMerged[key] = l;
      }
      // 両方変更 → 競合
      else {
        conflicts[key] = { local: l, remote: r };
      }
    }

    return { autoMerged, conflicts };
  }

  /**
   * 競合を保存（手動解決用）
   */
  private async saveConflict(
    entityId: string,
    entityType: 'card' | 'folder',
    autoMerged: unknown,
    conflicts: Record<string, { local: unknown; remote: unknown }>
  ): Promise<void> {
    const conflict: SyncConflict = {
      id: crypto.randomUUID(),
      entityId,
      entityType,
      autoMerged,
      conflicts,
      detectedAt: Date.now(),
    };
    await this.localDB.conflicts.put(conflict);
    console.log(`[Sync] Conflict detected for ${entityType} ${entityId}`);
  }

  /**
   * 未解決の競合を取得
   */
  async getUnresolvedConflicts(): Promise<SyncConflict[]> {
    return this.localDB.conflicts.toArray();
  }

  /**
   * 競合を解決
   */
  async resolveConflict(conflictId: string, resolvedData: unknown): Promise<void> {
    const conflict = await this.localDB.conflicts.get(conflictId);
    if (!conflict) {
      throw new Error(`Conflict ${conflictId} not found`);
    }

    // 解決済みデータをローカルDBに保存
    const table = conflict.entityType === 'card' ? 'cards' : 'folders';
    await this.localDB.upsert(table, resolvedData);

    // 競合レコードを削除
    await this.localDB.conflicts.delete(conflictId);
    console.log(`[Sync] Conflict ${conflictId} resolved`);
  }

  // ========================================
  // 完全削除（PURGE）同期対応
  // ========================================

  /**
   * 完全削除を同期対応で実行
   * TRASHED → PURGED の状態遷移
   * ローカルDB から物理削除し、Firestore からも削除（オフライン時はキューに追加）
   * 
   * @param entityType 'card' | 'folder'
   * @param id 削除するアイテムのID
   */
  async purgeWithSync(entityType: 'card' | 'folder', id: string): Promise<void> {
    const table = entityType === 'card' ? 'cards' : 'folders';
    
    // ローカルDBから物理削除（ローカルファースト）
    await this.localDB.purge(table, id);
    console.log(`[Sync] Purged ${entityType} ${id} from local DB`);
    
    // Firestore から削除を試行
    try {
      if (entityType === 'card') {
        await this.cloudProvider.deleteCard(id, this.userId);
      } else {
        await this.cloudProvider.deleteFolder(id, this.userId);
      }
      console.log(`[Sync] Purged ${entityType} ${id} from Firestore`);
    } catch (error: unknown) {
      // Firestore 削除失敗時はキューに追加
      console.warn(`[Sync] Failed to purge ${entityType} ${id} from Firestore, queueing for later:`, error.message);
      await this.enqueueChange(entityType, 'delete', { id });
    }
  }

  /**
   * 複数アイテムを一括で完全削除（同期対応）
   * 
   * @param items 削除するアイテムの配列 { type: 'card' | 'folder', id: string }
   */
  async bulkPurgeWithSync(items: Array<{ type: 'card' | 'folder'; id: string }>): Promise<{ succeeded: number; failed: number }> {
    let succeeded = 0;
    let failed = 0;
    
    for (const item of items) {
      try {
        await this.purgeWithSync(item.type, item.id);
        succeeded++;
      } catch (error) {
        console.error(`[Sync] Failed to purge ${item.type} ${item.id}:`, error);
        failed++;
      }
    }
    
    return { succeeded, failed };
  }



  /**
   * クラウドからの変更をプルし、ローカルDBに適用します。
   * @returns 同期が成功したかどうか
   */
  async pullChanges(onProgress?: (msg: string) => void): Promise<boolean> {
    const lastSyncTime = await this.localDB.getLastSyncTime(this.userId);
    console.log(`[Sync][Pull] Starting. since=${lastSyncTime?.toISOString() ?? 'epoch'}`);

    try {
      // 各コレクションから安全にデータを取得
      // 画像のアップロード（プッシュ前に行う）
      await this.imageSyncService.syncLocalImages(this.userId, onProgress);

      // 各コレクションから安全にデータを取得
      const serverChanges = await this.cloudProvider.fetchUpdatedDataSince(lastSyncTime || new Date(0), this.userId);
      
      // 他のデータ（UserSettings, UserStats）も取得
      const userSettings = await this.fetchUpdatedDocsSafe('userSettings', lastSyncTime);
      const userStats = await this.fetchUserStats();

      // 取得したデータをローカルDBに一括で適用（マージロジック）
      await this.mergeAndUpsert('folders', serverChanges.folders);
      await this.mergeAndUpsert('cards', serverChanges.cards);
      await this.mergeAndUpsert('userSettings', userSettings);
      await this.mergeAndUpsert('userStats', userStats);

      // 最終同期時刻を更新
      await this.localDB.updateLastSyncTime(this.userId, new Date());
      console.log('[Sync][Pull] Completed successfully.');
      return true;
    } catch (error: unknown) {
      console.error('[Sync][Pull] Failed:', sanitizeForLog(error));
      await this.recordError(error.message, 'download', error.stack);
      return false;
    }
  }

  private async mergeAndUpsert(table: string, remoteItems: unknown[]): Promise<void> {
    const entityType = table === 'cards' ? 'card' : 'folder';
    for (const item of remoteItems) {
        // PULL SIDE SANITIZATION: DB保存前に汚染データ（Blob URL）を除去
        if (table === 'userSettings' && item.profileImage) {
             item.profileImage = sanitizeProfileImage(item.profileImage).profileImage;
        }

        const localItem = await this.localDB.getItem(table, item.id);
        const merged = this.mergeEntity(localItem, item, entityType);
        await this.localDB.upsert(table, merged);
    }
  }

  /**
   * 指定されたコレクションから、最終同期時刻以降に更新されたドキュメントを取得します（エラーハンドリング付き）。
   * @param collectionName 同期するコレクション名
   * @param lastSyncTime 最終同期時刻
   */
  private async fetchUpdatedDocsSafe<T>(collectionName: SyncableCollection, lastSyncTime: Date | null): Promise<T[]> {
    try {
      // 'users' と 'userSettings' は1ユーザー1ドキュメントなので、直接ドキュメントを取得
      if (collectionName === 'users' || collectionName === 'userSettings') {
        const docRef = doc(firestoreDb, collectionName, this.userId);
        const snapshot = await getDoc(docRef);
        if (snapshot.exists()) {
          return [{ id: snapshot.id, ...snapshot.data() } as T];
        }
        return [];
      }

      // lastSyncTimeがない場合（初回同期など）、すべてのドキュメントを取得
      const collRef = collection(firestoreDb, collectionName);
      const q = lastSyncTime
        ? query(collRef, where('userId', '==', this.userId), where('updatedAt', '>', Timestamp.fromDate(lastSyncTime)))
        : query(collRef, where('userId', '==', this.userId));

      const snapshot = await getDocs(q);
      return snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as T));
    } catch (error: unknown) {
      // 権限不足の場合はログに出力して空配列を返す
      if (error?.code === 'permission-denied') {
        console.warn(`[Sync] Permission denied for collection "${collectionName}". Skipping...`);
        return [];
      }
      throw error;
    }
  }

  /**
   * 指定されたコレクションから、最終同期時刻以降に更新されたドキュメントを取得します。
   * @param collectionName 同期するコレクション名
   * @param lastSyncTime 最終同期時刻
   */
  private async fetchUpdatedDocs<T>(collectionName: SyncableCollection, lastSyncTime: Date | null): Promise<T[]> {
    // lastSyncTimeがない場合（初回同期など）、すべてのドキュメントを取得
    const collRef = collection(firestoreDb, collectionName);
    const q = lastSyncTime
      ? query(collRef, where('userId', '==', this.userId), where('updatedAt', '>', Timestamp.fromDate(lastSyncTime)))
      : query(collRef, where('userId', '==', this.userId));

    const snapshot = await getDocs(q);
    return snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as T));
  }

  /**
   * userStatsドキュメントを取得します。
   * userStatsは読み取り専用で、Cloud Functionsのみが書き込み可能です。
   */
  private async fetchUserStats(): Promise<UserStats[]> {
    try {
      const docRef = doc(firestoreDb, 'userStats', this.userId);
      const snapshot = await getDoc(docRef);
      if (snapshot.exists()) {
        return [{ id: snapshot.id, ...snapshot.data() } as UserStats];
      }
      return [];
    } catch (error: unknown) {
      if (error?.code === 'permission-denied') {
        console.warn('[Sync] Permission denied for userStats. Skipping...');
        return [];
      }
      console.warn('[Sync] Failed to fetch userStats:', error);
      return [];
    }
  }
  
   /**
   * ローカルでの変更を検出し、Firestoreにプッシュします。
   * 失敗時は自動的にオフラインキューへ追加します。
   * @param since この日時以降に更新されたアイテムを対象とします（指定しない場合はDBの最終同期日時）
   * @returns 同期が成功したかどうか
   */
  async pushChanges(since?: Date): Promise<boolean> {
    const dbLastSync = await this.localDB.getLastSyncTime(this.userId);
    // synchronize()から渡されたsince（pull前の時刻）を使用、なければDB値
    const lastSync = since || dbLastSync || new Date(0);
    
    console.log(`[Sync][Push] Starting. since=${lastSync.toISOString()}`);
    
    // 各テーブルからダーティなアイテムを取得
    const dirtyFolders = await this.localDB.getDirtyItems('folders', this.userId, lastSync);
    const dirtyCards = await this.localDB.getDirtyItems('cards', this.userId, lastSync);
    const dirtyUserSettings = await this.localDB.getDirtyItems('userSettings', this.userId, lastSync);
    const dirtyUserStats = await this.localDB.getDirtyItems('userStats', this.userId, lastSync);
    
    try {
        const totalDirty = dirtyFolders.length + dirtyCards.length + dirtyUserSettings.length + dirtyUserStats.length;
        if (totalDirty === 0) {
            console.log('[Sync][Push] Skipped: no local dirty records.', sanitizeForLog({
              folders: dirtyFolders.length,
              cards: dirtyCards.length,
              userSettings: dirtyUserSettings.length,
              userStats: dirtyUserStats.length,
            }));
            return true;
        }

        // 500アイテム制限を考慮してバッチを分ける
        const allItems = [
            ...dirtyFolders.map(f => ({ collection: 'folders', data: f })),
            ...dirtyCards.map(c => ({ collection: 'cards', data: c })),
            ...dirtyUserSettings.map(s => ({ collection: 'userSettings', data: s })),
            ...dirtyUserStats.map(s => ({ collection: 'userStats', data: s }))
        ];

        let pushedCount = 0;
        let skippedCount = 0;
        for (let i = 0; i < allItems.length; i += 500) {
            const chunk = allItems.slice(i, i + 500);
            const batch = writeBatch(firestoreDb);
            let operationCount = 0;
            
            // Optimistic Locking & Conflict Check
            for (const item of chunk) {
                const docRef = doc(firestoreDb, `${item.collection}/${item.data.id}`);
                
                // サーバー状態を確認（これはReadコストがかかるが、安全のため）
                // NOTE: バッチ書き込み前の個別チェックはコスト高だが、Integrity優先
                // 本番運用では "Blind Write with Precondition" が望ましいが、Types/Structure差異対策でReadしている
                let serverSnap;
                try {
                  serverSnap = await getDoc(docRef);
                } catch (e) {
                  skippedCount += 1;
                  console.warn('[Sync][Push] Skipped item: failed to check server state.', sanitizeForLog({
                    collection: item.collection,
                    entityId: item.data.id,
                  }));
                  continue; 
                }
                
                if (serverSnap.exists()) {
                    const serverData = serverSnap.data();
                    const serverUpdated = serverData.updatedAt?.toDate?.() || new Date(0);
                    // lastSync (Pull前の時刻) より後にサーバーが更新されていたら競合
                    if (serverUpdated > lastSync) {
                        skippedCount += 1;
                        console.warn('[Sync][Push] Skipped item: conflict (server newer than baseline).', sanitizeForLog({
                          collection: item.collection,
                          entityId: item.data.id,
                          serverUpdated: serverUpdated.toISOString(),
                          baseline: lastSync.toISOString(),
                        }));
                        // ここで Push をスキップし、次の Pull で解決されるのを待つ
                        // または、明示的に競合リストに入れる？
                        // 現状はスキップ安全策をとる
                        continue;
                    }
                }

                // Firestore用に正規化/前処理
                const payload = { ...item.data };

                // userSettingsの画像サニタイズ (Blob URLを除去)
                if (item.collection === 'userSettings' && payload.profileImage) {
                    payload.profileImage = sanitizeProfileImage(payload.profileImage).profileImage;
                }
                
                // updatedAtをTimestampに変換
                if (payload.updatedAt instanceof Date) {
                    payload.updatedAt = Timestamp.fromDate(payload.updatedAt);
                }
                if (payload.createdAt instanceof Date) {
                    payload.createdAt = Timestamp.fromDate(payload.createdAt);
                }
                
                batch.set(docRef, payload, { merge: true });
                operationCount++;
            }
            
            if (operationCount > 0) {
              await batch.commit();
              pushedCount += operationCount;
            }
        }

        console.log(`[Sync][Push] Completed. dirty=${totalDirty}, pushed=${pushedCount}, skipped=${skippedCount}`);
        return true;
    } catch (error: unknown) {
        console.error('[Sync][Push] Failed:', sanitizeForLog(error));
        await this.recordError(error.message, 'upload', error.stack);
        return false;
    }
  }


  /**
   * 初回ログイン時や新端末でのログイン時に、Firestoreから全データを取得してローカルDBを初期化します。
   */
  async performFullSync(): Promise<void> {
    const startedAt = Date.now();
    console.log('[Sync] Performing full sync from Firestore...');
    
    try {
      // Safety check: If local data exists, don't wipe it! Merge instead.
      const cardCount = await this.localDB.cards.count();
      const folderCount = await this.localDB.folders.count();
      
      if (cardCount > 0 || folderCount > 0) {
        console.log('[Sync] Local data found. Skipping wipe and performing safe pull/merge.');
      } else {
        console.log('[Sync] Local DB is empty. Cleaning and preparing for full download...');
        await this.localDB.clearAllData();
      }

      // Perform pull (lastSyncTime is null, so it gets everything from cloud)
      const success = await this.pullChanges();
      if (!success) {
        throw new Error('Initial download failed. Please check your connection and try again.');
      }

      // Migration Logic: Upload existing local data to cloud
      // Since lastSyncTime was just updated by pullChanges, we must explicitly sync from the beginning
      // to ensure all pre-existing local items are pushed.
      if (cardCount > 0 || folderCount > 0) {
        console.log('[Sync] Migrating local data to cloud...');
        const pushSuccess = await this.pushChanges(new Date(0));
        if (!pushSuccess) {
           console.warn('[Sync] Initial push (migration) had some errors, but sync process will continue.');
        }
      }
      
      console.log('[Sync] Full sync completed.');
      // 成功時に全エラーをクリア（以前のエラー状態をリセット）
      await this.clearAllErrors();
      await this.recordHistory(startedAt, 'success', 0, 0);
    } catch (error: unknown) {
      console.error('[Sync] Error during full sync:', error);
      await this.recordError(error.message, 'download', error.stack);
      await this.recordHistory(startedAt, 'failed', 0, 0);
      throw error; // Re-throw to notify caller (AuthContext)
    }
  }

  /**
   * プルとプッシュを順番に実行する標準的な同期プロセス。
   * 高度化機能を統合:
   * - WiFiチェック
   * - キュー処理優先
   * - 履歴記録
   * - エラー記録
   */
  async synchronize(onProgress?: (msg: string) => void): Promise<SyncResult> {
    const startedAt = Date.now();
    let uploaded = 0;
    const downloaded = 0;
    let conflictCount = 0;
    const errors: string[] = [];

    console.log('[Sync] Starting synchronization process...');

    // Phase 1: Sync Isolation
    // 同期中はキュー操作をブロックするためにフラグを立てる
    SyncService.isSyncing = true;

    if (!(await this.acquireSyncLock())) {
        SyncService.isSyncing = false; // Lock acquisition failed, release isolation
        return { success: false, uploaded: 0, downloaded: 0, conflicts: 0, errors: ['別の端末で同期が行われています。しばらく待ってから再試行してください。'] };
    }

    try {
      // 設定読み込み
      const settings = await this.loadSettings();

      // 端末数の情報を取得（制限はしないが統計として保持）
      const deviceCountInfo = await this.checkDeviceLimit();
      console.log(`[Sync] Active devices: ${deviceCountInfo.count}`);

      // WiFiチェック
      if (settings.wifiOnly && !this.isWifiConnection()) {
        console.log('[Sync] Skipped: WiFi only mode enabled but not on WiFi');
        await this.recordHistory(startedAt, 'skipped_wifi', 0, 0);
        return { success: false, uploaded: 0, downloaded: 0, conflicts: 0, errors: ['WiFi限定モードのためスキップ'] };
      }

      // キュー処理優先（オフライン中に溜まった変更をまず適用）
      console.log('[Sync][PushQueue] Processing queued operations before pull/push.');
      const queueResult = await this.processQueue();
      console.log('[Sync][PushQueue] Result', sanitizeForLog(queueResult));
      if (queueResult.failed > 0) {
        errors.push(`キュー処理失敗: ${queueResult.failed}件`);
      }
      uploaded += queueResult.processed;

      // 重要: Pull/Pushの基準となる時刻（前回同期時刻）を取得
      // Pullが成功するとDBのlastSyncTimeが更新されるため、Pushのために古い値を保持しておく必要がある
      const previousSyncTime = await this.localDB.getLastSyncTime(this.userId);

      // プル（サーバー → ローカル）
      onProgress?.('サーバーからデータを取得中...');
      let pullSuccess = false;
      try {
        pullSuccess = await this.pullChanges(onProgress);
      } catch (pullError: unknown) {
        console.warn('[Sync] Pull failed with fatal error. Checking for self-healing fallback...', pullError.message);
        // 【正常遷移: Delta Sync 失敗 → Full Sync】
        // 差分同期が論理的に修復不能なエラー（409衝突や構造不整合など）の場合、フル同期を試みる
        if (pullError.message?.includes('conflict') || pullError.message?.includes('version_mismatch') || pullError.message?.includes('failed to fetch')) {
          console.log('[Sync] Triggering self-healing Full Sync fallback.');
          await this.performFullSync();
          pullSuccess = true; // フル同期成功後は成功扱いとする
        }
      }

      if (!pullSuccess) {
        errors.push('プル失敗');
      }

      // プッシュ（ローカル → サーバー）
      if (pullSuccess && typeof navigator !== 'undefined' && !navigator.onLine) {
        console.warn('[Sync][Push] Skipped after pull: browser is offline.');
      } else if (pullSuccess) {
        onProgress?.('ローカルの変更を送信中...');
        let pushSuccess = false;
        try {
          pushSuccess = await this.pushChanges(previousSyncTime || undefined);
        } catch (pushError: unknown) {
          console.warn('[Sync] Push failed with fatal error. Checking for fallback...', pushError.message);
          // プッシュ失敗時も特定の条件下ではフル同期による整合性確保を試みる
          if (pushError.message?.includes('conflict')) {
            console.log('[Sync] Triggering Full Sync due to push conflict.');
            await this.performFullSync();
            pushSuccess = true;
          }
        }
        
        if (!pushSuccess) {
          errors.push('プッシュ失敗');
        }
      } else {
        console.warn('[Sync][Push] Skipped because pull did not succeed.');
      }

      // 競合チェック
      const conflicts = await this.getUnresolvedConflicts();
      conflictCount = conflicts.length;

      // 結果判定
      const result = errors.length === 0 ? 'success' : 'partial';
      
      if (result === 'success') {
        // 成功時に全エラーをクリア（以前のエラー状態をリセット）
        await this.clearAllErrors();
        
        // 端末の同期メタデータをFirestoreに記録
        const deviceMetaDoc = doc(firestoreDb, `sync_metadata/${this.userId}/devices/${this.deviceId}`);
        
        // 既存のドキュメントを確認し、名前が未設定または「不明なデバイス」等の場合にのみデフォルト名を設定
        const existingDoc = await getDoc(deviceMetaDoc);
        const existingData = existingDoc.exists() ? existingDoc.data() : null;
        
        const metadata: unknown = {
          userId: this.userId,
          deviceId: this.deviceId,
          lastSyncTime: Timestamp.now(),
          lastSyncAttempt: Timestamp.now(),
          isActive: true
        };

        // 名前がまだないか、以前の脆弱なロジックで取得された生UAっぽい名前の場合は上書き
        if (!existingData?.deviceName || existingData.deviceName === 'Unknown Device' || existingData.deviceName.includes('AppleWebKit')) {
          metadata.deviceName = getDeviceName();
        }

        await setDoc(deviceMetaDoc, metadata, { merge: true });

        // 同期成功時、設定が有効なら24時間以上活動がない端末を自動クリーンアップ
        if (settings.autoCleanupDevices) {
          this.cleanupInactiveDevices()
            .then(count => {
              if (count > 0) {
                console.log(`[Sync] Auto-cleaned ${count} inactive devices.`);
              }
            })
            .catch(err => console.error('[Sync] Auto-cleanup failed:', err));
        }
      }

      await this.recordHistory(startedAt, result, uploaded, downloaded);

      console.log(`[Sync] Synchronization finished. Result: ${result}`);
      return { 
        success: errors.length === 0, 
        uploaded, 
        downloaded, 
        conflicts: conflictCount, 
        errors 
      };

    } catch (error: unknown) {
      console.error('[Sync] Synchronization failed:', error);
      await this.recordError(error.message, 'merge', error.stack);
      await this.recordHistory(startedAt, 'failed', uploaded, downloaded);
      
      return { 
        success: false, 
        uploaded, 
        downloaded, 
        conflicts: conflictCount, 
        errors: [...errors, error.message] 
      };
    } finally {
      await this.releaseSyncLock();
      SyncService.isSyncing = false; // Release isolation
    }
  }

  /**
   * 同期統計を取得（過去7日間）
   */
  async getSyncStats(): Promise<{
    successRate: number;
    avgDuration: number;
    errorRate: number;
    totalSyncs: number;
  }> {
    const sevenDaysAgo = Date.now() - 7 * 24 * 60 * 60 * 1000;

    const histories = await this.localDB.syncHistory
      .where('finishedAt')
      .above(sevenDaysAgo)
      .toArray();

    const errors = await this.localDB.syncErrors
      .where('occurredAt')
      .above(sevenDaysAgo)
      .toArray();

    const totalSyncs = histories.length;
    const successCount = histories.filter(h => h.result === 'success').length;
    const successRate = totalSyncs > 0 ? (successCount / totalSyncs) * 100 : 0;

    const durations = histories.map(h => h.finishedAt - h.startedAt);
    const avgDuration = durations.length > 0
      ? durations.reduce((a, b) => a + b, 0) / durations.length
      : 0;

    const errorRate = totalSyncs > 0 ? (errors.length / totalSyncs) * 100 : 0;

    return { successRate, avgDuration, errorRate, totalSyncs };
  }
}

