import type { UploadedImage } from '@/types';
import { firestoreDb as db } from '../services/firebase';

/**
 * DB 保存前の厳格なバリデーション（全保存パスで必須）
 */
export const strictValidateBeforeSave = (image: UploadedImage): void => {
  // remoteUrl チェック
  if (image.remoteUrl) {
    if (!image.remoteUrl.startsWith('https://')) {
      throw new Error(`[CRITICAL] Invalid remoteUrl detected: ${image.remoteUrl.substring(0, 50)}`);
    }
    // Base64 チェック（data: プレフィックス + MIME 型）
    if (image.remoteUrl.startsWith('data:')) {
      throw new Error(`[CRITICAL] Base64 in remoteUrl: ${image.remoteUrl.substring(0, 50)}`);
    }
    // MIME 型チェック（より厳格）
    if (image.remoteUrl.includes('base64,')) {
      throw new Error(`[CRITICAL] Base64 encoding detected in remoteUrl`);
    }
  }
  
  // localUrl チェック
  if (image.localUrl) {
    if (!image.localUrl.startsWith('blob:')) {
      throw new Error(`[CRITICAL] Invalid localUrl detected: ${image.localUrl.substring(0, 50)}`);
    }
    // Base64 チェック（data: プレフィックス + MIME 型）
    if (image.localUrl.startsWith('data:')) {
      throw new Error(`[CRITICAL] Base64 in localUrl: ${image.localUrl.substring(0, 50)}`);
    }
    // MIME 型チェック（より厳格）
    if (image.localUrl.includes('base64,')) {
      throw new Error(`[CRITICAL] Base64 encoding detected in localUrl`);
    }
  }
  
  // 開発環境でのみ警告
  if (import.meta.env.DEV) {
    console.log('[Validation] UploadedImage passed strict validation', image);
  }
};

// Operation Queue とLocalDB の統合ユーティリティ
// 既存のカード操作フックに統合可能な形で提供

import { operationQueue } from '../services/operationQueue';
import type { QueuePriority } from '../services/operationQueue';
import type { Card } from '../types';

/**
 * カード操作のQueue化ラッパー
 * 既存のコードから簡単に呼び出せるシンプルなAPI
 */
export const queuedCardOperations = {
  /**
   * カード作成をキューに追加
   */
  async createCard(cardData: Partial<Card>): Promise<void> {
    if (!cardData.id) throw new Error('Card ID is required for queueing');
    await operationQueue.enqueueChange('card', cardData.id, 'create', cardData);
  },

  /**
   * カード更新をキューに追加
   */
  async updateCard(cardId: string, updates: Partial<Card>): Promise<void> {
    await operationQueue.enqueueChange('card', cardId, 'update', updates);
  },

  /**
   * カード削除をキューに追加
   */
  async deleteCard(cardId: string): Promise<void> {
    await operationQueue.enqueueChange('card', cardId, 'delete', {});
  },

  /**
   * キュー処理を即座に実行
   */
  async processQueue(): Promise<void> {
    await operationQueue.processQueue();
  },
};

/**
 * アプリケーション初期化時に呼び出す
 */
export async function initializeOperationQueue(): Promise<void> {
  // 初期化ロジック: 
  // 1. サービスの初期化が必要ならここで行う (現状はコンストラクタで十分なら不要だが、キックオフとしてprocessを呼ぶ)
  // 2. クラッシュ等のリカバリ (Stale Recovery) を走らせるため、一度processQueueを呼ぶのが適切
  console.log('[Queue] Initializing OperationQueue integration...');
  
  // Stale items recovery is included in processQueue
  operationQueue.triggerProcess(); // 非同期でキック
  
  // オンライン復帰時の自動処理
  if (typeof window !== 'undefined') {
    window.addEventListener('online', async () => {
      console.log('[Queue] Online detected, processing queue...');
      await operationQueue.processQueue();
    });
  }
}

import type { Card } from '../types/Card';
import { normalizeMemoryStability } from './reviewUtils';

/**
 * Determines if a card has been reviewed by the user.
 * 
 * @param card - The card to check.
 * @returns True if the card has been reviewed, false otherwise.
 * 
 * @remarks
 * **Definition of "Reviewed":**
 * A card is considered reviewed ONLY if `reviewCount > 0`.
 * This means the user has explicitly performed a review action at least once.
 * 
 * **Important Notes:**
 * - `memoryStability` is NOT used for this check, as it may be initialized to a non-zero value (e.g., 0.3) in some contexts or future features (AI generation).
 * - `lastReviewAt` is NOT used for this check, as it may be set during import or migration without an actual review taking place.
 * - This strict definition prevents unreviewed cards from polluting statistics with default values.
 */
export const isReviewed = (card: Partial<Card>): boolean => {
  return (card.reviewCount ?? 0) > 0;
};

/**
 * Calculates the average stability of a set of cards.
 * 
 * @param cards - Array of cards to calculate average from.
 * @returns The average stability (0-1) of reviewed cards, or `null` if no reviewed cards exist.
 */
export const calculateAverageStability = (cards: Partial<Card>[]): number | null => {
  const reviewedCards = cards.filter(isReviewed);

  if (reviewedCards.length === 0) {
    return null;
  }

  const totalStability = reviewedCards.reduce((sum, c) => {
    const stability = normalizeMemoryStability(
      c.memoryStability ?? (c as any).memory_stability,
      c.currentLevel ?? (c as any).current_level ?? (c as any).level
    );
    return sum + stability;
  }, 0);

  return totalStability / reviewedCards.length;
};

import { firestoreDb, storage } from '@/services/firebase';
import { collection, query, where, getDocs, deleteDoc, doc, Timestamp } from 'firebase/firestore';
import { ref, deleteObject } from 'firebase/storage';
import type { UploadMetadata } from '@/types';

/**
 * 24時間以上経過した、完了していないアップロード（failed, uploading, pending）をクリーンアップします。
 * 
 * @param userId ユーザーID
 * @returns 削除結果（件数とエラーリスト）
 */
export const cleanupFailedUploads = async (userId: string) => {
  const result = {
    deleted: 0,
    errors: [] as { id: string; error: unknown }[]
  };

  try {
    // 24時間前の閾値
    const yesterday = new Date(Date.now() - 24 * 60 * 60 * 1000);
    const yesterdayTimestamp = Timestamp.fromDate(yesterday);

    // アップロードメタデータのコレクション
    const uploadsRef = collection(firestoreDb, `users/${userId}/uploads`);
    
    // クエリ: 24時間より古く、かつステータスが ready 以外
    // Firestore では != 演算子が使えるが、インデックスの都合上、個別にチェックするか
    // あるいは simple get してクライアント側でフィルタリングする手法をとる
    const snapshot = await getDocs(uploadsRef);

    const staleUploads = snapshot.docs.filter(doc => {
      const data = doc.data() as UploadMetadata;
      const uploadedAt = data.uploadedAt;
      
      // Timestamp か Date かを判定して比較
      const date = uploadedAt && typeof (uploadedAt as any).toDate === 'function' 
        ? (uploadedAt as any).toDate() 
        : uploadedAt;
      
      const isOld = date && new Date(date) < yesterday;
      const isNotReady = data.status !== 'ready';

      return isOld && isNotReady;
    });

    for (const uploadDoc of staleUploads) {
      const data = uploadDoc.data() as UploadMetadata;
      const docId = uploadDoc.id;

      try {
        // 1. Storage からファイルを削除（パスが存在する場合）
        if (data.storagePath) {
          const fileRef = ref(storage, data.storagePath);
          try {
            await deleteObject(fileRef);
          } catch (e: unknown) {
            // ファイルが既に存在しない場合は無視してメタデータ削除に進む
            if (e.code !== 'storage/object-not-found') {
              throw e;
            }
          }
        }

        // 2. Firestore からメタデータを削除
        await deleteDoc(doc(firestoreDb, `users/${userId}/uploads`, docId));
        
        result.deleted++;
      } catch (err) {
        console.error(`Failed to cleanup upload ${docId}:`, err);
        result.errors.push({ id: docId, error: err });
      }
    }

    return result;
  } catch (error) {
    console.error('Cleanup process failed:', error);
    throw error;
  }
};

import { describe, it, expect, vi, beforeEach } from 'vitest';
import { blobUrlManager } from '@/utils/BlobUrlManager';

describe('BlobUrlManager テスト', () => {
  beforeEach(() => {
    // 各テスト前にクリーンアップ
    blobUrlManager.revokeAll();
  });
  
  it('Blob URL を生成できる', () => {
    const blob = new Blob(['test'], { type: 'text/plain' });
    const url = blobUrlManager.create(blob);
    
    expect(url).toMatch(/^blob:/);
    expect(blobUrlManager.getActiveCount()).toBe(1);
  });
  
  it('Blob URL を解放できる', () => {
    const blob = new Blob(['test'], { type: 'text/plain' });
    const url = blobUrlManager.create(blob);
    
    blobUrlManager.revoke(url);
    
    expect(blobUrlManager.getActiveCount()).toBe(0);
  });
  
  it('上限（20枚）を超えると最古の URL を自動解放', () => {
    const blobs = Array.from({ length: 25 }, () => new Blob(['test'], { type: 'text/plain' }));
    
    blobs.forEach(blob => {
      blobUrlManager.create(blob);
    });
    
    // 上限20枚を維持
    expect(blobUrlManager.getActiveCount()).toBe(20);
  });
  
  it('すべての Blob URL を解放できる', () => {
    const blobs = Array.from({ length: 10 }, () => new Blob(['test'], { type: 'text/plain' }));
    
    blobs.forEach(blob => {
      blobUrlManager.create(blob);
    });
    
    blobUrlManager.revokeAll();
    
    expect(blobUrlManager.getActiveCount()).toBe(0);
  });
